window.PRELOADED_DATA = {"stats": [{"key": "red", "count": 495}, {"key": "black", "count": 279}, {"key": "yellow", "count": 68}, {"key": "gray", "count": 40}, {"key": "white", "count": 223}, {"key": "green", "count": 27}, {"key": "blue", "count": 68}], "quotes": [{"bucket": "white", "quote": "我还记得初看见西洋人的时候，就觉得他脸太白，头发太黄，眼珠太淡，鼻梁太高。", "work": "第68章 略论中国人的脸 杂文《而已集》 1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "皮上常有红点，即因为颜色太白之故，倒不如我们之黄。", "work": "第68章 略论中国人的脸 杂文《而已集》 1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "微风起来，吹动她短发，确乎比去年白得多了。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "院子里满是月色，白得如银；", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但仰面一看，门旁却白白的，分明帖着一张斜角纸斜角纸：旧时民间习俗，人死后在大门旁斜贴一张白纸，纸上写明死者的性别和年龄，入殓时需要避开的是哪些生肖的人，以及“殃”和“煞”的种类、日期，使别人知道避忌。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "首先是一乘白彩的大轿，总该有八十一人抬着罢，里面一座木主，写的是‘大周文王之灵位’；", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "而一进门口所看见的长而白的东西就是他。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "倘要开头，他们还得有一个更通古学，更长古文的人，才能胜对垒之任，单是现在似的每周印一回公牍和游谈的堆积，纸张虽白，圈点虽多，是毫无用处的。", "work": "第290章 答KS君", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "一部乱蓬蓬的花白的胡子。", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "跌倒的是一个女人，花白头发，衣服都很破烂。", "work": "第12章 一件小事 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我这回在鲁镇所见的人们中，改变之大，可以说无过于她的了：五年前的花白的头发，即今已经全白，全不像四十上下的人；", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "不半年，头发也花白起来了，记性尤其坏，甚而至于常常忘却了去淘米。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "“是么，”四爷也捋着上唇的花白的鲇鱼须，却悠悠然，仿佛全不在意模样，说，“这也是他父亲的报应呵。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "迎接他的是花白胡子的教务长，大名鼎鼎的万瑶圃，别号“玉皇香案吏”“玉皇香案吏”：旧时附庸风雅的文人，常从古人诗词中摘取词句作为别号。", "work": "第30章 高老夫子 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "站在我前面的一个花白头发的老太太，便发出羡慕感叹的声音。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”大良们的祖母，那三角眼的胖女人，从对面的窗口探出她花白的头来了，也大声说，不耐烦似的。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "还有一只花白的叭儿狗，从庙会买来，记得似乎原有名字，子君却给它另起了一个，叫作阿随。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”他生着几根花白胡子的嘴唇还抖着。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这时眉间尺正看见一辆黄盖的大车驰来，正中坐着一个画衣的胖子，花白胡子，小脑袋；", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他是一个高而瘦的老人，须发都花白了，还戴着大眼镜。", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "第二是夏三爷赏了二十五两雪白的银子，独自落腰包，一文不花。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "又像用了力掷在墙上而反拨过来的皮球一般，一个小学生飞奔上来，一手按住了自己头上的雪白的小布帽，向人丛中直钻进去。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "主人始终穿洋服，硬领始终雪白；", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "主妇是前头的头发始终烫得蓬蓬松松像一个麻雀窠，牙齿是始终雪白的露着，但衣服却是中国装，…", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他们两人正在用午餐，”他想，“桌上铺了雪白的布；", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "好一会，一个武士的脸色忽而很端庄了，极小心地两手慢慢举起了勺子，水滴从勺孔中珠子一般漏下，勺里面便显出雪白的头骨来。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "楚国的郢城可是不比宋国：街道宽阔，房屋也整齐，大店铺里陈列着许多好东西，雪白的麻布，通红的辣椒，斑斓的鹿皮，肥大的莲子。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "圆的雪白的月亮照着前途，凉风吹脸，真是比大猎回来时还有趣。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我于是仿佛看见雪白的桌布已经沾了许多酱油渍，男男女女围着桌子都吃冰其淋，而许多媳妇儿，就如中国历来的大多数媳妇儿在苦节的婆婆脚下似的，都决定了暗淡的运命。", "work": "第102章 “碰壁”之后 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他不但活泼而诙谐，单是那浑身雪白这一点，在红红绿绿中就有“鹤立鸡群”之概。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "那罩是昨晚新换的罩，雪白的纸，折出波浪纹的叠痕，一角还画出一枝猩红色的栀子。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "华老栓忽然坐起身，擦着火柴，点上遍身油腻的灯盏，茶馆的两间屋子里，便弥满了青白的光。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "华大妈忙看她儿子和别人的坟，却只有不怕冷的几点青白小花，零星开着；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "莲花白竟赊来了，他喝了两杯，青白色的脸上泛了红，吃完饭，又颇有些高兴了，他点上一支大号哈德门香烟，从桌上抓起一本《尝试集》《尝试集》：系中国现代文学史上第一部白话诗集，是胡适里程碑式的著作，一九二○年三月上海亚东图书馆出版。", "work": "第15章 端午节 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但也还仿佛记得她脸色变成青白，后来又渐渐转作绯红，——没有见过，也没有再见的绯红；", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "公园里面，外国孩子聚沙成为圆堆，横插上两条短树干，这明明是在创造铁甲炮车了，而中国孩子是青白的，瘦瘦的脸，躲在大人的背后，羞怯的，惊异的看着，身上穿着一件斯文之极的长衫。", "work": "第95章 玩具 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "一切冰冷，一切青白。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "上下四旁无不冰冷，青白。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "而一切青白冰上，却有红影无数，纠结如珊瑚网。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "冰谷四面，登时完全青白。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "青白的两颊泛出轻红，如铅上涂了胭脂水。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "苍白的长方脸，然而衰瘦了。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "于是就看见带着笑涡的苍白的圆脸，苍白的瘦的臂膊，布的有条纹的衫子，玄色的裙。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”伯夷这才转过脸去看，只见叔齐的原是苍白的脸色，好像更加苍白了。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”于是她的脸色苍白了。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "警察吆喝着连抓带拖的弄进一个十八岁的学生来，苍白脸，脏衣服，站在下面。", "work": "第154章 写于深夜里(2) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我的头发已经苍白，不是很明白的事么？", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "那么我的灵魂的手一定也颤抖着，头发也一定苍白了。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "白光如一柄白团扇，摇摇摆摆的闪起在他房里了。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他说着，狮子似的赶快走进那房里去，但跨进里面的时候，便不见了白光的影踪，只有莽苍苍的一间旧房，和几个破书桌都没在昏暗里。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他爽然的站着，慢慢的再定睛，然而白光却分明的又起来了，这回更广大，比硫黄火更白净，比朝雾更霏微，而且便在靠东墙的一张书桌下。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "一般黑魆魆的挺立着，周围便放出浩大闪烁的白光来。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "而且这白光又远远的就在前面了。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但仰面一看，门旁却白白的，分明帖着一张斜角纸斜角纸：旧时民间习俗，人死后在大门旁斜贴一张白纸，纸上写明死者的性别和年龄，入殓时需要避开的是哪些生肖的人，以及“殃”和“煞”的种类、日期，使别人知道避忌。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但卷头有一页白纸，只有见过没有印出的字典的人，才能够看出字来，首先计三条：一，或从宽办理；", "work": "第153章 写于深夜里(1) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "自然有法院，但曾在白纸上看出字来的犯人，在开庭时候是决不抗辩的，因为坏人才爱抗辩，一辩即不免“从严办理”；", "work": "第154章 写于深夜里(2) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "只要望见一顶白纸的高帽子和他手里的破芭蕉扇的影子，大家就都有些紧张，而且高兴起来了。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "指挥台正中的白布横额上，写有“天地正气”四个醒目的大字。", "work": "第57章 论睁了眼看 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这一下“der”，就令人眼睛发白，因为这是茄门话茄门话：即德语。", "work": "第62章 风马牛 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "直刺着天空中圆满的月亮，使月亮窘得发白。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "灯火也因惊惧而缩小了，东方已经发白。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "至于革命党，有的说是便在这一夜进了城，个个白盔白甲：穿着崇正皇帝的素穿着崇正皇帝的素：崇正，作品中人物对崇祯的讹称。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "来了一阵白盔白甲的革命党，都拿着板刀，钢鞭，炸弹，洋炮，三尖两刃刀，钩镰枪，走过土谷祠，叫道，‘阿q！", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "从此决不能望有白盔白甲的人来叫他，他所有的抱负，志向，希望，前程，全被一笔勾销了。", "work": "第9章 阿Q正传(4) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他游到夜间，赊了两碗酒，喝下肚去，渐渐的高兴起来了，思想里才又出现白盔白甲的碎片。", "work": "第9章 阿Q正传(4) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但他究竟是做过“这路生意”，格外胆大，于是躄出路角，仔细的听，似乎有些嚷嚷，又仔细的看，似乎许多白盔白甲的人，络绎的将箱子抬出了，器具抬出了，秀才娘子的宁式床也抬出了，但是不分明，他还想上前，两只脚却没有动。", "work": "第9章 阿Q正传(4) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他躺了好一会，这才定了神，而且发出关于自己的思想来：白盔白甲的人明明到了，并不来打招呼，搬了许多好东西，又没有自己的份，——这全是假洋鬼子可恶，不准我造反，否则，这次何至于没有我的份呢？", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "忽然见华大妈坐在地上看她，便有些踌躇，惨白的脸上，现出些羞愧的颜色；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "直到现在，那青年的惨白的脸，凹下的眼睛，两只满是鲜血的手，还时常浮在我的眼前，使我难于忘却！", "work": "第154章 写于深夜里(2) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "写完了大略，抬头看看窗外，一地惨白的月色，心里不禁渐渐地冰凉了起来。", "work": "第154章 写于深夜里(2) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "“鬼魂们在冷油温火里醒来，从魔鬼的光辉中看见地狱小花，惨白可怜，被大蛊惑，倏忽间记起人世，默想至不知几多年，遂同时向着人间，发一声反狱的绝叫。", "work": "第199章 失掉的好地狱 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "其实我们这白篷的航船，本也不愿意和乌篷的船在一处，而况没有空地呢…", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "看见的人报告说，河里面上午就泊了一只白篷船，篷是全盖起来的，不知道什么人在里面，但事前也没有人去理会他。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "“怎么又是白篷船呢？", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”白衣是亲族有服者所穿的，现在必须“争穿”而又“不遂”，足见并非亲族，但竟以为“有失体面”，演成这样的大战了。", "work": "第140章 说“面子” 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "街上黑沉沉的一无所有，只有一条灰白的路，看得分明。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但他似乎被太阳晒得头晕了，脸色越加变成灰白，从劳乏的红肿的两眼里，发出古怪的闪光。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "灰白色的沉重的晚云中间时时发出闪光，接着一声钝响，是送灶的爆竹；", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "有时，仿佛看见那生路就像一条灰白的长蛇，自己蜿蜒地向我奔来，我等着，等着，看看临近，但忽然便消失在黑暗里了。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他便要请我吃点心，荞麦粉，并且告诉我所加的是白糖。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "你想，家里能有白糖的船户，可见决不是一个穷船户了，所以他也吃得很阔绰。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "伊在这肉红色的天地间走到海边，全身的曲线都消融在淡玫瑰似的光海里，直到身中央才浓成一段纯白。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这纯白的影子在海水里动摇，仿佛全体都正在四面八方的迸散。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他眼睛还是那样，然而奇怪，只这几年，头上却有了白发了，但也许本来就有，我先前没有留心到。", "work": "第184章 范爱农 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "马只能认着白色的田塍走，而且早已筋疲力竭，自然走得更慢了。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他们研究了世界上各人种的脸色，决定了脸色一致的人种，就得取同一的行为，所以黄色的无产阶级，不该和黄色的有产阶级斗争，却该和白色的无产阶级斗争。", "work": "第135章 中国文坛上的鬼魅 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "灰白色的沉重的晚云中间时时发出闪光，接着一声钝响，是送灶的爆竹；", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "胖孩子却看见那白背心正研究着这发亮的秃头，他也便跟着去研究，就只见满头光油油的，耳朵左近还有一片灰白色的头发，此外也不见得有怎样新奇。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他看见他的母亲坐在灰白色的月影中，仿佛身体都在颤动；", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "她们的眼睛都已老花多年了，但望这红白的花，却还能明白看见。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "不一会，窗缝里透进了银白色的曙光。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "东方渐渐发白，窗缝里透进了银白色的曙光。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "强烈的银白色的月光，照得纸窗发白。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "不一会，北风小了，路上浮尘早已刮净，剩下一条洁白的大道来，车夫也跑得更快。", "work": "第12章 一件小事 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "有时有一点杂感，仔细一看，觉得没有什么大意思，不要去填黑了那么洁白的纸张，便废然而止了。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "罗汉就塑得比孩子们高得多，虽然不过是上小下大的一堆，终于分不清是葫芦还是罗汉，然而很洁白，很明艳，以自身的滋润相粘结，整个地闪闪地生光。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "即使有时还会想起伯夷叔齐来，但恍恍忽忽，好像看见他们蹲在石壁下，正在张开白胡子的大口，拼命的吃鹿肉。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "两人在后面说一声“借光”，民众回头一看，见是两位白须老者，便照文王敬老的上谕，赶忙闪开，让他们走到前面。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "白须老臣的讲道，矮胖侏儒的打诨，王是早已听厌的了；", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "事后反动当局为掩盖真相，诬称学生“为反动分子所利用”、被害学生是“失足落水”等，并发表验尸报告，说被害者“腿有青紫白黑四色，上身为黑白二色”等。", "work": "第78章 逃的辩护 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”我这才栗然地回想长安，记得看见很多的白杨，很大的石榴树，道中喝了不少的黄河水。", "work": "第56章 说胡须 杂文《坟》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "窗外的白杨的嫩叶，在日光下发乌金光；", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但是擦着白粉，颧骨没有这么高，嘴唇也没有这么薄，而且终日坐着，我也从没有见过这圆规式的姿势。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "因为他不会噜苏了，种种的权势者便用种种的白粉给他来化妆，一直抬到吓人的高度。", "work": "第148章 在现代中国的孔夫子 杂文《且介亭杂文二集》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "大王就又射了三箭，拔出剑来，一砍，这才拿了黑斧头，割下她们的脑袋，挂在小白旗上。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我们便到街上去走了一通，满眼是白旗。", "work": "第184章 范爱农 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "原来中国军阀的混战，从“青年军人”，从“民族主义文学者”看来，是并非驱同国人民互相残杀，却是外国人在打别一外国人，两个国度，两个民族，在战地上一到夜里，自己就飘飘然觉得皮色变白，鼻梁加高，成为腊丁民族腊丁民族：泛指拉丁语系的意大利、法兰西、西班牙、葡萄牙等国人。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "一路胜下去，可惜后来四种人不知“友谊”的要紧和“团结的力量”，自相残杀，竟为白种武士所乘了——这是作者的讽喻，也是作者的悲哀。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "（二）没有到过外国的人，往往以为白种人都是对人来讲耶稣道理或开洋行的，鲜衣美食，一不高兴就用皮鞋向人乱踢。", "work": "第153章 写于深夜里(1) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但白种人是一切“奶”都叫“milk”的，我们看惯了罐头牛奶上的文字，有时就不免于误译，是的，这也是无足怪的事。", "work": "第62章 风马牛 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我看出他话中全是毒，笑中全是刀，他们的牙齿，全是白厉厉的排着，这就是吃人的家伙。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "凉风虽然拂拂的吹动他斑白的短发，初冬的太阳却还是很温和的来晒他。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "上面是铅色的天，白皑皑的绝无精彩，而且微雪又飞舞起来了。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "独有眼睛非常大，睫毛也很长，眼白又青得如夜的晴天，而且是北方的无风的晴天，这里的就没有那么明净了。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "秃头正仰视那电杆上钉着的红牌上的四个白字，仿佛很觉得有趣。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他的母亲端坐在床上，在暗白的月影里，两眼发出闪闪的光芒。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”伊看定他们，伸出带着泥土的手指去拨他肥白的脸。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这一点，就要任凭文学逞能，恰如冢中的白骨，往古来今，总要以它的永久来傲视少女颊上的轻红似的。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "记得年幼时，很喜欢看变戏法，猢狲骑羊，石子变白鸽，最末是将一个孩子刺死，盖上被单，一个江北口音的人向观众装出撒钱模样道：huazaahuazaa：用拉丁字母拼写的象声词，译音似“哗嚓”，形容撒钱的声音。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但是，也如“吃白相饭”朋友那样，卖票人是还有他的道德的。", "work": "第163章 “揩油” 杂文《准风月谈》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "老莱子即是一例，道学先生以为他白璧无瑕时，他却已在孩子的心中死掉了。", "work": "第178章 《二十四孝图》散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "别人不知其详，我是将钱都在上海换了日本的银元，还带了十双中国袜——白袜。", "work": "第186章 琐记 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "其次，则给以冰冷的呼吸，示以淡白的嘴唇，使之人性茫然，得到生命的飞扬的极致的大欢喜；", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "“月白风清，如此良夜何？", "work": "第273章 《准风月谈》前记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这一种可怜的眼光，是阿q从来没有见过的，一见之下，又使他舒服得如六月里喝了雪水。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "须大雪下了才好。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我们沙地上，下了雪，我扫出一块空地来，用短棒支起一个大竹匾，撒下秕谷，看鸟雀来吃时，我远远地将缚在棒上的绳子只一拉，那鸟雀就罩在竹匾下了。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我于是又很盼望下雪。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "乌鸦喜鹊想要下来时，它们便躬着身子用后脚在地上使劲的一弹，砉的一声直跳上来，像飞起了一团雪，鸦鹊吓得赶紧走，这样的几回，再也不敢近来了。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "天色愈阴暗了，下午竟下起雪来，雪花大的有梅花那么大，满天飞舞，夹着烟霭和忙碌的气色，将鲁镇乱成一团糟。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但是我总觉得不安，过了一夜，也仍然时时记忆起来，仿佛怀着什么不祥的预感，在阴沉的雪天里，在无聊的书房里，这不安愈加强烈了。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "冬季日短，又是雪天，夜色早已笼罩了全市镇。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "雪花落在积得厚厚的雪褥上面，听去似乎瑟瑟有声，使人更加感得沉寂。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我静听着窗外似乎瑟瑟作响的雪花声，一面想，反而渐渐的舒畅起来。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "“我真傻，真的，”祥林嫂抬起她没有神采的眼睛来，接着说，“我单知道下雪的时候野兽在山坳里没有食吃，会到村里来；", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "“我真傻，真的，”她说，“我单知道雪天是野兽在深山里没有食吃，会到村里来；", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "“是的，你是单知道雪天野兽在深山里没有食吃，才会到村里来的。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "微雪点点的下来了。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "祥林嫂似很局促了，立刻敛了笑容，旋转眼光，自去看雪花。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我在蒙胧中，又隐约听到远处的爆竹声联绵不断，似乎合成一天音响的浓云，夹着团团飞舞的雪花，拥抱了全市镇。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "深冬雪后，风景凄清，懒散和怀旧的心绪联结起来，我竟暂寓在s城的洛思旅馆里了；", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "上面是铅色的天，白皑皑的绝无精彩，而且微雪又飞舞起来了。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这园大概是不属于酒家的，我先前也曾眺望过许多回，有时也在雪天里。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但现在从惯于北方的眼睛看来，却很值得惊异了：几株老梅竟斗雪开着满树的繁花，仿佛毫不以深冬为意；", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "倒塌的亭子边还有一株山茶树，从晴绿的密叶里显出十几朵红花来，赫赫的在雪中明得如火，愤怒而且傲慢，如蔑视游人的甘心于远行。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我这时又忽地想到这里积雪的滋润，着物不去，晶莹有光，不比朔雪的粉一般干，大风一吹，便飞得满空如烟雾。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "觉得北方固不是我的旧乡，但南来又只能算一个客子，无论那边的干雪怎样纷飞，这里的柔雪又怎样的依恋，于我都没有什么关系了。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "楼外的雪也越加纷纷的下。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "积雪里会有花，雪地下会不冻。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我站在雪中，决然的指着它对土工说，‘掘开来！", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "窗外沙沙的一阵声响，许多积雪从被它压弯了的一枝山茶树上滑下去了，树枝笔挺的伸直，更显出乌油油的肥叶和血红的花来。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "小鸟雀啾唧的叫着，大概黄昏将近，地面又全罩了雪，寻不出什么食粮，都赶早回巢来休息了。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我独自向着自己的旅馆走，寒风和雪片扑在脸上，倒觉得很爽快。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "见天色已是黄昏，和屋宇和街道都织在密雪的纯白而不定的罗网里。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "下了一天雪，到夜还没有止，屋外一切静极，静到要听出静的声音来。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我在小小的灯火光中，闭目枯坐，如见雪花片片飘坠，来增补这一望无际的雪堆；", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我自己还是一个儿童，在后园的平坦处和一伙小朋友塑雪罗汉。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "雪罗汉的眼睛是用两块小炭嵌出来的，颜色很黑，这一闪动，便变了连殳的眼睛。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "推窗一望，雪果然下得更大了。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "“我这里下大雪了。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "眉间尺伏在掘开的洞穴旁边，伸手下去，谨慎小心地撮开烂树，待到指尖一冷，有如触着冰雪的时候，那纯青透明的剑也出现了。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "雪一下，可就两样了。", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "拍雪人（将自己的全形印在雪上）和塑雪罗汉需要人们鉴赏，这是荒园，人迹罕至，所以不相宜，只好来捕鸟。", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "薄薄的雪，是不行的；", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "总须积雪盖了地面一两天，鸟雀们久已无处觅食的时候才好。", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "扫开一块雪，露出地面，用一支短棒支起一面大的竹筛来，下面撒些秕谷，棒上系一条长绳，人远远地牵着，看鸟雀下来啄食，走到竹筛底下的时候，将绳子一拉，便罩住了。", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "的雨，向来没有变过冰冷的坚硬的灿烂的雪花。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "江南的雪，可是滋润美艳之至了；", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "雪野中有血红的宝珠山茶宝珠山茶：据《广群芳谱》卷四十一载：“宝珠山茶，千叶含苞，历几月而放，殷红若丹，最可爱。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "雪下面还有冷绿的杂草。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但我的眼前仿佛看见冬花开在雪野中，有许多蜜蜂们忙碌地飞着，也听得他们嗡嗡地闹着。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "孩子们呵着冻得通红，像紫芽姜一般的小手，七八个一齐来塑雪罗汉。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他也就目光灼灼地嘴唇通红地坐在雪地里。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但是，朔方的雪花在纷飞之后，却永远如粉，如沙，他们决不粘连，撒在屋上，地上，枯草上，就是这样。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "屋上的雪是早已就有消化了的，因为屋里居人的火的温热。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "是的，那是孤独的雪，是死掉的雨，是雨的精魂。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "北京的冬季，地上还有积雪，灰黑色的秃树枝丫叉于晴朗的天空中，而远处有一二风筝浮动，在我是一种惊异和悲哀。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "大雪下了，扫出路寻他；", "work": "第210章 他 近代诗《集外集》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "又白又光明，像才下的雪。", "work": "第214章 他们的花园 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”相传周穆王在大风雪中作《黄竹歌》哀悼人民的冻饿。", "work": "第235章 无题", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "因为无论何人，在风雪的呼号中，花卉的议论中，虫鸟的歌舞中，谅必都能够更洪亮的听得自然母的言辞自然母的言辞：剧本中的自然母认为“强者生存弱者灭亡”是自然界的“第一的法则”，而“第一等的强者”应是“对于一切有同情，对于一切都爱”的人，而非暴力者。", "work": "第258章 《桃色的云》序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "然而这里却没有霜，也没有雪，凡萎黄的都是“寿终正寝”，怪不得别个。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他的口角上现出微笑，似乎自以为大有深意，而将繁霜洒在我的园里的野花草上。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "繁霜夜降，木叶多半凋零，庭前的一株小小的枫树也变成红色了。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "回家之后，又须忙别的事了，因为开方的医生是最有名的，以此所用的药引也奇特：冬天的芦根，经霜三年的甘蔗，蟋蟀要原对的，结子的平地木，…", "work": "第264章 《呐喊》自序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这些现象，我先前总以为是所谓“严霜”之故，于是有时候对于那“廪秋”不免口出怨言，加以攻击。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "然而这里却没有霜，也没有雪，凡萎黄的都是“寿终正寝”，怪不得别个。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "今天晚上，很好的月光。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "今天全没月光，我知道不妙。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "天气是好，月色也很亮了。", "work": "第3章 狂人日记(2) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "月亮对着陈士成注下寒冷的光波来，当初也不过像是一面新磨的铁镜罢了，而这镜却诡秘的照透了陈士成的全身，就在他身上映出铁的月亮的影。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他突然仰面向天，月亮已向西高峰这方面隐去，远想离城三十五里的西高峰正在眼前，朝笏朝笏：古代臣子朝见皇帝时所执狭长而稍弯的板子，按品级不同，分别用玉、象牙或竹制成，将要奏的事记在上面，以免遗忘。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他看见一地月光，仿佛满铺了无缝的白纱，玉盘似的月亮现在白云间，看不出一点缺。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "潮湿的路极其分明，仰看太空，浓云已经散去，挂着一轮圆月，散出冷静的光辉。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "强烈的银白色的月光，照得纸窗发白。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "院子里满是月色，白得如银；", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他默默地立在暗中，渐看见月光的皎洁。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他的母亲端坐在床上，在暗白的月影里，两眼发出闪闪的光芒。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "后面远处有银白的条纹，是月亮已从那边出现；", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "那一边，却是一个生铁一般的冷而且白的月亮。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "幸而月亮却在天际渐渐吐出银白的清辉。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "圆的雪白的月亮照着前途，凉风吹脸，真是比大猎回来时还有趣。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "写完了大略，抬头看看窗外，一地惨白的月色，心里不禁渐渐地冰凉了起来。", "work": "第154章 写于深夜里(2) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "有时有一点杂感，仔细一看，觉得没有什么大意思，不要去填黑了那么洁白的纸张，便废然而止了。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他所戴的纸糊的高帽子，本来是挂在台角上的，这时预先拿进去了；", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "时常吃死肉，连极大的骨头，都细细嚼烂，咽下肚子去，想起来也教人害怕。", "work": "第3章 狂人日记(2) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "只有小栓坐在里排的桌前吃饭，大粒的汗，从额上滚下，夹袄也贴住了脊心，两块肩胛骨高高凸出，印成一个阳文的“八”字。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他又聚精会神的挖起那东西来，谨慎的撮着，就灯光下仔细看时，那东西斑斑剥剥的像是烂骨头，上面还带着一排零落不全的牙齿。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他已经悟到这许是下巴骨了，而那下巴骨也便在他手里索索的动弹起来，而且笑吟吟的显出笑影，终于听得他开口道：“这回又完了！", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他栗然的发了大冷，同时也放了手，下巴骨轻飘飘的回到坑底里不多久，他也就逃到院子里了。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他偷看房里面，灯火如此辉煌，下巴骨如此嘲笑，异乎寻常的怕人，便再不敢向那边看。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "好一会，一个武士的脸色忽而很端庄了，极小心地两手慢慢举起了勺子，水滴从勺孔中珠子一般漏下，勺里面便显出雪白的头骨来。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "他便将头骨倒在金盘里。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "但不久就陆续停止了，因为武士又捞起了一个同样的头骨。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "此后又是一个头骨。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "将捞出的物件分盛了三金盘：一盘头骨，一盘须发，一盘簪。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "大家只得平心静气，去细看那头骨，但是黑白大小，都差不多，连那孩子的头，也无从分辨。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "可是终于大平静了，大波不过高如从前的山，像是陆地的处所便露出棱棱的石骨。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这一点，就要任凭文学逞能，恰如冢中的白骨，往古来今，总要以它的永久来傲视少女颊上的轻红似的。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "丁丁地想，钉尖从脚背穿透，钉碎了一块骨，痛楚也透到心髓中，然而他们钉杀着他们的神之子了，可咒诅的人们呵，这使他痛得舒服。", "work": "第191章 复仇（二）散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "突然间，碎骨的大痛楚透到心髓了，他即沉酣于大欢喜和大悲悯中。", "work": "第191章 复仇（二）散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "第二是夏三爷赏了二十五两雪白的银子，独自落腰包，一文不花。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "银子！", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "那白气到天半便变成白云，罩住了这处所，渐渐现出绯红颜色，映得一切都如桃花。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "这是高大的冰山，上接冰天，天上冻云弥漫，片片如鱼鳞模样。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "飘渺的名园中，奇花盛开着，红颜的静女正在超然无事地逍遥，鹤唳一声，白云郁然而起…", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "我这时又忽地想到这里积雪的滋润，着物不去，晶莹有光，不比朔雪的粉一般干，大风一吹，便飞得满空如烟雾。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "办公室里已经充满了秦益堂的水烟的烟雾。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "white", "quote": "”伊又吃了惊，觉得全身的毛孔中无不有什么东西飞散，于是地上便罩满了乳白色的烟云，伊才定了神，那些小东西也住了口。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "人迹绝了许久之后，忽然从城里闪出那一个黑色的人来。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "前面却仅有两点磷火一般的那黑色人的眼光。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "暗中的声音刚刚停止，眉间尺便举手向肩头抽取青色的剑，顺手从后项窝向前一削，头颅坠在地面的青苔上，一面将剑交给黑色人。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "最先头的一匹大狼就向黑色人扑过来。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "先头是宦官，后面是四个武士，中间夹着一个黑色人。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那黑色人站在旁边，见炭火一红，便解下包袱，打开，两手捧出孩子的头来，高高举起。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑色人捧着向四面转了一圈，便伸手擎到鼎上，动着嘴唇说了几句不知什么话，随即将手一松，只听得扑通一声，坠入水中去了。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "炭火也正旺，映着那黑色人变成红黑，如铁的烧到微红。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑色人的歌声才停，那头也就在水中央停住，面向王殿，颜色转成端庄。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "“大王，”那黑色人半跪着说，“他正在鼎底里作最神奇的团圆舞，不临近是看不见的。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "刚在惊疑，黑色人已经掣出了背着的青色的剑，只一挥，闪电般从后项窝直劈下去，扑通一声，王的头就落在鼎里了。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑色人也仿佛有些惊慌，但是面不改色。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑色人和眉间尺的头也慢慢地住了嘴，离开王头，沿鼎壁游了一匝，看他可是装死还是真死。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "伊接过来看时，是一条很光滑的青竹片，上面还有两行黑色的细点，比槲树叶上的黑斑小得多。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "卢弓，卢矢：黑色的弓和矢。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "，须发开张飘动，像黑色火，这一瞬息，使人仿佛想见他当年射日的雄姿。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那时候大约是盛夏，青蝇密集在凉棚索子上，铁黑色的细腰蜂就在桑树间或墙角的蛛网左近往来飞行，有时衔一支小青虫去了，有时拉一个蜘蛛。", "work": "第51章 春末闲谈 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "倘一律刷成黑色，也还有破磁可划，粉笔可书，真是穷于应付。", "work": "第57章 论睁了眼看 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”每一新制度，新学术，新名词，传入中国，便如落在黑色染缸，立刻乌黑一团，化为济私助焰之具。", "work": "第94章 偶感 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "大红衫子，黑色长背心，长发蓬松，颈挂两条纸锭，垂头，垂手，弯弯曲曲的走一个全台，内行人说：这是走了一个“心”字。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "北京的冬季，地上还有积雪，灰黑色的秃树枝丫叉于晴朗的天空中，而远处有一二风筝浮动，在我是一种惊异和悲哀。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "过客——约三四十岁，状态困顿倔强，眼光阴沉，黑须，乱发，黑色短衣裤皆破碎，赤足著破鞋，胁下挂一个口袋，支着等身的竹杖。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "头黑色，鳞片边缘暗红色；", "work": "第217章 我的失恋 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "逃掉了五色旗下的“铁窗斧钺风味”，而在青天白日之下又有“缧绁缧绁：古时系罪人的黑色绳索。", "work": "第286章 通信", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他的笔调高亢，力透纸背，唤醒了国人麻木的灵魂，为黑暗的天空带来了一抹恒久的光明，并深刻地影响着一代又一代中国人，堪称中华民族之魂！", "work": "第1章 永远的鲁迅，永远的民族魂", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "伤感的《故乡》，沉重的《药》，冷峻的《祝福》，讽刺的《阿q正传》，幽默的《故事新编》，无不将那个黑暗的时代所造成的人性与社会的阴暗描画得入木三分，均是掷地有声、发人深省的佳作；", "work": "第1章 永远的鲁迅，永远的民族魂", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "作品以“药”为题，寓意深刻，充分表现出作者对黑暗社会的鞭挞、对腐朽封建制度的抨击、对革命志士仁人的同情、对愚昧无知百姓的痛心疾首，体现鲁迅先生这位“五四”新文化运动先锋的民族责任感，读来令人深思。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这一夜没有月，未庄在黑暗里很寂静，寂静到像羲皇羲皇：指伏羲氏。", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "不多久，松柏林早在船后了，船行也并不慢，但周围的黑暗只是浓，可知已经到了深夜。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我便轻如行云，漂浮空际，上有蔚蓝的天，下是深山大海，广厦高楼，战场，摩托车，洋场，公馆，晴明的闹市，黑暗的夜…", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "死于无爱的人们的眼前的黑暗，我仿佛一一看见，还听得一切苦闷和绝望的挣扎的声音。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "有时，仿佛看见那生路就像一条灰白的长蛇，自己蜿蜒地向我奔来，我等着，等着，看看临近，但忽然便消失在黑暗里了。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "所以种种黑暗，竟和古代的乱世仿佛，况且政界军界学界商界等等里面，全是男人，并无不节烈的女子夹杂在内。", "work": "第49章 我之节烈观(1) 杂文《坟》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "的时候，就突出来帮着袁世凯咬死了许多革命人，中国又一天一天沉入黑暗里，一直到现在，遗老不必说，连遗少也还是那么多。", "work": "第54章 论“费厄泼赖”应该缓行(1）杂文《坟》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这就因为先烈的好心，对于鬼蜮的慈悲，使它们繁殖起来，而此后的明白青年，为反抗黑暗计，也就要花费更多更多的气力和生命。", "work": "第54章 论“费厄泼赖”应该缓行(1）杂文《坟》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "假使此后光明和黑暗还不能作彻底的战斗，老实人误将纵恶当作宽容，一味姑息下去，则现在似的混沌状态，是可以无穷无尽的。", "work": "第55章 论“费厄泼赖”应该缓行(2) 杂文《坟》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "等等的时候了，即使要谈论这些，也必须先知道习惯和风俗，而且有正视这些的黑暗面的勇猛和毅力。", "work": "第66章 习惯与改革 杂文《二心集》 1930", "year": "1930", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "因为我就想发一点议论，然而立刻又想到恐怕一面有人疑心我在冷嘲（有人说，我是只喜欢冷嘲的），一面又有人责罚我传播黑暗，因此咒我灭亡，自己带着一切黑暗到地底里去。", "work": "第85章 铲共大观 杂文《三闲集》1928", "year": "1928", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "而且至少是赤膊的，——但这也许我猜得不对，是我自己太黑暗之故。", "work": "第85章 铲共大观 杂文《三闲集》1928", "year": "1928", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "再说下去，恐怕有些英雄们又要责我散布黑暗，阻碍革命了。", "work": "第85章 铲共大观 杂文《三闲集》1928", "year": "1928", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但不是正因为黑暗，正因为没有出路，所以要革命的么？", "work": "第85章 铲共大观 杂文《三闲集》1928", "year": "1928", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我临末还要揭出一点黑暗，是我们中国现在（现在！", "work": "第85章 铲共大观 杂文《三闲集》1928", "year": "1928", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "“中国什么都黑暗，谁也不行，但没有事的时候是看不出来的。", "work": "第102章 “碰壁”之后 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "从不像我似的常常“碰壁”的青年学生的眼睛看来，中国也就如此之黑暗么？", "work": "第102章 “碰壁”之后 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "见有什么像毒蛇似的在尸林中蜿蜒，怨鬼似的在黑暗中奔驰，就更应该留心了：这在预告“真的愤怒”将要到来。", "work": "第105章 杂感 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我先是该校的一个讲师，于黑暗残虐情形，多曾目睹；", "work": "第108章 “公理”的把戏 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但是，我的话里，一面固然显示着我的狡猾，而且无能，但一面也显示着社会的黑暗。", "work": "第120章 世故三昧 杂文《南腔北调集》1932", "year": "1932", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "不过中国的有一些士大夫，总爱无中生有，移花接木的造出故事来，他们不但歌颂升平，还粉饰黑暗。", "work": "第137章 病后杂谈(2) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他们在前仆后继的战斗，不过一面总在被摧残，被抹杀，消灭于黑暗中，不能为大家所知道罢了。", "work": "第139章 中国人失掉自信力了吗 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "仁厚黑暗的地母呵，愿在你怀里永安她的魂灵！", "work": "第177章 阿长与《山海经》 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "一九二六年十一月，鲁迅在厦门大学执教，仍然念念不忘范爱农，又提笔写下此文，记叙了故友范爱农的悲惨遭遇，批判了辛亥革命的不彻底性，揭露了当时的黑暗社会现实，反映了生活在黑暗社会里的知识分子地位的卑下和思想的苦闷。", "work": "第184章 范爱农 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "它以象征的手法，通过丰富的想象力，生动的意象和细腻的文笔，借景抒情，托物言志，塑造了枣树这一饱经沧桑、坚实挺拔、憎恶黑暗现实，顽强抗击黑暗势力，历经战斗洗礼的老战士形象，表达了作者对这样的战士的热情歌颂，也寄托了自己与黑暗势力抗争，在艰难中顽强求索的精神。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我不过一个影，要别你而沉没在黑暗里了。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "然而黑暗又会吞并我，然而光明又会使我消失。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "然而我不愿彷徨于明暗之间，我不如在黑暗里沉没。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我将向黑暗里彷徨于无地。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "无已，则仍是黑暗和虚空而已。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但是，我愿意只是黑暗，或者会消失于你的白天；", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我独自远行，不但没有你，并且再没有别的影在黑暗里。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "只有我被黑暗沉没，那世界全属于我自己。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "遍地都黑暗了。", "work": "第191章 复仇（二）散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "作者采用象征和对比的手法，通过形象和比喻，生动地描写了三种人物对待黑暗现实和奴隶悲惨生活的不同态度，辛辣地揭露了聪明人的伪善和欺骗，无情地嘲讽和鞭挞了驯服麻木而实际又在维护旧社会的奴才，热情地歌颂了和旧社会作坚持斗争的傻子的执着和反抗。", "work": "第205章 聪明人和傻子和奴才 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他的作品主要描写精神颓废者的生活，有些也反映了沙皇统治的黑暗。", "work": "第238章 娜拉走后怎样", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑暗的消灭，光明的出现，这种革命青年学生，常起最大作用。", "work": "第242章 聪明人不能做事世界是属于傻子", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但为达到这希望计，是必须与前驱者取同一的步调的，我于是删削些黑暗，装点些欢容，使作品比较的显出若干亮色，那就是后来结集起来的《呐喊》，一共有十四篇。", "work": "第272章 《自选集》自序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "招牌是挂了，却只在吹嘘同伙的文章，而对于目前的暴力和黑暗不敢正视。", "work": "第287章 文艺与革命（并冬芬来信）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "或则将剧本的动作辞句都推到演员的“昨日的文学家”“昨日的文学家”：冯乃超在独幕话剧《同在黑暗的路上走》（一九二八年一月《文化批判》第一号）的“附识”中说：“戏曲的本质应该在人物的动作上面去求，洗练的会话，深刻的事实，那些工作让给昨日的文学家去努力吧。", "work": "第287章 文艺与革命（并冬芬来信）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我给你看两句冯乃超的剧本的结末的警句：“野雉：我再不怕黑暗了。", "work": "第287章 文艺与革命（并冬芬来信）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他的母亲端过一碟乌黑的圆东西，轻轻说：“吃下去罢，——病便好了。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他一到里面，很吃了惊，只见假洋鬼子正站在院子的中央，一身乌黑的大约是洋衣，身上也挂着一块银桃子，手里是阿q曾经领教过的棍子，已经留到一尺多长的辫子都拆开了披在肩背上，蓬头散发的像一个刘海仙。", "work": "第9章 阿Q正传(4) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "女人端出乌黑的蒸干菜和松花黄的米饭，热蓬蓬冒烟。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "七斤嫂眼睛好，早望见今天的赵七爷已经不是道士，却变成光滑头皮，乌黑发顶；", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "从前是绢光乌黑的辫子，现在弄得僧不僧道不道的。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这时他其实早已不看到什么墙上的榜文了，只见有许多乌黑的圆圈，在眼前泛泛的游走。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这时船走得更快，不多时，在台上显出人物来，红红绿绿的动，近台的河里一望乌黑的是看戏的人家的船篷。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "然而我决计努力地做，一本半新的字典，不到半月，边上便有了一大片乌黑的指痕，这就证明着我的工作的切实。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "高个子，乌黑的脸…", "work": "第44章 非攻(2) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "伊顺下眼去看，照例是先前所做的小东西，然而更异样了，累累坠坠的用什么布似的东西挂了一身，腰间又格外挂上十几条布，头上也罩着些不知什么，顶上是一块乌黑的小小的长方板长方板：古代帝王、诸侯礼冠顶上的饰板，古名为“延”，亦名“冕板”。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”每一新制度，新学术，新名词，传入中国，便如落在黑色染缸，立刻乌黑一团，化为济私助焰之具。", "work": "第94章 偶感 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "她将披着的头发向后一抖，人这才看清了脸孔：石灰一样白的圆脸，漆黑的浓眉，乌黑的眼眶，猩红的嘴唇。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "一片独有一点蛀孔，镶着乌黑的花边，在红、黄和绿的斑驳中，明眸似的向人凝视。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "庵和春天时节一样静，白的墙壁和漆黑的门。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "土谷祠里更漆黑；", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "可是，没有办法，——幸亏我家的死鬼那时还在，给想了一个法：将长明灯用厚棉被一围，漆漆黑黑地，领他去看，说是已经吹熄了。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "大的圆脸上长着两条细眼和漆黑的细胡须；", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "木棍似的那男人也进来了，将小乌龟模样的一个漆黑的扁的小东西指鼻烟壶。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他旋转身子去，对了书桌，只见蒙着一层尘，再转脸去看纸窗，挂着的日历上，写着两个漆黑的隶书：廿七。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我家的漆黑的炉子里，是躺着通红的两把剑。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "绕着水边一高一低地游了三匝，忽然睁大眼睛，漆黑的眼珠显得格外精彩，同时也开口唱起歌来：", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "伊近于失神了，更其抡，但是不独腰腿痛，连两条臂膊也都乏了力，伊于是不由的蹲下身子去，将头靠着高山，头发漆黑的搭在山顶上，喘息一回之后，叹一口气，两眼就合上了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "她将披着的头发向后一抖，人这才看清了脸孔：石灰一样白的圆脸，漆黑的浓眉，乌黑的眼眶，猩红的嘴唇。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我听父亲说过的，中国有一种墨猴，只有拇指一般大，全身的毛是漆黑而且发亮的。", "work": "第185章 狗·猫·鼠 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "她像是受了炮烙似的缩手，脸色同时变作灰黑，也不再去取烛台，只是失神的站着。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "到入棺，是连殳很不妥帖地躺着，脚边放一双黄皮鞋，腰边放一柄纸糊的指挥刀，骨瘦如柴的灰黑的脸旁，是一顶金边的军帽。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "远望前面，便依稀看见灰黑色的城墙和雉堞。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "伊于是只好搀些白石，再不够，便凑上些红黄的和灰黑的，后来总算将就的填满了裂口，止要一点火，一熔化，事情便完成，然而伊也累得眼花耳响，支持不住了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我姑且举灰黑的手装作喝干一杯酒，我将在不知道时候的时候独自远行。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "北京的冬季，地上还有积雪，灰黑色的秃树枝丫叉于晴朗的天空中，而远处有一二风筝浮动，在我是一种惊异和悲哀。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "待到回家，大概已经昏黑。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "就在这样一个昏黑的晚上，我照常没精打采地回来，一看见寓所的门，也照常更加丧气，使脚步放得更缓。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我似乎被周围所排挤，奔到院子中间，有昏黑在我的周围；", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "还没有走完高粱田，天色已经昏黑；", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "三太太说，鸦鹊到不打紧，至多也不过抢吃一点食料，可恶的是一只大黑猫，常在矮墙上恶狠狠的看，这却要防的，幸而s和猫是对头，或者还不至于有什么罢。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这时是连日的阴天，三太太又虑到遭了那大黑猫的毒手的事去。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这爪痕倘说是大兔的，爪该不会有这样大，伊又疑心到那常在墙上的大黑猫去了，伊于是也就不能不定下发掘的决心了。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "三太太从此不但深恨黑猫，而且颇不以大兔为然了。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "况且黑猫害了小兔，我更是“师出有名”的了。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那黑猫是不能久在矮墙上高视阔步的了，我决定的想，于是又不由的一瞥那藏在书箱里的一瓶青酸钾青酸钾：即氰酸钾，是一种剧毒的化学品。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "听说西洋是不很喜欢黑猫的，不知道可确；", "work": "第185章 狗·猫·鼠 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他在短篇小说《黑猫》中，写一个囚犯自述的故事，他因杀死一只猫而被神秘的黑猫逼成了谋杀犯。", "work": "第185章 狗·猫·鼠 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "的小说里的黑猫，却实在有点骇人。", "work": "第185章 狗·猫·鼠 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "追来的是一匹很肥大的黑狗。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑狗哼而且追，已经要咬着阿q的腿，幸而从衣兜里落下一个萝卜来，那狗给一吓，略略一停，阿q已经爬上桑树，跨到土墙，连人和萝卜都滚出墙外面了。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "只剩着黑狗还在对着桑树嗥，老尼姑念着佛。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "阿q怕尼姑又放出黑狗来，拾起萝卜便走，沿路又捡了几块小石头，但黑狗却并不再现。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "阿q连忙捏好砖头，摆开马步，准备和黑狗来开战。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但庵门只开了一条缝，并无黑狗从中冲出，望进去只有一个老尼姑。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "大家只得平心静气，去细看那头骨，但是黑白大小，都差不多，连那孩子的头，也无从分辨。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "事后反动当局为掩盖真相，诬称学生“为反动分子所利用”、被害学生是“失足落水”等，并发表验尸报告，说被害者“腿有青紫白黑四色，上身为黑白二色”等。", "work": "第78章 逃的辩护 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "文中说：“六人学业，俱非不良，至于品行一端，平素又绝无惩戒记过之迹，以此与开除并论，而又若离若合，殊有混淆黑白之嫌。", "work": "第103章 并非闲话 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "宣言中所谓“若离若合，殊有混淆黑白之嫌”者，似乎也就是为此辈的手段写照。", "work": "第103章 并非闲话 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "《顺天时报》的记者倘竟不知，可谓昏瞀，倘使知道而故意淆乱黑白，那就有挑拨对于北大怀着恶感的人物，将那恶感蔓延于女师大之嫌，居心可谓卑劣。", "work": "第108章 “公理”的把戏 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "“那是一个黑瘦的，乞丐似的男子。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "即使玩不成，这回也有了那乞丐似的黑瘦男子来受祸，他们只要能挨到传了进来的时候就好了。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "其时进来的是一个黑瘦的先生，八字须，戴着眼镜，挟着一迭大大小小的书。", "work": "第183章 藤野先生 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "每当夜间疲倦，正想偷懒时，仰面在灯光中瞥见他黑瘦的面貌，似乎正要说出抑扬顿挫的话来，便使我忽又良心发现，而且增加勇气了，于是点上一支烟，再继续写些为“正人君子”之流所深恶痛疾的文字。", "work": "第183章 藤野先生 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "即使玩不成，这回也有了那乞丐似的黑瘦男子来受祸，他们只要能挨到传了进来的时候就好了。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "其时进来的是一个黑瘦的先生，八字须，戴着眼镜，挟着一迭大大小小的书。", "work": "第183章 藤野先生 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "每当夜间疲倦，正想偷懒时，仰面在灯光中瞥见他黑瘦的面貌，似乎正要说出抑扬顿挫的话来，便使我忽又良心发现，而且增加勇气了，于是点上一支烟，再继续写些为“正人君子”之流所深恶痛疾的文字。", "work": "第183章 藤野先生 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "屋里面全是黑沉沉的。", "work": "第3章 狂人日记(2) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "街上黑沉沉的一无所有，只有一条灰白的路，看得分明。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑沉沉的灯光，照着宝儿的脸，绯红里带一点青。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "她一面哭，一面想：想那时候，自己纺着棉纱，宝儿坐在身边吃茴香豆，瞪着一双小黑眼睛想了一刻，便说：“妈！", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”他睁着大的黑眼睛，痴痴的想。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "前面的人圈子动摇了，挤进一个黑色的人来，黑须黑眼睛，瘦得如铁。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "陈士成狮子似的奔到门后边，伸手去摸锄头，撞着一条黑影。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "而且很胆怯，不独怕暗夜，怕黑影，即使看见人，虽是自己的主人，也总惴惴的，有如在白天出穴游行的小鼠；", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”女辛想了一想，大悟似的说，“我点了灯出去的时候，的确看见一个黑影向这边飞去的，但我那时万想不到是太太…", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "原来他是一个短小瘦削的人，长方脸，蓬松的头发和浓黑的须眉占了一脸的小半，只见两眼在黑气里发光。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "暮霭笼罩了大宅，邻屋上都腾起浓黑的炊烟，已经是晚饭时候。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我将深味这非人间的浓黑的悲凉；", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "前面的人圈子动摇了，挤进一个黑色的人来，黑须黑眼睛，瘦得如铁。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”店主是一个黄脸黑须的胖子，果然很知道。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "过客——约三四十岁，状态困顿倔强，眼光阴沉，黑须，乱发，黑色短衣裤皆破碎，赤足著破鞋，胁下挂一个口袋，支着等身的竹杖。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "村外多是水田，满眼是新秧的嫩绿，夹着几个圆形的活动的黑点，便是耕田的农夫。", "work": "第7章 阿Q正传(2) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "还有一点和先前的编法不同的，是将刊登时被删改的文字大概补上去了，而且旁加黑点，以清眉目。", "work": "第273章 《准风月谈》前记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "一年之中，只有三篇，现在补全，仍用黑点为记。", "work": "第274章 《花边文学》序言", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "不多久，那惟一的盆景万年青的阔叶又已消失在昏暗中，破絮一般的白云间闪出星点，黑夜就从此开头。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我并未实验过，但有时候想：倘将一位久蛰洞房的老太爷抛在夏天正午的烈日底下，或将不出闺门的千金小姐拖到旷野的黑夜里，大概只好闭了眼睛，暂续他们残存的旧梦，总算并没有遇到暗或光，虽然已经是绝不相同的现实。", "work": "第57章 论睁了眼看 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "呜呼呜呼，倘是黄昏，黑夜自然会来沉没我，否则我要被白天消失，如果现是黎明。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他一急，两眼发黑，耳朵里喤的一声，似乎发昏了。", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他早就两眼发黑，耳朵里嗡的一声，觉得全身仿佛微尘似的迸散了。", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但非常忧愁，忘却了吸烟，象牙嘴六尺多长湘妃竹烟管的白铜斗里的火光，渐渐发黑了。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他移开桌子，用锄头一气掘起四块大方砖，蹲身一看，照例是黄澄澄的细沙，揎了袖爬开细沙，便露出下面的黑土来。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他的心抖得很厉害，聚精会神的挖起那方砖来，下面也满是先前一样的黑土，爬松了许多土，下面似乎还无穷。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但又不是静止的，它令人觉得一种震动——这震动，恰如用坚实的步法，一步一步，踏着坚实的广大的黑土进向建设的路的大队友军的足音。", "work": "第155章 记苏联版画展览会 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "原来他是一个短小瘦削的人，长方脸，蓬松的头发和浓黑的须眉占了一脸的小半，只见两眼在黑气里发光。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我也不由的突然觉到：连殳就始终没有落过一滴泪，只坐在草荐上，两眼在黑气里闪闪地发光。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "听说有一回，三良发了红斑痧，竟急得他脸上的黑气愈见其黑了；", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "尖端还有凝固的黑烟，疑这才从火宅火宅：佛家用语，《法华经·譬喻品》中说：“三界（按这里指欲界、色界、无色界，泛指世界）无安，犹如火宅，众苦充满，甚可怖畏，常有生老病死忧患，如是等火，炽然不息。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我的身上喷出一缕黑烟，上升如铁线蛇铁线蛇：又名盲蛇，无毒，状如蚯蚓，是我国最小的一种蛇。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "壕沟，最黑最黑的深夜，利刃的一击，毫无声响的脚步…", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我总要上下四方寻求，得到一种最黑，最黑，最黑的咒文，先来诅咒一切反对白话，妨害白话者。", "work": "第178章 《二十四孝图》散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "一阵红黑的火焰过去时，店屋里散满了一种奇怪的香味。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "炭火也正旺，映着那黑色人变成红黑，如铁的烧到微红。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他一急，两眼发黑，耳朵里喤的一声，似乎发昏了。", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他早就两眼发黑，耳朵里嗡的一声，觉得全身仿佛微尘似的迸散了。", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "原来他是一个短小瘦削的人，长方脸，蓬松的头发和浓黑的须眉占了一脸的小半，只见两眼在黑气里发光。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我也不由的突然觉到：连殳就始终没有落过一滴泪，只坐在草荐上，两眼在黑气里闪闪地发光。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他们跨进黑油大门时，便被邀进门房去；", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "从一扇黑油的竹门进去，第三间是书房。", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "远望前面，便依稀看见灰黑色的城墙和雉堞。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "北京的冬季，地上还有积雪，灰黑色的秃树枝丫叉于晴朗的天空中，而远处有一二风筝浮动，在我是一种惊异和悲哀。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "红帽哼兮黑帽呵，风流太守看梅花。", "work": "第142章 论俗人应避雅人 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "转得大了，都昏天黑地的在社会上转，同他们的父亲一样，或者还不如。", "work": "第164章 随感录二十五 杂文《热风》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这在迎神时候也有的，但名称却讹作死无常了，黑脸、黑衣，谁也不爱看。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这在迎神时候也有的，但名称却讹作死无常了，黑脸、黑衣，谁也不爱看。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "在许多人期待着恶人的没落的凝望中，他出来了，服饰比画上还简单，不拿铁索，也不带算盘，就是雪白的一条莽汉，粉面朱唇，眉黑如漆，蹙着，不知道是在笑还是在哭。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但同是涉及风月的“月黑杀人夜，风高放火天”呢，这不明明是一联古诗么？", "work": "第273章 《准风月谈》前记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "两个眼眶，都围着一圈黑线。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "此后捞出来的是一团糟的白头发和黑头发；", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "伊接过来看时，是一条很光滑的青竹片，上面还有两行黑色的细点，比槲树叶上的黑斑小得多。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "可是，没有办法，——幸亏我家的死鬼那时还在，给想了一个法：将长明灯用厚棉被一围，漆漆黑黑地，领他去看，说是已经吹熄了。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑漆漆的，不知是日是夜。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "许多长衫和短衫人物，忽然给他穿上一件洋布的白背心，上面有些黑字。", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "淡黑的起伏的连山，仿佛是踊跃的铁的兽脊似的，都远远的向船尾跑去了，但我却还以为船慢。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "慰老爷她是不放在眼里的，见过两回，不过一个团头团脑的矮子：这种人本村里就很多，无非脸色比他紫黑些。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "待到他看见全身，——湿淋淋的黑毛，大的肚子，蚯蚓随的尾巴，——便又觉得可恨可憎得很，慌忙将芦柴一抖，扑通一声，老鼠又落在水瓮里，他接着就用芦柴在它头上捣了几下，叫它赶快沉下去。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "终于，腰腿的酸痛逼得伊站立起来，倚在一座较为光滑的高山上，仰面一看，满天是鱼鳞样的白云，下面则是黑压压的浓绿。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "前面则海天微茫，黑絮一般的夜色简直似乎要扑到心坎里。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "华夏大概并非地狱，然而“境由心造”，我眼前总充塞着重迭的黑云，其中有故鬼，新鬼，游魂，牛首阿旁，畜生，化生，大叫唤，无叫唤，牛首阿旁：地狱中牛头人身的鬼卒；", "work": "第102章 “碰壁”之后 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "看去是一个二十多岁的青年，面貌很端正，颜色是黑黑的，当时的谈话我已经忘却，只记得他自说姓徐，象山人；", "work": "第117章 为了忘却的记念(1) 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "然而我们中华民族是究竟有些“极端”的，不多久，老病复发，有些女士们已在别想花样，用一支细黑柱子将脚跟支起，叫它离开地球。", "work": "第128章 由中国女人的脚，推定中国人之非中庸，又由此推定孔夫子有胃病 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "被囚在黑狱里，到革命后才见天日而身上永带着匪刑的伤痕的也还有一两人。", "work": "第184章 范爱农 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "去的前梦黑如墨，在的后梦墨一般黑；", "work": "第209章 梦 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "于是分头四出，寻黑矮汉，寻梢长大汉，寻头陀，寻胖大和尚，寻茁壮妇人，寻姣长妇人，寻青面，寻歪头，寻赤须，寻美髯，寻黑大汉，寻赤脸长须。", "work": "第179章 五猖会 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那夜他很生气，说是连第九个妃子的头发，也没有昨天那样的黑得好看了。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这是一个高大身材，长头发，眼球白多黑少的人，看人总像在藐视。", "work": "第184章 范爱农 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”他四面一看，只见一只乌鸦，站在一株没有叶的树上，便接着说，“我知道了。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "——你如果真在这里，听到我的话，——便教这乌鸦飞上你的坟顶，给我看罢。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "两人站在枯草丛里，仰面看那乌鸦；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那乌鸦也在笔直的树枝间，缩着头，铁铸一般站着。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "两个人都悚然的回过头，只见那乌鸦张开两翅，一挫身，直向着远处的天空，箭也似的飞去了。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "许多狗都拖出舌头来，连树上的乌老鸦也张着嘴喘气，——但是，自然也有例外的。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "突然一声乌鸦叫。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那古槐上就有三四个乌鸦窠。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他们一早就被乌老鸦闹醒，后来重又睡去，醒来却已是上午时分。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他知道她眼睛快，一定早瞧见那几匹乌鸦的了，不觉一吓，脚步登时也一停，——但只得往里走。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "“今天的运气仍旧不见佳，还是只有乌鸦…", "work": "4", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”嫦娥将柳眉一扬，忽然站起来，风似的往外走，嘴里咕噜着，“又是乌鸦的炸酱面，又是乌鸦的炸酱面！", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "你去问问去，谁家是一年到头只吃乌鸦肉的炸酱面的？", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我真不知道是走了什么运，竟嫁到这里来，整年的就吃乌鸦的炸酱面！", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "中央是一大碗乌鸦肉做的炸酱。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那时谁料到只剩下乌鸦做菜…", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "“唉唉，这样的人，我就整年地只给她吃乌鸦的炸酱面…", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "——不过乌老鸦的炸酱面确也不好吃，难怪她忍不住…", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "眼色也同赵贵翁一样，脸色也都铁青。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他便变了脸，铁一般青。", "work": "第3章 狂人日记(2) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那乌鸦也在笔直的树枝间，缩着头，铁铸一般站着。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "月亮对着陈士成注下寒冷的光波来，当初也不过像是一面新磨的铁镜罢了，而这镜却诡秘的照透了陈士成的全身，就在他身上映出铁的月亮的影。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但今天铁的光罩住了陈士成，又软软的来劝他了，他或者偶一迟疑，便给他正经的证明，又加上阴森的摧逼，使他不得不又向自己的房里转过眼光去。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他极小心的，幽静的，一锄一锄往下掘，然而深夜究竟太寂静了，尖铁触土的声音，总是钝重的不肯瞒人的发响。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "淡黑的起伏的连山，仿佛是踊跃的铁的兽脊似的，都远远的向船尾跑去了，但我却还以为船慢。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "她又带了窗外的半枯的槐树的新叶来，使我看见，还有挂在铁似的老干上的一房一房的紫白的藤花。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "道路上容易遇见熟人，得到轻蔑的一瞥，但此地却决无那样的横祸，因为他们是永远围在别的铁炉旁，或者靠在自家的白炉边的。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他看见自己的手掌比平常大了三四倍，铁铸似的，向荷生的脸上一掌批过去…", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那作品，像太阳的光一样，从无量的光源中涌出来，不像石火，用铁和石敲出来，这才是真艺术。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "二十年前，王妃生下了一块铁王妃生下了一块铁：是一个传说，据清代陈元龙撰《格致镜原》卷三十四引《列士传》佚文：“楚王夫人于夏纳凉，抱铁柱，心有所感，遂怀孕，产一铁；", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”，听说是抱了一回铁柱之后受孕的，是一块纯青透明的铁。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "不幸你的父亲那时偏偏入了选，便将铁捧回家里来，日日夜夜地锻炼，费了整三年的精神，炼成两把剑。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "前面的人圈子动摇了，挤进一个黑色的人来，黑须黑眼睛，瘦得如铁。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "炭火也正旺，映着那黑色人变成红黑，如铁的烧到微红。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那是遍身多用铁片包起来的，脸上的神情似乎很失望而且害怕。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”伊转过脸去了，却又看见一个高兴而且骄傲的脸，也多用铁片包了全身的。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”伊气得从两颊立刻红到耳根，火速背转头，另外去寻觅，好容易才看见一个不包铁片的东西，身子精光，带着伤痕还在流血，只是腰间却也围着一块破布片。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "伊料想他和包铁片的那些是别一种，应该可以探出一些头绪了，便问道：“那是怎么一回事呢？", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那一边，却是一个生铁一般的冷而且白的月亮。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "现在，气象似乎一变，到处听不见歌吟花月的声音了，代之而起的是铁和血的赞颂。", "work": "第57章 论睁了眼看 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "铁蹄践着断骨，骆驼的鸣声变成怪吼；", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "中国现在总算有一点铁路了，他们偏要一步一步的走过去；", "work": "第67章 中华民国的新“堂·吉诃德”们 杂文《二心集》 1932", "year": "1932", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "”青年好像头上受到了铁椎的一击，绝望的叫了一声。", "work": "第154章 写于深夜里(2) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "在百静中，我似乎头里要伸出许多铁钳，将什么“生于太荒”之流夹住；", "work": "第179章 五猖会 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但是，有几枝还低亚着，护定他从打枣的竿梢所得的皮伤，而最直最长的几枝，却已默默地铁似的直刺着奇怪而高的天空，使天空闪闪地鬼眼；", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "而一无所有的干子，却仍然默默地铁似的直刺着奇怪而高的天空，一意要制他的死命，不管他各式各样地着许多蛊惑的眼睛。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这以前，我的心也曾充满过血腥的歌声：血和铁，火焰和毒，恢复和报仇。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他毫无乞灵于牛皮和废铁的甲胄；", "work": "第204章 这样的战士 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "“假如一间铁屋子，是绝无窗户而万难破毁的，里面有许多熟睡的人们，不久都要闷死了，然而是从昏睡入死灭，并不感到就死的悲哀。", "work": "第264章 《呐喊》自序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "“然而几个人既然起来，你不能说决没有毁坏这铁屋的希望。", "work": "第264章 《呐喊》自序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "第267章 写在《坟》后面", "work": "第267章 写在《坟》后面", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "黑漆漆的，不知是日是夜。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "秋天的后半夜，月亮下去了，太阳还没有出，只剩下一片乌蓝的天；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "除了夜游的东西，什么都睡着。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但夜深没有睡的既然只有两家，这单四嫂子家有声音，便自然只有老拱们听到，没有声音，也只有老拱们听到。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但宝儿也许是日轻夜重，到了明天，太阳一出，热也会退，气喘也会平的：这实在是病人常有的事。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "夏天夜短，老拱们呜呜的唱完了不多时，东方已经发白；", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "只有那暗夜为想变成明天，却仍在这寂静里奔波；", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这一夜没有月，未庄在黑暗里很寂静，寂静到像羲皇羲皇：指伏羲氏。", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "最先就绝了人声，接着是陆续的熄了灯火，独有月亮，却缓缓的出现在寒夜的空中。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这院子，是他家还未如此凋零的时候，一到夏天的夜间，夜夜和他的祖母在此纳凉的院子。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他极小心的，幽静的，一锄一锄往下掘，然而深夜究竟太寂静了，尖铁触土的声音，总是钝重的不肯瞒人的发响。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "他独自靠在自己的卧榻上，很高的眉棱在金黄色的长发之间微蹙了，是在想他旧游之地的缅甸，缅甸的夏夜。", "work": "第17章 鸭的喜剧 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "然而夜气很清爽，真所谓“沁人心脾”，我在北京遇着这样的好空气，仿佛这是第一遭了。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那声音大概是横笛，宛转，悠扬，使我的心也沉静，然而又自失起来，觉得要和它弥散在含着豆麦蕴藻之香的夜气里。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "最惹眼的是屹立在庄外临河的空地上的一座戏台，模胡在远处的月夜中，和空间几乎分不出界限，我疑心画上见过的仙境，就在这里出现了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "不多久，松柏林早在船后了，船行也并不慢，但周围的黑暗只是浓，可知已经到了深夜。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这一次船头的激水声更其响亮了，那航船，就像一条大白鱼背着一群孩子在浪花里蹿，连夜渔的几个老渔父，也停了艇子看着喝彩起来。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "真的，一直到现在，我实在再没有吃到那夜似的好豆，——也不再看到那夜似的好戏了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "夏夜，窗外面，常听到苍蝇的悠长的吱吱的叫声，这一定是给蝇虎咬住了，然而我向来无所容心于其间，而别人并且不听到…", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "冬季日短，又是雪天，夜色早已笼罩了全市镇。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "而且很胆怯，不独怕暗夜，怕黑影，即使看见人，虽是自己的主人，也总惴惴的，有如在白天出穴游行的小鼠；", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "不多久，那惟一的盆景万年青的阔叶又已消失在昏暗中，破絮一般的白云间闪出星点，黑夜就从此开头。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "只有打出来的骨牌拍在紫檀桌面上的声音，在初夜的寂静中清彻地作响。", "work": "第30章 高老夫子 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "忽然，他流下泪来了，接着就失声，立刻又变成长嚎，像一匹受伤的狼，当深夜在旷野中嗥叫，惨伤里夹杂着愤怒和悲哀。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我辞别连殳出门的时候，圆月已经升在中天了，是极静的夜。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但是学校里的人们，虽是月薪十五六元的小职员，也没有一个不是乐天知命的，仗着逐渐打熬成功的铜筋铁骨，面黄肌瘦地从早办公一直到夜，其间看见名位较高的人物，还得恭恭敬敬地站起，实在都是不必“衣食足而知礼节”的人民。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "下了一天雪，到夜还没有止，屋外一切静极，静到要听出静的声音来。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "现在已是深夜，吐了两口血，使我清醒起来。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "耳朵中有什么挣扎着，久之，久之，终于挣扎出来了，隐约像是长嗥，像一匹受伤的狼，当深夜在旷野中嗥叫，惨伤里夹杂着愤怒和悲哀。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "深夜中独自躺在床上，就如我未曾和子君同居以前一般，过去一年中的时光全被消灭，全未有过，我并没有曾经从这破屋子搬出，在吉兆胡同创立了满怀希望的小小的家庭。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "夜阑人静，是相对温习的时候了，我常是被质问，被考验，并且被命复述当时的言语，然而常须由她补足，由她纠正，像一个丁等的学生。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "唉唉，那是怎样的宁静而幸福的夜呵！", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "到夜间，在她的凄惨的神色中，加上冰冷的分子了。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "中的贵人，洋场上的投机家，深山密林中的豪杰，讲台上的教授，昏夜的运动者和深夜的偷儿…", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "记得有一夜，子君的眼里忽而又发出久已不见的稚气的光来，笑着和我谈到还在会馆时候的情形，时时又很带些恐怖的神色。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "夜间，便蜷伏在比冰还冷的冷屋中。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我便轻如行云，漂浮空际，上有蔚蓝的天，下是深山大海，广厦高楼，战场，摩托车，洋场，公馆，晴明的闹市，黑暗的夜…", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "壕沟，最黑最黑的深夜，利刃的一击，毫无声响的脚步…", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "躺着，在合着的眼前经过的预想的前途，不到半夜已经现尽；", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "初春的夜，还是那么长。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "现在所有的只是初春的夜，竟还是那么长。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "在夜的渐就寂静中，在他的翘望中，每一辆汽车的汽笛的呼啸声更使他听得分明，有时竟无端疑为普大夫的汽车，跳起来去迎接。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但夜却已经很深了，连汽车也逐渐地减少。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "有一夜，是有星无月的夜。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "杉树林的每一片叶尖，都挂着露珠，其中隐藏着夜气。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "前面则海天微茫，黑絮一般的夜色简直似乎要扑到心坎里。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "夜正长，路也正长，我不如忘却，不说的好罢。", "work": "第118章 为了忘却的记念(2) 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "那是一个我的幼时的夏夜，我躺在一株大桂树下的小板桌上乘凉，祖母摇着芭蕉扇坐在桌旁，给我猜谜，讲故事。", "work": "第185章 狗·猫·鼠 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "夜色更加黯然；", "work": "第185章 狗·猫·鼠 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "这上面的夜的天空，奇怪而高，我生平没有见过这样奇怪而高的天空。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我记得有一种开过极细小的粉红花，现在还开着，但是更极细小了，她在冷的夜气中，瑟缩地做梦，梦见春的到来，梦见秋的到来，梦见瘦的诗人将眼泪擦在她最末的花瓣上，告诉她秋虽然来，冬虽然来，而此后接着还是春，蝴蝶乱飞，蜜蜂都唱起春词来了。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "哇的一声，夜游的恶鸟飞过了。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我忽而听到夜半的笑声，吃吃地，似乎不愿意惊动睡着的人，然而四围的空气都应和着笑。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "夜半，没有别的人，我即刻听出这声音就在我嘴里，我也即刻被这笑声所驱逐，回进自己的房。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我又听到夜半的笑声；", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "呜呼呜呼，倘是黄昏，黑夜自然会来沉没我，否则我要被白天消失，如果现是黎明。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "希望，希望，用这希望的盾，抗拒那空虚中的暗夜的袭来，虽然盾后面也依然是空虚中的暗夜。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我只得由我来肉薄这空虚中的暗夜了。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "桀骜英勇如petfi，也终于对了暗夜止步，回顾茫茫的东方了。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我只得由我来肉薄这空虚中的暗夜了，纵使寻不到身外的青春，也总得自己来一掷我身中的迟暮。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但暗夜又在哪里呢？", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "青年们很平安，而我的面前又竟至于并且没有真的暗夜。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "晴天又来消释他的皮肤，寒夜又使他结一层冰，化作不透明的水晶模样，连续的晴天又使他成为不知道算什么，而嘴上的胭脂也褪尽了。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "石油又不是老牌的，早熏得灯罩很昏暗，鞭爆的繁响在四近，烟草的烟雾在身边：是昏沉的夜。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但我总记得见过这一篇好的故事，在昏沉的夜…", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "过客向野地里跄踉地闯进去，夜色跟在他后面。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "自身不知所在，眼前却有一间在深夜中禁闭的小屋的内部，但也看见屋上瓦松瓦松：又名“向天草”或“昨叶荷草”。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我自身不知所在，眼前却有一间在深夜中禁闭的小屋的内部，我自己知道是在续着残梦。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "她开开板门，迈步在深夜中走出，遗弃了背后一切的冷骂和毒笑。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "她在深夜中尽走，一直走到无边的荒野；", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "繁霜夜降，木叶多半凋零，庭前的一株小小的枫树也变成红色了。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "但今夜他却黄蜡似的躺在我的眼前，那眸子也不复似去年一般灼灼。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "夏夜，蚊子多了，便摇着蒲扇坐在槐树下，从密叶缝里看那一点一点的青天，晚出的槐蚕又每每冰冷的落在头颈上。", "work": "第264章 《呐喊》自序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "在一年的尽头的深夜中，整理了这一年所写的杂感，竟比收在《热风》里的整四年中所写的还要多。", "work": "第265章 《华盖集》题记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "现在是一年的尽头的深夜，深得这夜将尽了，我的生命，至少是一部分的生命，已经耗费在写这些无聊的东西中，而我所获得的，乃是我自己的灵魂的荒凉和粗糙。", "work": "第265章 《华盖集》题记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "我只在深夜的街头摆着一个地摊，所有的无非几个小钉，几个瓦碟，但也希望，并且相信有些人会从中寻出合于他的用处的东西。", "work": "第275章 《且介亭杂文》序言", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "black", "quote": "因此一共喝了两杯，看看窗外的夜的江南，几乎没有睡觉。", "work": "第291章 上海通信", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "小鸟雀啾唧的叫着，大概黄昏将近，地面又全罩了雪，寻不出什么食粮，都赶早回巢来休息了。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "见天色已是黄昏，和屋宇和街道都织在密雪的纯白而不定的罗网里。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "未到黄昏时分，天下已经泰平，或者竟是全都忘却了，人们的脸上不特已不紧张，并且早褪尽了先前的喜悦的痕迹。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "”都可以就是照旧，本来是无足观了，但他们也还要看，黄昏之后，便欣欣然聚满了一堂前。", "work": "第31章 孤独者(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "每日办公散后，虽然已近黄昏，车夫又一定走得这样慢，但究竟还有二人相对的时候。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "”他吆喝道，“黄昏了，不正是私贩子爬城偷税的时候了吗？", "work": "第45章 出关 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但是马力乏了，刚到走惯的高粱田近旁，已是黄昏时候。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我回家坐在自己的窗下的时候，天色已近黄昏，而阴惨惨的颜色却渐渐地退去，回忆到碰壁的学说，居然微笑起来了。", "work": "第102章 “碰壁”之后 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "在我幼小时候可已经不然了，也如大戏一样，始于黄昏，到次日的天明便完结。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "然而我终于彷徨于明暗之间，我不知道是黄昏还是黎明。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "呜呼呜呼，倘是黄昏，黑夜自然会来沉没我，否则我要被白天消失，如果现是黎明。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "时：或一日的黄昏", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "很多的梦，趁黄昏起哄。", "work": "第209章 梦 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "寻声渐渐的寻到赵太爷的内院里，虽然在昏黄中，却辨得出许多人，赵府一家连两日不吃饭的太太也在内，还有间壁的邹七嫂，真正本家的赵白眼，赵司晨。", "work": "第7章 阿Q正传(2) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "昏黄只显得浓密，已经是晚饭时候了。", "work": "第26章 肥皂(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "各样的青春在眼前一一驰去了，身外但有昏黄环绕。", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "忽而警觉，身外也还是环绕着昏黄；", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "这时候，我的脑里忽然闪出一幅神异的图画来：深蓝的天空中挂着一轮金黄的圆月，下面是海边的沙地，都种着一望无际的碧绿的西瓜，其间有一个十一二岁的少年，项带银圈，手捏一柄钢叉，向一匹猹猹：鲁迅在一九二九年五月四日致舒新城的信中说：“‘猹’字是我据乡下人所说的声音，生造出来的，读如‘查’。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我在朦胧中，眼前展开一片海边碧绿的沙地来，上面深蓝的天空中挂着一轮金黄的圆月。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他独自靠在自己的卧榻上，很高的眉棱在金黄色的长发之间微蹙了，是在想他旧游之地的缅甸，缅甸的夏夜。", "work": "第17章 鸭的喜剧 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "两人到山脚下一看，只见新叶嫩碧，土地金黄，野草里开着些红红白白的小花，真是连看看也赏心悦目。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "先前的紫色的圆脸，已经变作灰黄，而且加上了很深的皱纹；", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "她脸色陡然变成灰黄，死了似的；", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "暗中忽然仿佛看见一堆食物，这之后，便浮出一个子君的灰黄的脸来，睁了孩子气的眼睛，恳托似的看着我。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "此后是拿着木棍，戈，刀，弓弩，旌旗的武人，走得满路黄尘滚滚。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "街道上满积着又细又粘的黄尘。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "大家在关口目送着，去了两三丈远，还辨得出白发，黄袍，青牛，白口袋，接着就尘头逐步而起，罩着人和牛，一律变成灰色，再一会，已只有黄尘滚滚，什么也看不见了。", "work": "第45章 出关 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "窗外起了一阵风，括上黄尘来，遮得半天暗。", "work": "第45章 出关 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "黄祸来了！", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "黄祸来了！", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "这德皇威廉因为要鼓吹“德国德国，高于一切”而大叫的“黄祸”德皇威廉：指威廉二世（wilhelmⅡ，1859—1941），德意志帝国皇帝，第一次世界大战的祸首。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "“黄祸”：威廉二世曾于一八九五年绘制了一幅“黄祸的素描”，题词为“欧洲各国人民，保卫你们最神圣的财富！", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "一九○七年又说：“‘黄祸’——这是我早就认识到的一种危险。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "实际上创造‘黄祸’这个名词的人就是我”。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "）（按：“黄祸”论兴起于十九世纪末，盛行于二十世纪初，它宣称中国、日本等东方黄种民族的国家是威胁欧洲的祸害，为西方帝国主义对东方的奴役、掠夺制造舆论。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "华大妈跟了她指头看去，眼光便到了前面的坟，这坟上草根还没有全合，露出一块一块的黄土，煞是难看。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "心里忐忑，嘴里不说，仍是走，到得傍晚，临近了一座并不很高的黄土冈，上面有一些树林，几间土屋，他们便在途中议定，到这里去借宿。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "结果是有几个多事的人，就地用黄土把他们埋起来，还商量立一块石碑，刻上几个字，给后来好做古迹。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "掘出来的都是黄土，约到五尺多深，土色有些不同了，似乎是烂掉的材木。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "这大厅就是城楼的中一间，临窗一望，只见外面全是黄土的平原，愈远愈低；", "work": "第45章 出关 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "传说她用黄土造人。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他们踹起黄土来，飞进我的鼻孔，使我想打喷嚏了，但终于没有打，仅有想打的心。", "work": "第203章 死后 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "黄河以北的几省，是黄色和灰色画的，江浙是淡墨和淡绿，厦门是淡红和灰色，广州是深绿和深红。", "work": "第84章 在钟楼上（夜记之二）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他们研究了世界上各人种的脸色，决定了脸色一致的人种，就得取同一的行为，所以黄色的无产阶级，不该和黄色的有产阶级斗争，却该和白色的无产阶级斗争。", "work": "第135章 中国文坛上的鬼魅 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他们还想到了成吉思汗，作为理想的标本，描写他的孙子拔都汗，怎样率领了许多黄色的民族，侵入斡罗斯，将他们的文化摧残，贵族和平民都做了奴隶。", "work": "第135章 中国文坛上的鬼魅 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我给那些因为在近旁而极响的爆竹声惊醒，看见豆一般大的黄色的灯火光，接着又听得毕毕剥剥的鞭炮，是四叔家正在“祝福”了；", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "武王伐纣时，由陕西进入河南，在此渡过黄河，至朝歌近郊牧野，击败纣兵，便占领了纣的都城朝歌（故城在今河南汤阴县）。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "”我这才栗然地回想长安，记得看见很多的白杨，很大的石榴树，道中喝了不少的黄河水。", "work": "第56章 说胡须 杂文《坟》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "公元三八六年拓跋珪自立为魏王，后日益强大，占有黄河以北的土地；", "work": "第58章 论“他妈的！” 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "黄河以北的几省，是黄色和灰色画的，江浙是淡墨和淡绿，厦门是淡红和灰色，广州是深绿和深红。", "work": "第84章 在钟楼上（夜记之二）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "这是处世法的精义，只要黄河不流到脚下，炸弹不落在身边，可以保管一世没有挫折的。", "work": "第120章 世故三昧 杂文《南腔北调集》1932", "year": "1932", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "这就是想别人一心看着《六朝文絮》，而忘记了自己是抱在黄河决口之后，淹得仅仅露出水面的树梢头。", "work": "第132章 小品文的危机 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "结末又大略相象了，“及掘坑二尺，得黄金一釜，上云：天赐郭巨，官不得取，民不得夺！", "work": "第178章 《二十四孝图》散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我最初实在替这孩子捏一把汗，待到掘出黄金一釜，这才觉得轻松。", "work": "第178章 《二十四孝图》散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "如果一丝不走样，也掘出一釜黄金来，那自然是如天之福，但是，那时我虽然年纪小，似乎也明白天下未必有这样的巧事。", "work": "第178章 《二十四孝图》散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "不过彼一时，此一时，彼时我委实有点害怕：掘好深坑，不见黄金，连“摇咕咚”一同埋下去，盖上土，踏得实实的，又有什么法子可想呢。", "work": "第178章 《二十四孝图》散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "“唉，”他和蔼地说，“这西山的文豹，还是我们结婚以前射得的，那时多么好看，全体黄金光。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "那时我也就皱眉叹息，装作一齐发愁的模样，以示“所见略同”之至意，殊不知我国的圣君，贤臣，圣贤，圣贤之徒，却早已有过这一种黄金世界的理想了。", "work": "第51章 春末闲谈 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "有我所不乐意的在你们将来的黄金世界里，我不愿去。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "曾经借了他所做的小说，质问过梦想将来的黄金世界的理想家，因为要造那世界，先唤起许多人们来受苦。", "work": "第238章 娜拉走后怎样", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他说，“你们将黄金世界预约给他们的子孙了，可是有什么给他们自己呢？", "work": "第238章 娜拉走后怎样", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "这虽然也是颇远的梦，可是比黄金世界的梦近得不少了。", "work": "第238章 娜拉走后怎样", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "红鼻子老拱手里擎了一碗黄酒，说着，向间壁努一努嘴。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "那是赵太爷的儿子进了秀才的时候，锣声镗镗的报到村里来，阿q正喝了两碗黄酒，便手舞足蹈的说，这于他也很光彩，因为他和赵太爷原来是本家，细细的排起来他还比秀才长三辈呢。", "work": "第6章 阿Q正传(1) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "里面真是郁郁葱葱，但似乎并没有黄酒馒头，以及此外可吃的之类。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他们往往要亲眼看着黄酒从坛子里舀出，看过壶子底里有水没有，又亲看将壶子放在热水里，然后放心：在这严重监督下，羼水也很为难。", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "其实吴先生的“用讲话体为文”，即“其貌”也何尝与“黄口小儿所作若同”。", "work": "第114章 古书与白话 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "其中自然有古典，为“黄口小儿”所不知，尤有新典，为“束发小生”所不晓。", "work": "第114章 古书与白话 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "，其战史就有这么长，则见闻之多，自然非现在的“黄口小儿”所能企及。", "work": "第114章 古书与白话 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "，“黄口小儿”们还要看什么《甲寅》之流，也未免过于可惨罢，即使它“自从孤桐先生下台之后，…", "work": "第114章 古书与白话 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "这时眉间尺正看见一辆黄盖的大车驰来，正中坐着一个画衣的胖子，花白胡子，小脑袋；", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他也不暇计较，再望路上，不但黄盖车已经走过，连拥护的骑士也过去了一大阵了。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "再后面是黄盖随着路的不平而起伏着，并且渐渐近来了，于是现出灵车，上载金棺，棺里面藏着三个头和一个身体。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "”便拖出躲在背后的孩子来，这正是一个廿年前的闰土，只是黄瘦些，颈子上没有银圈罢了。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "“她于是详细的告诉我，说是‘大约从去年春天以来，她就见得黄瘦，后来忽而常常下泪了，问她缘故又不说；", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他觉得她脸上仿佛比往常黄瘦些，生怕她生了病。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "临河的土场上，太阳渐渐的收了它通黄的光线了。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "接着因为第九个王妃抗议，说她确曾看见王有几根通黄的胡子，现在怎么能知道决没有一根红的呢。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他移开桌子，用锄头一气掘起四块大方砖，蹲身一看，照例是黄澄澄的细沙，揎了袖爬开细沙，便露出下面的黑土来。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "譬如说罢，没有电灯的地方，小百姓不顾什么国货年，人人都要买点洋货的煤油，晚上就点起来：那么幽黯的黄澄澄的光线映在纸窗上，多不大方！", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "有一年的冬初，四叔家里要换女工，做中人的卫老婆子带她进来了，头上扎着白头绳，乌裙，蓝夹袄，月白背心，年纪大约二十六七，脸色青黄，但两颊却还是红的。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "她仍然头上扎着白头绳，乌裙，蓝夹祆，月白背心，脸色青黄，只是两颊上已经消失了血色，顺着眼，眼角上带些泪痕，眼光也没有先前那样精神了。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "在电杆旁，和他对面，正向着马路，其时也站定了两个人：一个是淡黄制服的挂刀的面黄肌瘦的巡警，手里牵着绳头，绳的那头就拴在别一个穿蓝布大衫上罩白背心的男人的臂膊上。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但是学校里的人们，虽是月薪十五六元的小职员，也没有一个不是乐天知命的，仗着逐渐打熬成功的铜筋铁骨，面黄肌瘦地从早办公一直到夜，其间看见名位较高的人物，还得恭恭敬敬地站起，实在都是不必“衣食足而知礼节”的人民。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "这剧诗的事迹，是黄色人种的西征，主将是成吉思汗的孙子拔都元帅，真正的黄色种。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "尤其不好的是红鼻子，有时简直像是将要熔化的蜡烛油，仿佛就要滴下来，使人看得栗栗危惧，也不及黄色人种的较为隐晦，也见得较为安全。", "work": "第68章 略论中国人的脸 杂文《而已集》 1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "小草也有点萎黄。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "然而这里却没有霜，也没有雪，凡萎黄的都是“寿终正寝”，怪不得别个。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "黄黄的脸，连脂粉也不及涂抹。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "还有鸡冠花，很细碎，和江浙的有些不同，也红红黄黄地永是这样一盆一盆站着。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "后来她也长得并不好看，不过是平常的瘦瘦的瓜子脸，黄脸皮；", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "”店主是一个黄脸黑须的胖子，果然很知道。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "一粒深黄色火，是南普陀寺的琉璃灯。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "”，白中隐青的单瓣梅花，深黄的磬口的蜡梅花磬口的蜡梅花：据清代陈淏子撰《花镜》卷三载：“圆瓣深黄，形似梅花，虽盛开如半含者，名磬口，最为世珍。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "银黄面庞上还有微红，", "work": "第214章 他们的花园 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "残膏的灯火照着残妆，粉有些褪了，眼圈显得微黄，眉毛的黛色也仿佛两边不一样。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "在电杆旁，和他对面，正向着马路，其时也站定了两个人：一个是淡黄制服的挂刀的面黄肌瘦的巡警，手里牵着绳头，绳的那头就拴在别一个穿蓝布大衫上罩白背心的男人的臂膊上。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "时候既然是深冬，渐近故乡时，天气又阴晦了，冷风吹进船舱中，呜呜的响，从篷隙向外一望，苍黄的天底下，远近横着几个萧索的荒村，没有一些活气。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他看见眼前浮出一朵扁圆的乌花，橙黄心，从左眼的左角漂到右，消失了；", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "在亚细亚的黄人中，现在可以拟为那时的蒙古的只有一个日本。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "不料这秃儿却拿着一支黄漆的棍子——就是阿q所谓哭丧棒哭丧棒：旧时在为父母送殡时，“孝子”须手拄“孝杖”，以示悲痛难支。", "work": "第7章 阿Q正传(2) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但今夜他却黄蜡似的躺在我的眼前，那眸子也不复似去年一般灼灼。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "也不必说鸣蝉在树叶里长吟，肥胖的黄蜂伏在菜花上，轻捷的叫天子（云雀）忽然从草间直窜向云霄里去了。", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但我们且看这黄色军的威猛和恶辣罢——", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我们的古人有言，“书中自有黄金屋”，现在渐在实现了。", "work": "第88章 书籍和财色 杂文《三闲集》1930", "year": "1930", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "待到小鸭褪了黄毛，爱罗先珂君却忽而渴念着他的“俄罗斯母亲”“俄罗斯母亲”：俄罗斯人民对祖国的爱称。", "work": "第17章 鸭的喜剧 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "其次便是一同去放牛，但或者因为高等动物了的缘故罢，黄牛水牛都欺生，敢于欺侮我，因此我也总不敢走近身，只好远远地跟着，站着。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "的话问你们：你们将黄金时代的出现预约给这些人们的子孙了，但有什么给这些人们自己呢？", "work": "第20章 头发的故事 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我独坐在发出黄光的菜油灯下，想，这百无聊赖的祥林嫂，被人们弃在尘芥堆中的，看得厌倦了的陈旧的玩物，先前还将形骸露在尘芥里，从活得有趣的人们看来，恐怕要怪讶她何以还要存在，现在总算被无常打扫得干干净净了。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "一个黄头发的女孩子又来冲上茶。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "一条土黄的军裤穿上了，嵌着很宽的红条，其次穿上去的是军衣，金闪闪的肩章，也不知道是什么品级，那里来的品级。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "七大人随即用那一只手的一个指头蘸着掌心，向自己的鼻孔里塞了两塞，鼻孔和人中立刻黄焦焦了。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "“还是‘杳如黄鹤’。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "黄铜床，或者质朴点，第一监狱工场做的榆木床也就够，床底下很干净，…", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "大家在关口目送着，去了两三丈远，还辨得出白发，黄袍，青牛，白口袋，接着就尘头逐步而起，罩着人和牛，一律变成灰色，再一会，已只有黄尘滚滚，什么也看不见了。", "work": "第45章 出关 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "因为中国革命还没有成功，正是青黄不接，忙于革命的时候。", "work": "第69章 革命时代的文学 杂文《而已集》 1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "最普通的是斗鸡，斗蟋蟀，南方有斗黄头鸟，斗画眉鸟，北方有斗鹌鹑，一群闲人们围着呆看，还因此赌输赢。", "work": "第77章 观斗 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "快要秋凉了，一早到马路上去走走，看见手捧肚子，口吐黄水的就是那些“席卷天下”的前任活神仙。", "work": "第100章 安贫乐道法 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "她生得黄胖而矮，“长”也不是形容词。", "work": "第177章 阿长与《山海经》 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "其中自然也有可以勉力仿效的，如“子路负米”，“黄香扇枕”之类。", "work": "第178章 《二十四孝图》散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我的住所的门前有一株不认识的植物，开着秋葵似的黄花。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "一片独有一点蛀孔，镶着乌黑的花边，在红、黄和绿的斑驳中，明眸似的向人凝视。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "’各家大半懒洋洋的踱出一个国民来，撅起一块斑驳陆离的洋布斑驳陆离的洋布：指辛亥革命后至一九二七年这一时期的国旗，也叫五色旗，由红黄蓝白黑五色横列。", "work": "第20章 头发的故事 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "脸上瘦削不堪，黄中带黑，而且消尽了先前悲哀的神色，仿佛是木刻似的；", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我还记得初看见西洋人的时候，就觉得他脸太白，头发太黄，眼珠太淡，鼻梁太高。", "work": "第68章 略论中国人的脸 杂文《而已集》 1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "十个油豆腐，辣酱要多！", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "油豆腐也煮得十分好；", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "其间还点菜，我们先前原是毫不客气的，但此刻却推让起来了，终于说不清哪一样是谁点的，就从堂倌的口头报告上指定了四样莱：茴香豆，冻肉，油油豆腐，青鱼干。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "堂倌搬上新添的酒菜来，排满了一桌，楼上又添了烟气和油豆腐的热气，仿佛热闹起来了；", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "店里坐着许多人，老栓也忙了，提着大铜壶，一趟一趟的给客人冲茶；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "枯草支支直立，有如铜丝。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "她虽然是粗笨女人，心里却有决断，便站起身，从木柜子里掏出每天节省下来的十三个小银元和一百八十铜钱，都装在衣袋里，锁上门，抱着宝儿直向何家奔过去。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "阿q的铜钱拿过来…", "work": "第6章 阿Q正传(1) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他赢而又赢，铜钱变成角洋，角洋变成大洋，大洋又成了叠。", "work": "第6章 阿Q正传(1) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "天色将黑，他睡眼蒙眬的在酒店门前出现了，他走近柜台，从腰间伸出手来，满把是银的和铜的，在柜上一扔说：“现钱！", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "尼姑待他们走后，定了神来检点，龙牌固然已经碎在地上了，而且又不见了观音娘娘座前的一个宣德炉宣德炉：明宣德年间（1426—1435）制造的一种比较名贵的小型铜香炉，炉底有“大明宣德年制”的字样。", "work": "第9章 阿Q正传(4) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "做工的人，傍午傍晚散了工，每每花四文铜钱，买一碗酒，——这是二十多年前的事，现在每碗要涨到十文，——靠柜外站着，热热的喝了休息；", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我没有思索的从外套袋里抓出一大把铜元，交给巡警，说：“请你给他…", "work": "第12章 一件小事 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "以前的事姑且搁起，这一大把铜元又是什么意思？", "work": "第12章 一件小事 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "七斤一手捏着象牙嘴白铜斗六尺多长的湘妃竹烟管，低着头，慢慢地走来，坐在矮凳上。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但非常忧愁，忘却了吸烟，象牙嘴六尺多长湘妃竹烟管的白铜斗里的火光，渐渐发黑了。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他在晚饭席上，对九斤老太说，这碗是在城内钉合的，因为缺口大，所以要十六个铜钉，三文一个，一总用了四十八文小钱。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "伊虽然新近裹脚，却还能帮同七斤嫂做事，捧着十八个铜钉十八个铜钉：据上文应是“十六个”。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但忽而又触着坚硬的小东西了，圆的，大约是一个锈铜钱；", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "我们每天的事情大概是掘蚯蚓，掘来穿在铜丝做的小钩上，伏在河沿上去钓虾。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "远处隐隐有两个铜盏相击的声音，使人忆起酸梅汤，依稀感到凉意，可是那懒懒的单调的金属音的间作，却使那寂静更其深远了。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但是学校里的人们，虽是月薪十五六元的小职员，也没有一个不是乐天知命的，仗着逐渐打熬成功的铜筋铁骨，面黄肌瘦地从早办公一直到夜，其间看见名位较高的人物，还得恭恭敬敬地站起，实在都是不必“衣食足而知礼节”的人民。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "只是盐和干辣椒，面粉，半株白菜，却聚集在一处了，旁边还有几十枚铜元。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他抽开书桌的抽屉，一把抓起所有的铜元，不下二三十，放在她摊开的手掌上，看她出了房，才又回过头来向书桌。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "黄铜床，或者质朴点，第一监狱工场做的榆木床也就够，床底下很干净，…", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他看得耕柱子已经把窝窝头上了蒸笼，便回到自己的房里，在壁厨里摸出一把盐渍藜菜干，一柄破铜刀，另外找了一张破包袱，等耕柱子端进蒸熟的窝窝头来，就一起打成一个包裹。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "墨子拍着红铜的兽环兽环：是指大门上的铜环。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "因为铜环衔在铜制兽头的嘴里，所以称之为兽环。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "今年在上海所见，专以小孩子为对手的糖担，十有九带了赌博性了，用一个铜元，经一种手续，可有得到一个铜元以上的糖的希望。", "work": "第88章 书籍和财色 杂文《三闲集》1930", "year": "1930", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "庙会时就有传授这些戏法的人，几枚铜元一件，学得来时，倒从此索然无味了。", "work": "第93章 朋友 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "明明用银元去换铜元，钱摊却帖着“收买现洋”的纸条，隐然以“买主”自命。", "work": "第112章 记“发薪” 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但如果他出身旧家，先前曾有玩弄翰墨的人，则只要不很破落，未将觉得没用的东西卖给旧货担，就也许还能在尘封的废物之中，寻出一个小小的镜屏，玲珑剔透的石块，竹根刻成的人像，古玉雕出的动物，锈得发绿的铜铸的三脚癞虾蟆：这就是所谓“小摆设”。", "work": "第132章 小品文的危机 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "例如罢，甲乙决斗，甲赢，乙死了，人们固然要看杀人的凶手，但也一样的要看那不中用的死尸，如果用芦席围起来，两个铜板看一下，准可以发一点小财的。", "work": "第147章 “京派”和“海派” 杂文《且介亭杂文》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "花几个铜元就发见了自己的优胜，那当然是很上算的。", "work": "第149章 论“人言可畏” 杂文《且介亭杂文二集》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "然而彼一时，此一时，如果三等客中有时偶缺一个铜元，你却只好在目的地以前下车，这时他就不肯通融，变成洋商的忠仆了。", "work": "第163章 “揩油” 杂文《准风月谈》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "那怕你，铜墙铁壁！", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "先到都督府去辞职，自然照准，派来了一个拖鼻涕的接收员，我交出账目和余款一角又两铜元，不是校长了。", "work": "第184章 范爱农 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "相骂声中失土地，相骂声中捐铜钱，", "work": "第211章 好东西歌 近代诗《集外集拾遗》1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "图三“哪怕你，铜墙铁壁”", "work": "第271章 《朝花夕拾》后记(2)", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "尤其不好的是红鼻子，有时简直像是将要熔化的蜡烛油，仿佛就要滴下来，使人看得栗栗危惧，也不及黄色人种的较为隐晦，也见得较为安全。", "work": "第68章 略论中国人的脸 杂文《而已集》 1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "麻将桌边，电灯替代了蜡烛，法会坛上，镁光照出了喇嘛当时举办的时轮金刚法会上，班禅喇嘛诵经作法时，有摄影师在佛殿内使用镁光灯照明。", "work": "第94章 偶感 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "但今夜他却黄蜡似的躺在我的眼前，那眸子也不复似去年一般灼灼。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "白吹下许多枯叶。", "work": "第210章 他 近代诗《集外集》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，那红的还是一点一点的往下滴。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "老栓也打开灯笼罩，用荷叶重新包了那红的馒头。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那头是秀眉长眼，皓齿红唇；", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "还有书上都写着，通红崭新！", "work": "第3章 狂人日记(2) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一犯讳，不问有心与无心，阿q便全疤通红的发起怒来，估量了对手，口讷的他便骂，气力小的他便打；", "work": "第6章 阿Q正传(1) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他癞疮疤块块通红了，将衣服摔在地上，吐一口唾沫，说：“这毛虫！", "work": "第6章 阿Q正传(1) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”尼姑满脸通红的说，一面赶快走。", "work": "第7章 阿Q正传(2) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”老尼姑两眼通红的说。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "七斤嫂没有听完，两个耳朵早通红了；", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "眼睛也像他父亲一样，周围都肿得通红，这我知道，在海边种地的人，终日吹着海风，大抵是这样的。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但也竖直了小小的通红的长耳朵，动着鼻子，眼睛里颇现些惊疑的神色，大约究竟觉得人地生疏，没有在老家时候的安心了。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "杀鸡，宰鹅，买猪肉，用心细细的洗，女人的臂膊都在水里浸得通红，有的还带着绞丝银镯子。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他满脸已经通红，似乎很有些醉，但眼光却又消沉下去了。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他走进他兄弟的卧室，觉得心跳得更厉害，因为他脸上似乎见得更通红了，而且发喘。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他走进房去点起灯来看，靖甫的脸更觉得通红了，的确还现出更红的点子，眼睑也浮肿起来。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "看靖甫的脸，已没有昨天那样通红了。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他忽而觉得，她那可爱的天真的脸，正像五年前的她的母亲，通红的嘴唇尤其像，不过缩小了轮廓。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他也忽然惊醒，一定睛，只见孩子还是挂着眼泪，而且张开了通红的嘴唇对他看。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "约摸有烙十张饼的时候，这才气急败坏的跑回来，鼻子冻得通红，嘴里一阵一阵的喷着白蒸气。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "眼圈通红的，恭敬的夸赞了姜汤的力量，谢了那太太的好意之后，这才解决了这一场大纠纷。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "只是抓劲已经没有先前似的有力，眼睛也淹在水里面，单露出一点尖尖的通红的小鼻子，咻咻地急促地喘气。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我家的漆黑的炉子里，是躺着通红的两把剑。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "楚国的郢城可是不比宋国：街道宽阔，房屋也整齐，大店铺里陈列着许多好东西，雪白的麻布，通红的辣椒，斑斓的鹿皮，肥大的莲子。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”还没有熄，西边的天际都通红。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大风忽地起来，火柱旋转着发吼，青的和杂色的石块都一色通红了，饴糖似的流布在裂缝中间，像一条不灭的闪电。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "秋高稻熟时节，吴越间所多的是螃蟹，煮到通红之后，无论取哪一只，揭开背壳来，里面就有黄，有膏；", "work": "第52章 论雷峰塔的倒掉 杂文《坟》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "想着走着，出去开门，果然，信封上首先就看见通红的一行字：国立北京女子师范大学。", "work": "第102章 “碰壁”之后 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "是小学生，在募集水灾的捐款，因为冷，连鼻子尖也冻得通红。", "work": "第151章 我要骗人 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "孩子们呵着冻得通红，像紫芽姜一般的小手，七八个一齐来塑雪罗汉。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他也就目光灼灼地嘴唇通红地坐在雪地里。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他也并非全树通红，最多的是浅绛，有几片则在绯红地上，还带着几团浓绿。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "因为他姓孔，别人便从描红纸描红纸：是一种印有红色楷字，供儿童摹写毛笔字用的字帖。", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "伊以为他们搬了家了，很高兴，然而仍然掘，待见底，那里面也铺着草叶和兔毛，而上面却睡着七个很小的兔，遍身肉红色，细看时，眼睛全都没有开。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他恭敬地跪着俯伏下去时，果然看见背上有一个圆圆的小包袱，青色布，上面还画上一些暗红色的花纹。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "讨论了小半夜，只将几根红色的胡子选出；", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "伊在这肉红色的天地间走到海边，全身的曲线都消融在淡玫瑰似的光海里，直到身中央才浓成一段纯白。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "风和火势卷得伊的头发都四散而且旋转，汗水如瀑布一般奔流，大光焰烘托了伊的身躯，使宇宙间现出最后的肉红色。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "女乙来点灯了，对面墙上挂着的彤弓，彤矢，卢弓，卢矢，弩机彤弓：红色的弓和矢。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "苏木汁即用苏方制成的红色溶液，可作染料。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "看他的画像，是红面孔，红胡须，不过祭祀的时候，却须避去一切红色的东西，而代之以绿色。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他大约像西班牙的牛一样，一看见红色，便会亢奋起来，做出一种可怕的行动的西班牙以前有斗牛的风俗，斗牛士手持红布对牛撩拨，待牛以角向他触去，即与之搏斗。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "因为她投缳之际，准备作厉鬼以复仇，红色较有阳气，易于和生人相接近，…", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那罩是昨晚新换的罩，雪白的纸，折出波浪纹的叠痕，一角还画出一枝猩红色的栀子。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但倘若用一柄尖锐的利刃，只一击，穿透这桃红色的，菲薄的皮肤，将见那鲜红的热血激箭似的以所有温热直接灌溉杀戮者；", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "繁霜夜降，木叶多半凋零，庭前的一株小小的枫树也变成红色了。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "头黑色，鳞片边缘暗红色；", "work": "第217章 我的失恋 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "体背黑褐色，有红色窄横纹，无毒。", "work": "第217章 我的失恋 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "头部有红色肉冠，喉下垂红色肉瓣；", "work": "第286章 通信", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "公鸡常扩翼展尾如扇状，同时肉冠及肉瓣便由红色变为蓝白色。", "work": "第286章 通信", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "红鼻子老拱手里擎了一碗黄酒，说着，向间壁努一努嘴。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这时聚集了几堆人：门内是王九妈蓝皮阿五之类，门外是咸亨的掌柜和红鼻子老拱之类。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这时红鼻子老拱的小曲，也早经唱完；", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "第二个是长的，在脸上很惹眼的显出一个红鼻子；", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "待到增加了秃头的老头子之后，空缺已经不多，而立刻又被一个赤膊的红鼻子胖大汉补满了。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他诧异地四顾：外面围着一圈人，上首是穿白背心的，那对面是一个赤膊的胖小孩，胖小孩后面是一个赤膊的红鼻子胖大汉。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他这时隐约悟出先前的伟大的障碍物的本体了，便惊奇而且佩服似的只望着红鼻子。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他近来很有点不大喜欢红鼻子的人。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但这回见了这尖尖的小红鼻子，却忽然觉得它可怜了，就又用那芦柴，伸到它的肚下去，老鼠抓着，歇了一回力，便沿着芦干爬了上来。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "尤其不好的是红鼻子，有时简直像是将要熔化的蜡烛油，仿佛就要滴下来，使人看得栗栗危惧，也不及黄色人种的较为隐晦，也见得较为安全。", "work": "第68章 略论中国人的脸 杂文《而已集》 1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "黑沉沉的灯光，照着宝儿的脸，绯红里带一点青。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "银白的曙光又渐渐显出绯红，太阳光接着照到屋脊。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但也还仿佛记得她脸色变成青白，后来又渐渐转作绯红，——没有见过，也没有再见的绯红；", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那白气到天半便变成白云，罩住了这处所，渐渐现出绯红颜色，映得一切都如桃花。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "至少，也当浸渍了亲族、师友、爱人的心，纵使时光流驶，洗成绯红，也会在微漠的悲哀中永存微笑的和蔼的旧影。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "的樱花烂熳的时节，望去确也像绯红的轻云，但花下也缺不了成群结队的“清国留学生”的速成班速成班：指东京弘文学院速成班；", "work": "第183章 藤野先生 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "很觉得满眼绯红，一定是太阳上来了。", "work": "第203章 死后 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他也并非全树通红，最多的是浅绛，有几片则在绯红地上，还带着几团浓绿。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我向来没有这样忍耐的等待过什么事物，而况这身边的胖绅士的吁吁的喘气，这台上的冬冬喤喤的敲打，红红绿绿的晃荡，加之以十二点，忽而使我省悟到在这里不适于生存了。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这时船走得更快，不多时，在台上显出人物来，红红绿绿的动，近台的河里一望乌黑的是看戏的人家的船篷。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我想你红绿帖红绿帖：旧时男女订婚时两家交换的帖子。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "又将两份红绿帖子互换了地方，推给两面，嘴里说道：", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "两方面各将红绿帖子收起，大家的腰骨都似乎直得多，原先收紧着的脸相也宽懈下来，全客厅顿然见得一团和气了。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们用两个长短不同的竹筒，染成红绿，连作一排，筒内藏一个弹簧，旁边有一个把手，摇起来就格格的响。", "work": "第95章 玩具 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "鬼卒和鬼王是红红绿绿的衣裳，赤着脚；", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他不但活泼而诙谐，单是那浑身雪白这一点，在红红绿绿中就有“鹤立鸡群”之概。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她将披着的头发向后一抖，人这才看清了脸孔：石灰一样白的圆脸，漆黑的浓眉，乌黑的眼眶，猩红的嘴唇。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那罩是昨晚新换的罩，雪白的纸，折出波浪纹的叠痕，一角还画出一枝猩红色的栀子。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "猩红的栀子开花时，枣树又要做小粉红花的梦，青葱地弯成弧形了…", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "还有赵白眼的母亲，——一说是赵司晨的母亲，待考，——也买了一件孩子穿的大红洋纱衫，七成新，只用三百大钱九二串。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我也不知道她喜欢深色还是浅色，就买了一朵大红的，一朵粉红的，都带到这里来。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "黄三就在他桌旁坐下，向桌面上一瞥，立刻在一面镜子和一堆乱书之间，发见了一个翻开着的大红纸的帖子。", "work": "第30章 高老夫子 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红衫子，黑色长背心，长发蓬松，颈挂两条纸锭，垂头，垂手，弯弯曲曲的走一个全台，内行人说：这是走了一个“心”字。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红花和斑红花，都在水里面浮动，忽而碎散，拉长了，缕缕的胭脂水，然而没有晕。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红花一朵朵全被拉长了，这时是泼剌奔迸的红锦带。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一面整顿了灶火，老栓便把一个碧绿的包，一个红红白白的破灯笼，一同塞在灶里；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我向来没有这样忍耐的等待过什么事物，而况这身边的胖绅士的吁吁的喘气，这台上的冬冬喤喤的敲打，红红绿绿的晃荡，加之以十二点，忽而使我省悟到在这里不适于生存了。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这时船走得更快，不多时，在台上显出人物来，红红绿绿的动，近台的河里一望乌黑的是看戏的人家的船篷。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "两人到山脚下一看，只见新叶嫩碧，土地金黄，野草里开着些红红白白的小花，真是连看看也赏心悦目。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "鬼卒和鬼王是红红绿绿的衣裳，赤着脚；", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他不但活泼而诙谐，单是那浑身雪白这一点，在红红绿绿中就有“鹤立鸡群”之概。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "还有鸡冠花，很细碎，和江浙的有些不同，也红红黄黄地永是这样一盆一盆站着。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "倒塌的亭子边还有一株山茶树，从晴绿的密叶里显出十几朵红花来，赫赫的在雪中明得如火，愤怒而且傲慢，如蔑视游人的甘心于远行。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红花和斑红花，都在水里面浮动，忽而碎散，拉长了，缕缕的胭脂水，然而没有晕。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红花一朵朵全被拉长了，这时是泼剌奔迸的红锦带。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但斑红花影也已碎散，伸长，就要织进塔、村女、狗、茅屋、云里去了。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我也不知道她喜欢深色还是浅色，就买了一朵大红的，一朵粉红的，都带到这里来。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "粉红的天空中，曲曲折折的漂着许多条石绿色的浮云，星便在那后面忽明忽灭的眨眼。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我记得有一种开过极细小的粉红花，现在还开着，但是更极细小了，她在冷的夜气中，瑟缩地做梦，梦见春的到来，梦见秋的到来，梦见瘦的诗人将眼泪擦在她最末的花瓣上，告诉她秋虽然来，冬虽然来，而此后接着还是春，蝴蝶乱飞，蜜蜂都唱起春词来了。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他知道小粉红花的梦，秋后要有春；", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "猩红的栀子开花时，枣树又要做小粉红花的梦，青葱地弯成弧形了…", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一面整顿了灶火，老栓便把一个碧绿的包，一个红红白白的破灯笼，一同塞在灶里；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "——分明有一圈红白的花，围着那尖圆的坟顶。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她们的眼睛都已老花多年了，但望这红白的花，却还能明白看见。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "两人到山脚下一看，只见新叶嫩碧，土地金黄，野草里开着些红红白白的小花，真是连看看也赏心悦目。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "唐与正守台日，酒边尝命赋红白桃花…", "work": "第142章 论俗人应避雅人 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一只手却撮着一个鲜红的馒头鲜红的馒头：指蘸有人血的馒头。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "倘是雌的，就有石榴子一般鲜红的子。", "work": "第52章 论雷峰塔的倒掉 杂文《坟》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "人的皮肤之厚，大概不到半分，鲜红的热血，就循着那后面，在比密密层层地爬在墙壁上的槐蚕更其密的血管里奔流，散出温热。", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但倘若用一柄尖锐的利刃，只一击，穿透这桃红色的，菲薄的皮肤，将见那鲜红的热血激箭似的以所有温热直接灌溉杀戮者；", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这《八月的乡村》，即是很好的一部，虽然有些近乎短篇的连续，结构和描写人物的手段，也不能比法捷耶夫的《毁灭》，然而严肃，紧张，作者的心血和失去的天空，土地，受难的人民，以至失去的茂草，高粱，蝈蝈，蚊子，搅成一团，鲜红的在读者眼前展开，显示着中国的一份和全部，现在和未来，死路与活路。", "work": "第281章 田军作《八月的乡村》序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "黄河以北的几省，是黄色和灰色画的，江浙是淡墨和淡绿，厦门是淡红和灰色，广州是深绿和深红。", "work": "第84章 在钟楼上（夜记之二）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "然而造化又常常为庸人设计，以时间的流驶，来洗涤旧迹，仅使留下淡红的血色和微漠的悲哀。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "在这淡红的血色和微漠的悲哀中，又给人暂得偷生，维持着这似人非人的世界。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "苟活者在淡红的血色中，会依稀看见微茫的希望；", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我向来没有这样忍耐的等待过什么事物，而况这身边的胖绅士的吁吁的喘气，这台上的冬冬喤喤的敲打，红红绿绿的晃荡，加之以十二点，忽而使我省悟到在这里不适于生存了。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这时船走得更快，不多时，在台上显出人物来，红红绿绿的动，近台的河里一望乌黑的是看戏的人家的船篷。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "鬼卒和鬼王是红红绿绿的衣裳，赤着脚；", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他不但活泼而诙谐，单是那浑身雪白这一点，在红红绿绿中就有“鹤立鸡群”之概。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "忽而一个红衫的小丑被绑在台柱子上，给一个花白胡子的用马鞭打起来了，大家才又振作精神的笑着看。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红衫子，黑色长背心，长发蓬松，颈挂两条纸锭，垂头，垂手，弯弯曲曲的走一个全台，内行人说：这是走了一个“心”字。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我只知道她何以要穿红衫。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "却可爱，自新郎新妇以至傧相、宾客、执事，没有一个不是尖腮细腿，像煞读书人的，但穿的都是红衫绿裤。", "work": "第185章 狗·猫·鼠 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "伊以为他们搬了家了，很高兴，然而仍然掘，待见底，那里面也铺着草叶和兔毛，而上面却睡着七个很小的兔，遍身肉红色，细看时，眼睛全都没有开。", "work": "第21章 兔和猫 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”伊想着，猛然间站立起来了，擎上那非常圆满而精力洋溢的臂膊，向天打一个欠伸，天空便突然失了色，化为神异的肉红，暂时再也辨不出伊所在的处所。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "伊在这肉红色的天地间走到海边，全身的曲线都消融在淡玫瑰似的光海里，直到身中央才浓成一段纯白。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "风和火势卷得伊的头发都四散而且旋转，汗水如瀑布一般奔流，大光焰烘托了伊的身躯，使宇宙间现出最后的肉红色。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "桃红和青白色的斗大的杂花，在眼前还分明，到远处可就成为斑斓的烟霭了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "旧时学塾教学生练习对仗的一种功课，用虚实平仄的字相对，如“天”对“地”、“雨”对“风”、“桃红”对“柳绿”之类。", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但倘若用一柄尖锐的利刃，只一击，穿透这桃红色的，菲薄的皮肤，将见那鲜红的热血激箭似的以所有温热直接灌溉杀戮者；", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "每有汗出，红腻而多香，或拭之于巾帕之上，其色如桃红也。", "work": "第213章 桃花 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "窗外沙沙的一阵声响，许多积雪从被它压弯了的一枝山茶树上滑下去了，树枝笔挺的伸直，更显出乌油油的肥叶和血红的花来。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "天边的血红的云彩里有一个光芒四射的太阳，如流动的金球包在荒古的熔岩中；", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "天边的血红的云彩里有一个光芒四射的太阳，如流动的金球包在荒古的熔岩中；", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "雪野中有血红的宝珠山茶宝珠山茶：据《广群芳谱》卷四十一载：“宝珠山茶，千叶含苞，历几月而放，殷红若丹，最可爱。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "上暗红的镶边。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他恭敬地跪着俯伏下去时，果然看见背上有一个圆圆的小包袱，青色布，上面还画上一些暗红色的花纹。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "头黑色，鳞片边缘暗红色；", "work": "第217章 我的失恋 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我只知道她何以要穿红衫。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "看王充的《论衡》，知道汉朝的鬼的颜色是红的，但再看后来的文字和图画，却又并无一定颜色，而在戏文里，穿红的则只有这“吊神”。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "绍兴的妇女，至今还偶有搽粉穿红之后，这才上吊的。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她年青，好看，穿着描金的红衣服，戴着珠冠，和我母亲的像差不多。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "还有扮犯人的，红衣枷锁，内中也有孩子。", "work": "第179章 五猖会 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "扫除腻粉呈风骨，褪却红衣学淡妆。", "work": "第219章 莲蓬人 七律", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这类母亲，在中国的指甲还未染红的乡下，也常有的，然而人往往嗤笑她，说做母亲的只爱不中用的儿子。", "work": "第153章 写于深夜里(1) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我忽而看见他眼圈微红了，但立即知道是有了酒意。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "炭火也正旺，映着那黑色人变成红黑，如铁的烧到微红。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "银黄面庞上还有微红，", "work": "第214章 他们的花园 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”孔乙己便涨红了脸，额上的青筋条条绽出，争辩道：“窃书不能算偷…", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "孔乙己喝过半碗酒，涨红的脸色渐渐复了原，旁人便又问道，“孔乙己，你当真认识字么？", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我的话可并没得罪你，你怎的便涨红了面孔！", "work": "第213章 桃花 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他恭敬地跪着俯伏下去时，果然看见背上有一个圆圆的小包袱，青色布，上面还画上一些暗红色的花纹。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "头黑色，鳞片边缘暗红色；", "work": "第217章 我的失恋 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红花和斑红花，都在水里面浮动，忽而碎散，拉长了，缕缕的胭脂水，然而没有晕。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红花一朵朵全被拉长了，这时是泼剌奔迸的红锦带。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们一不小心，一松手，阿呀，阿弥陀佛，她就一头撞在香案角上，头上碰了一个大窟窿，鲜血直流，用了两把香灰，包上两块红布还止不住血呢。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他大约像西班牙的牛一样，一看见红色，便会亢奋起来，做出一种可怕的行动的西班牙以前有斗牛的风俗，斗牛士手持红布对牛撩拨，待牛以角向他触去，即与之搏斗。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一阵红黑的火焰过去时，店屋里散满了一种奇怪的香味。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "炭火也正旺，映着那黑色人变成红黑，如铁的烧到微红。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "手里提着一个纸包和一支长烟管，那手也不是我所记得的红活圆实的手，却又粗又笨而且开裂，像是松树皮了。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "子君竟胖了起来，脸色也红活了；", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，甚至于到官里去告密，一面固然在保全自己的尊荣，但也未始没有那时所谓“以人血染红顶子”“以人血染红顶子”：清朝用不同质料和颜色的帽顶子来区分官阶的高低，最高的一品官是用红宝石或红珊瑚珠作帽顶子。", "work": "第54章 论“费厄泼赖”应该缓行(1）杂文《坟》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这样，映在冰的四壁，而且互相反映，化成无量数影，使这冰谷，成红珊瑚色。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "回望戏台在灯火光中，却又如初来未到时候一般，又缥缈得像一座仙山楼阁，满被红霞罩着了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "唱尽新词欢不见，红霞映树鹧鸪鸣。", "work": "第233章 赠人二首", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那白气到天半便变成白云，罩住了这处所，渐渐现出绯红颜色，映得一切都如桃花。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "飘渺的名园中，奇花盛开着，红颜的静女正在超然无事地逍遥，鹤唳一声，白云郁然而起…", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "阿q没有想得十分停当，已经发了鼾声，四两烛还只点去了小半寸，红焰焰的光照着他张开的嘴。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "冰谷四面，又登时满有红焰流动，如大火聚火聚：佛家语，猛火聚集的地方。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但他似乎被太阳晒得头晕了，脸色越加变成灰白，从劳乏的红肿的两眼里，发出古怪的闪光。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她说她曾经知道顺姑因为看见谁的头上戴着红的剪绒花，自己也想一朵，弄不到，哭了，哭了小半夜，就挨了她父亲的一顿打，后来眼眶还红肿了两三天。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这一点，就要任凭文学逞能，恰如冢中的白骨，往古来今，总要以它的永久来傲视少女颊上的轻红似的。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "青白的两颊泛出轻红，如铅上涂了胭脂水。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "不必说碧绿的菜畦，光滑的石井栏，高大的皂荚树，紫红的桑椹；", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "倘只有一条像诸君一样的紫红的绒绳的围巾，那可是无论宽到二尺或三尺，也完全是不中用。", "work": "第238章 娜拉走后怎样", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "黄三就在他桌旁坐下，向桌面上一瞥，立刻在一面镜子和一堆乱书之间，发见了一个翻开着的大红纸的帖子。", "work": "第30章 高老夫子 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”聪明人叹息着，眼圈有些发红，似乎要下泪。", "work": "第205章 聪明人和傻子和奴才 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "后洒处生草，其花甚媚，色如妇面，其叶正绿反红，秋开，名曰断肠花，即今秋海棠也。", "work": "第218章 别诸弟三首·庚子二月 七绝", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "怵目飞红随蝶舞，开心茸碧绕阶生。", "work": "第220章 惜花四律·步湘州", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，甚至于到官里去告密，一面固然在保全自己的尊荣，但也未始没有那时所谓“以人血染红顶子”“以人血染红顶子”：清朝用不同质料和颜色的帽顶子来区分官阶的高低，最高的一品官是用红宝石或红珊瑚珠作帽顶子。", "work": "第54章 论“费厄泼赖”应该缓行(1）杂文《坟》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "原来我的讲义已经从头到末，都用红笔添改过了，不但增加了许多脱漏的地方，连文法的错误，也都一一订正。", "work": "第183章 藤野先生 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她于是一笑，虽然颜色冻得红惨惨地，仍然瑟缩着。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那头是秀眉长眼，皓齿红唇；", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，又成了火焰的柱，赫赫的压倒了昆仑山上的红光。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "红帽哼兮黑帽呵，风流太守看梅花。", "work": "第142章 论俗人应避雅人 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "每有汗出，红腻而多香，或拭之于巾帕之上，其色如桃红也。", "work": "第213章 桃花 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "秃头正仰视那电杆上钉着的红牌上的四个白字，仿佛很觉得有趣。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "还有许多客，只见红青缎子马挂发闪。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "头顶是秃的，可是那脑壳和脸都很红润，油光光地发亮。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "戏仿唐宫护佳种，金铃轻绾赤阑边五代王仁裕《开元天宝遗事》卷上：“（宁王）至春时，于后园中纫红丝为绳，密缀金铃，系于花梢之上。", "work": "第220章 惜花四律·步湘州", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "墨子拍着红铜的兽环兽环：是指大门上的铜环。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "北京的白菜运往浙江，便用红头绳系住菜根，倒挂在水果店头，尊为“胶菜”；", "work": "第183章 藤野先生 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "正如中国人中，有吃燕窝鱼翅的人，有卖红丸的人，有拿回扣的人，但不能因此就说一切中国人，都在吃燕窝鱼翅，卖红丸，拿回扣一样。", "work": "第146章 中国语文的新生 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "阿q没有想得十分停当，已经发了鼾声，四两烛还只点去了小半寸，红焰焰的光照着他张开的嘴。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她年青，好看，穿着描金的红衣服，戴着珠冠，和我母亲的像差不多。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "而一切青白冰上，却有红影无数，纠结如珊瑚网。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "文禽共惜春将去，秀野欣逢红欲然。", "work": "第220章 惜花四律·步湘州", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一明天用红烛——要一斤重的——一对，香一封，到赵府上去赔罪。", "work": "第7章 阿Q正传(2) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "往往伸着颈子等候多时，却只见十几个人抬着一个金脸或蓝脸红脸的神像匆匆地跑过去。", "work": "第179章 五猖会 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "竟能气红了面孔。", "work": "第213章 桃花 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "黄河以北的几省，是黄色和灰色画的，江浙是淡墨和淡绿，厦门是淡红和灰色，广州是深绿和深红。", "work": "第84章 在钟楼上（夜记之二）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但倘若用一柄尖锐的利刃，只一击，穿透这桃红色的，菲薄的皮肤，将见那鲜红的热血激箭似的以所有温热直接灌溉杀戮者；", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那罩是昨晚新换的罩，雪白的纸，折出波浪纹的叠痕，一角还画出一枝猩红色的栀子。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那黑色人站在旁边，见炭火一红，便解下包袱，打开，两手捧出孩子的头来，高高举起。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "雪野中有血红的宝珠山茶宝珠山茶：据《广群芳谱》卷四十一载：“宝珠山茶，千叶含苞，历几月而放，殷红若丹，最可爱。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”孔乙己便涨红了脸，额上的青筋条条绽出，争辩道：“窃书不能算偷…", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "去年城里杀了犯人，还有一个生痨病的人，用馒头蘸血舐。", "work": "第3章 狂人日记(2) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一只手却撮着一个鲜红的馒头鲜红的馒头：指蘸有人血的馒头。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "旧时民间迷信，认为人血可以医治肺痨，刽子手便借此骗取钱财。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这样的人血馒头，什么痨病都包好！", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "夏瑜这些为了让像华小栓这样的老百姓能够摆脱清政府的腐败统治，为了无数人的未来和幸福付出生命的革命志士，却不能得到老百姓的理解、信任、支持，最终却被他为之付出生命的人，吞噬了自己的鲜血（用馒头沾他的血治病，即使这样，也还是无法挽救华小栓的性命），百姓的麻木不仁、愚昧无知与夏瑜的品质构成了鲜明的对比。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "幸而车夫早有点停步，否则伊定要栽一个大斤斗，跌到头破血出了。", "work": "第12章 一件小事 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，在新华门前烂泥里被国军打得头破血出之后，倒居然也发了一点薪水。", "work": "第15章 端午节 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们一不小心，一松手，阿呀，阿弥陀佛，她就一头撞在香案角上，头上碰了一个大窟窿，鲜血直流，用了两把香灰，包上两块红布还止不住血呢。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她仍然头上扎着白头绳，乌裙，蓝夹祆，月白背心，脸色青黄，只是两颊上已经消失了血色，顺着眼，眼角上带些泪痕，眼光也没有先前那样精神了。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这里有新的宾客，新的馈赠，新的颂扬，新的钻营，新的磕头和打拱，新的打牌和猜拳，新的冷眼和恶心，新的失眠和吐血…", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "现在已是深夜，吐了两口血，使我清醒起来。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他虽然穿一套皱的短衫裤，大襟上还有血迹，脸上也瘦削得不堪，然而面目却还是先前那样的面目，宁静地闭着嘴，合着眼，睡着似的，几乎要使我伸手到他鼻子前面，去试探他可是其实还在呼吸着。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "到一个多月前，这才听到他吐过几回血，但似乎也没有看医生；", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但他却不能即刻动弹，只觉得四肢无力，而且背上冷冰冰的还有许多汗，而且看见床前站着一个满脸流血的孩子，自己正要去打她。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "——荷生满脸是血，哭着进来了。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "传说也不少：有的说，周师到了牧野，和纣王的兵大战，杀得他们尸横遍野，血流成河，连木棍也浮起来，仿佛水上的草梗一样；", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "只听得吱的一声，他蹲下去仔细看时，只见口角上微有鲜血，大概是死掉了。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "低微的声音里，含着无限的悲哀，使他冷得毛骨悚然，而一转眼间，又觉得热血在全身中忽然腾沸。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "后来听得人说，第一个用血来饲你父亲自己炼成的剑的人，就是他自己——你的父亲。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "第一口撕尽了眉间尺的青衣，第二口便身体全都不见了，血痕也顷刻舔尽，只微微听得咀嚼骨头的声音。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "别的狼们第一口撕尽了它的皮，第二口便身体全都不见了，血痕也顷刻舔尽，只微微听得咀嚼骨头的声音。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "爱兮血兮兮谁乎独无。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "爱一头颅兮血乎呜呼！", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "血乎呜呼兮呜呼阿呼，", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "血一头颅兮爱乎呜呼。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”伊气得从两颊立刻红到耳根，火速背转头，另外去寻觅，好容易才看见一个不包铁片的东西，身子精光，带着伤痕还在流血，只是腰间却也围着一块破布片。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "而且，“十”字形的病菌，似乎已经侵入血管，流布全身，其势力早不在“！", "work": "第53章 再论雷峰塔的倒掉 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "有人论中国说，倘使没有带着新鲜的血液的野蛮的侵入，真不知自身会腐败到如何！", "work": "第53章 再论雷峰塔的倒掉 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，甚至于到官里去告密，一面固然在保全自己的尊荣，但也未始没有那时所谓“以人血染红顶子”“以人血染红顶子”：清朝用不同质料和颜色的帽顶子来区分官阶的高低，最高的一品官是用红宝石或红珊瑚珠作帽顶子。", "work": "第54章 论“费厄泼赖”应该缓行(1）杂文《坟》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "清末的官僚和绅士常用告密和捕杀革命党人作为升官的手段，所以当时有“以人血染红顶子”的说法。", "work": "第54章 论“费厄泼赖”应该缓行(1）杂文《坟》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "世界日日改变，我们的作家取下假面，真诚地，深入地，大胆地看取人生并且写出他的血和肉来的时候早到了；", "work": "第57章 论睁了眼看 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "现在，气象似乎一变，到处听不见歌吟花月的声音了，代之而起的是铁和血的赞颂。", "work": "第57章 论睁了眼看 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "描写军事的小说并不足奇，奇特的是这位“青年军人”的作者所自述的在战场上的心绪，这是“民族主义文学家”的自画像，极有郑重引用的价值的——“每天晚上站在那闪烁的群星之下，手里执着马枪，耳中听着虫鸣，四周飞动着无数的蚊子，那样都使人想到法国‘客军’在菲洲沙漠里与阿剌伯人争斗流血的生活。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "亚细亚勇士们张大吃人的血口。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "），这一张“亚细亚勇士们张大”的“吃人的血口”，我们的诗人却是对着“斡罗斯”，就是现在无产者专政的第一个国度，以消灭无产阶级的模范——这是“民族主义文学”的目标；", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但究竟因为是殖民地顺民的“民族主义文学”，所以我们的诗人所奉为首领的，是蒙古人拔都，不是中华人赵构，张开“吃人的血口”的是“亚细亚勇士们”，不是中国勇士们，所希望的是拔都的统驭之下的“友谊”，不是各民族间的平等的友爱——这就是露骨的所谓“民族主义文学”的特色，但也是青年军人的作者的悲哀。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，日本人“张大吃人的血口”，吞了东三省了。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "看同胞们的血喷出来了，", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "现在日本兵“东征”了东三省，正是“民族主义文学家”理想中的“西征”的第一步，“亚细亚勇士们张大吃人的血口”的开场。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他在《共产主义运动中的“左派”幼稚病》一书中曾说：“无产阶级专政是对旧社会的势力和传统进行的顽强斗争，流血的和不流血的，暴力的和和平的，军事的和经济的，教育的和行政的斗争。", "work": "第66章 习惯与改革 杂文《二心集》 1930", "year": "1930", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "据一九三一年十一月二十一日、二十二日《申报》报导，“青年援马团”曾抬棺游行，并有人断指写血书。", "work": "第67章 中华民国的新“堂·吉诃德”们 杂文《二心集》 1932", "year": "1932", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "不过，中国经了许多战士的精神和血肉的培养，却的确长出了一点先前所没有的幸福的花果来，也还有逐渐生长的希望。", "work": "第71章 黄花节的杂感 杂文《而已集》 1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "艰难缔造，原期死守，不幸冷口失陷，一令传出，即行后退，血汗金钱所合并成立之阵地，多未重用，弃若敝屣，至堪痛心；", "work": "第80章 “有名无实”的反驳 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "尼采爱看血写的书。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但我想，血写的文章，怕未必有罢。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "文章总是墨写的，血写的倒不过是血迹。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这些都应该和时光一同消逝，假使会比血迹永远鲜活，也只足证明文人是侥幸者，是乖角儿。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但真的血写的书，当然不在此例。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我在小学的时候，看同学们变小戏法，“耳中听字”呀，“纸人出血”呀，很以为有趣。", "work": "第93章 朋友 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "然而文学家却又悲哀起来，说是吐血了，这真是没有法子想。", "work": "第99章 看书琐记（二）杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "无泪的人则以血赠答，但又各各拒绝别人的血。", "work": "第105章 杂感 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "无泪的人无论何时，都不愿意爱人下泪，并且连血也不要：他拒绝一切为他的哭泣和灭亡。", "work": "第105章 杂感 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "杀了无泪的人，一定连血也不见。", "work": "第105章 杂感 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "血书，章程，请愿，讲学，哭，电报，开会，挽联，演说，神经衰弱，则一切无用。", "work": "第105章 杂感 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "血书所能挣来的是什么？", "work": "第105章 杂感 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "不过就是你的一张血书，况且并不好看。", "work": "第105章 杂感 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "跳蚤的来吮血，虽然可恶，而一声不响地就是一口，何等直截爽快。", "work": "第106章 夏三虫 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "如果所哼的是在说明人血应该给它充饥的理由，那可更其讨厌了，幸而我不懂。", "work": "第106章 夏三虫 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "后邻人忿兰，盗斫木母，应刀血出。", "work": "第109章 学界的三魂 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "四十多个青年的血，洋溢在我的周围，使我艰于呼吸视听，那里还能有什么言语？", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "真的猛士，敢于直面惨淡的人生，敢于正视淋漓的鲜血。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "然而造化又常常为庸人设计，以时间的流驶，来洗涤旧迹，仅使留下淡红的血色和微漠的悲哀。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "在这淡红的血色和微漠的悲哀中，又给人暂得偷生，维持着这似人非人的世界。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "况且始终微笑着的和蔼的刘和珍君，更何至于无端在府门前喋血呢？", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "中国军人的屠戮妇婴的伟绩，八国联军的惩创学生的武功，不幸全被这几缕血痕抹杀了。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但是中外的杀人者却居然昂起头来，不知道个个脸上有着血污…", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "人类的血战前行的历史，正如煤的形成，当时用大量的木材，结果却只是一小块，但请愿是不在其中的，更何况是徒手。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "然而既然有了血痕了，当然不觉要扩大。", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "苟活者在淡红的血色中，会依稀看见微茫的希望；", "work": "第110章 记念刘和珍君 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "改革自然常不免于流血，但流血非即等于改革。", "work": "第111章 空谈 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "血的应用，正如金钱一般，吝啬固然是不行的，浪费也大大的失算。", "work": "第111章 空谈 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "以血的洪流淹死一个敌人，以同胞的尸体填满一个缺陷，已经是陈腐的话了。", "work": "第111章 空谈 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "撕得鲜血淋漓，臭架子打得粉碎，然后可以谈后话。", "work": "第113章 我还不能“带住” 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "当时血出极多。", "work": "第115章 《阿Q正传》的成因 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我有时谈到人会怎样的骗人，怎样的卖友，怎样的吮血，他就前额亮晶晶的，惊疑地圆睁了近视的眼睛，抗议道，“会这样的么？", "work": "第117章 为了忘却的记念(1) 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "不是年青的为年老的写记念，而在这三十年中，却使我目睹许多青年的血，层层淤积起来，将我埋得不能呼吸，我只能用这样的笔墨，写几句文章，算是从泥土中挖一个小孔，自己延口残喘，这是怎样的世界呢。", "work": "第118章 为了忘却的记念(2) 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "先生做都督，就可以知道是不会流血的了。", "work": "第119章 谣言世家 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "笑里可以有刀，自称酷爱和平的人民，也会有杀人不见血的武器，那就是造谣言。", "work": "第119章 谣言世家 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这事发生之后，颇有人为鲁迅先生担心，因为不晓得流了‘一滩鲜血’的究竟是那一位。", "work": "第121章 经验 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "不过较之写些“青面獠牙”“口鼻流血”的笨伯，自然聪明得远。", "work": "第123章 捣鬼心传 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "生存的小品文，必须是匕首，是投枪，能和读者一同杀出一条生存的血路的东西；", "work": "第132章 小品文的危机 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "纣的军队也加反抗，非使他们的血流到漂杵不可。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "于是许多青年们，共产主义者及其嫌疑者，左倾者及其嫌疑者，以及这些嫌疑者的朋友们，就到处用自己的血来洗自己的错误，以及那些权力者们的错误。", "work": "第135章 中国文坛上的鬼魅 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "权力者们的先前的错误，是受了他们的欺骗的，所以必得用他们的血来洗干净。", "work": "第135章 中国文坛上的鬼魅 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但是，革命青年的血，却浇灌了革命文学的萌芽，在文学方面，倒比先前更其增加了革命性。", "work": "第135章 中国文坛上的鬼魅 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "蒙蔽是不能长久的，接着起来的又将是一场血腥的战斗。", "work": "第135章 中国文坛上的鬼魅 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "另一位是愿秋天薄暮，吐半口血，两个侍儿扶着，恹恹的到阶前去看秋海棠。", "work": "第136章 病后杂谈(1) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "第一位姑且不谈他罢，第二位的“吐半口血”，就有很大的道理。", "work": "第136章 病后杂谈(1) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "才子本来多病，但要“多”，就不能重，假使一吐就是一碗或几升，一个人的血，能有几回好吐呢？", "work": "第136章 病后杂谈(1) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "医生从他那大皮包里取出玻璃管来，要取我的血液，我知道他在疑心我生伤寒病了，自己也有些发愁。", "work": "第136章 病后杂谈(1) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "然而他第二天对我说，血里没有一粒伤寒菌；", "work": "第136章 病后杂谈(1) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "好几回检查了全体，没有死症，不至于呜呼哀哉是明明白白的，不过是每晚发热，没有力，不想吃东西而已，这真无异于“吐半口血”，大可享生病之福了。", "work": "第136章 病后杂谈(1) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那一位愿吐半口血的才子，也就是那时躺着无事，忽然记了起来的。", "work": "第136章 病后杂谈(1) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但又开始知道了有些聪明的士大夫，依然会从血泊里寻出闲适来。", "work": "第137章 病后杂谈(2) 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一时双方有剧烈之战争，头破血流，多人受有重伤。", "work": "第140章 说“面子” 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "发见了血液在人身中环流，这和一切社会制度有什么关系呢，却也被攻击了一世。", "work": "第146章 中国语文的新生 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "结果是：血液在人身中环流！", "work": "第146章 中国语文的新生 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "中国的人民，是常用自己的血，去洗权力者的手，使他又变成洁净的人物的，现在单是这模样就完事，总算好得很。", "work": "第151章 我要骗人 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "临末，用血写添几句个人的预感，算是一个答礼罢。", "work": "第151章 我要骗人 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "直到现在，那青年的惨白的脸，凹下的眼睛，两只满是鲜血的手，还时常浮在我的眼前，使我难于忘却！", "work": "第154章 写于深夜里(2) 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "被压迫者即使没有报复的毒心，也决无被报复的恐惧，只有明明暗暗，吸血吃肉的凶手或其帮闲们，这才赠人以“犯而勿校”或“勿念旧恶”的格言，——我到今年，也愈加看透了这些人面东西的秘密。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "凡有牺牲在祭坛前沥血之后，所留给大家的，实在只有“散胙”“散胙”：旧时祭祀以后，散发祭祀所用的肉。", "work": "第169章 即小见大  杂文《热风》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "即不然，或则叹息现代作品的浅薄，那是望著作家更其深，或则叹息现代作品之没有血泪，那是怕著作界复归于轻佻。", "work": "第170章 对于批评家的希望 杂文《热风》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "有一回，我就听得一间空屋里有着这种“数钱”的声音，推门进去，一条蛇伏在横梁上，看地上，躺着一匹隐鼠，口角流血，但两胁还是一起一落的。", "work": "第185章 狗·猫·鼠 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "人的皮肤之厚，大概不到半分，鲜红的热血，就循着那后面，在比密密层层地爬在墙壁上的槐蚕更其密的血管里奔流，散出温热。", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但倘若用一柄尖锐的利刃，只一击，穿透这桃红色的，菲薄的皮肤，将见那鲜红的热血激箭似的以所有温热直接灌溉杀戮者；", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们已经预觉着事后自己的舌上的汗或血的鲜味。", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "以死人似的眼光，赏鉴这路人们的干枯，无血的大戮，而永远沉浸于生命的飞扬的极致的大欢喜中。", "work": "第190章 复仇 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "钉杀了“人之子”的人们身上，比钉杀了“神之子”的尤其血污，血腥。", "work": "第191章 复仇（二）散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这以前，我的心也曾充满过血腥的歌声：血和铁，火焰和毒，恢复和报仇。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但以为身外的青春固在：星，月光，僵坠的蝴蝶，暗中的花，猫头鹰的不祥之言，杜鹃的啼血，笑的渺茫，爱的翔舞。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "可恨的是我的脚早经走破了，有许多伤，流了许多血。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "〔举起一足给老人看〕因此，我的血不够了；", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我要喝些血。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但血在哪里呢？", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "可是我也不愿意喝无论谁的血。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我只得喝些水，来补充我的血。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "只是我的力气太稀薄了，血里面太多了水的缘故罢。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他知道这点头就是敌人的武器，是杀人不见血的武器，许多战士都在此灭亡，正如炮弹一般，使猛士无所用其力。", "work": "第204章 这样的战士 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "暗暗地使人类流血，却不敢使血色永远鲜秾；", "work": "第207章 淡淡的血痕中 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他专为他的同类——人类中的怯弱者——设想，用废墟荒坟来衬托华屋，用时光来冲淡苦痛和血痕；", "work": "第207章 淡淡的血痕中 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "几片废墟和几个荒坟散在地上，映以淡淡的血痕，人们都在其间咀嚼着人我的渺茫的悲苦。", "work": "第207章 淡淡的血痕中 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他屹立着，洞见一切已改和现有的废墟和荒坟，记得一切深广和久远的苦痛，正视一切重叠淤积的凝血，深知一切已死，方生，将生和未生。", "work": "第207章 淡淡的血痕中 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我愿意在无形无色的鲜血淋漓的粗暴上接吻。", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "是的，青年的魂灵屹立在我眼前，他们已经粗暴了，或者将要粗暴了，然而我爱这些流血和隐痛的魂灵，因为他使我觉得是在人间，是在人间活着。", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "好生拿了回家，映着面庞，分外添出血色。", "work": "第214章 他们的花园 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，我以我血荐轩辕。", "work": "第222章 自题小像", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "血沃中原肥劲草，寒凝大地发春华。", "work": "第228章 无题", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "可惜中国太难改变了，即使搬动一张桌子，改装一个火炉，几乎也要血；", "work": "第238章 娜拉走后怎样", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "而且即使有了血，也未必一定能搬动，能改装。", "work": "第238章 娜拉走后怎样", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "你们看看，当今所谓“聪明人”，如段祺瑞、贾德耀等北洋军阀，只知勾结帝国主义者，屠杀无辜的爱国工人和学生，他们是双手沾满血腥的刽子手；", "work": "第242章 聪明人不能做事世界是属于傻子", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们会用“聪明”作钢刀，见血去杀人；", "work": "第242章 聪明人不能做事世界是属于傻子", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们也会用“聪明”作软刀，杀人不见血。", "work": "第242章 聪明人不能做事世界是属于傻子", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "革命有血，有污秽，但有婴孩。", "work": "第263章 《溃灭》一至三章译者附记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这“溃灭”正是新生之前的一滴血，是实际战斗者献给现代人们的大教训。", "work": "第263章 《溃灭》一至三章译者附记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "还是站在沙漠上，看看飞沙走石，乐则大笑，悲则大叫，愤则大骂，即使被沙砾打得遍身粗糙，头破血流，而时时抚摩自己的凝血，觉得若有花纹，也未必不及跟着中国的文士们去陪莎士比亚文士们：指陈西滢、徐志摩等人。", "work": "第265章 《华盖集》题记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "最末的论“费厄泼赖”这一篇，也许可供参考罢，因为这虽然不是我的血所写，却是见了我的同辈和比我年幼的青年们的血而写的。", "work": "第267章 写在《坟》后面", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我的确时时解剖别人，然而更多的是更无情面地解剖我自己，发表一点，酷爱温暖的人物已经觉得冷酷了，如果全露出我的血肉来，末路正不知要到怎样。", "work": "第267章 写在《坟》后面", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "野草，根本不深，花叶不美，然而吸取露，吸取水，吸取陈死人的血和肉，各各夺取它的生存。", "work": "第268章 《野草》题辞", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "林木伐尽，水泽湮枯，将来的一滴水，将和血液等价，倘这事能为现在和将来的青年所记忆，那么，这书所得的酬报，也就非常之大了。", "work": "第278章 《进化和退化》小引", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但革命的先驱者的血，现在已经并不希奇了。", "work": "第279章 《守常全集》题记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "血是流得太多了。", "work": "第279章 《守常全集》题记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们就义了已经足有五个年头了，我的记忆上，早又蒙上许多新鲜的血迹；", "work": "第283章 白莽作《孩儿塔》序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一个作者自取的别名，自然可以窥见他的思想，譬如“铁血”，“病鹃”之类，固不妨由此开一点小玩笑。", "work": "第295章 辱骂和恐吓决不是战斗", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但是最后在社会民主党政府的血腥镇压下失败。", "work": "第295章 辱骂和恐吓决不是战斗", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "提一个破旧的朱漆圆篮，外挂一串纸锭，三步一歇的走。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我回到四叔的书房里时，瓦楞上已经雪白，房里也映得较光明，极分明的显出壁上挂着的朱拓的大“寿”字，陈抟老祖写的，一边的对联已经脱落，松松的卷了放在长桌上，一边的还在，道是“事理通达，心气和平”。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "假使半夜之后，在薄暗中，远处隐约着一位这样的粉面朱唇，就是现在的我，也许会跑过去看看的，但自然，却未必就被诱惑得上吊。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "在许多人期待着恶人的没落的凝望中，他出来了，服饰比画上还简单，不拿铁索，也不带算盘，就是雪白的一条莽汉，粉面朱唇，眉黑如漆，蹙着，不知道是在笑还是在哭。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "中偷得胭脂来涂在嘴唇上。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "晴天又来消释他的皮肤，寒夜又使他结一层冰，化作不透明的水晶模样，连续的晴天又使他成为不知道算什么，而嘴上的胭脂也褪尽了。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大红花和斑红花，都在水里面浮动，忽而碎散，拉长了，缕缕的胭脂水，然而没有晕。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "青白的两颊泛出轻红，如铅上涂了胭脂水。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，忽然翻出一片压干的枫叶来。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "繁霜夜降，木叶多半凋零，庭前的一株小小的枫树也变成红色了。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "看看窗外，很能耐寒的树木也早经秃尽了，枫树更何消说得。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他忽而听得一种异样的声音，又不是爆竹。", "work": "第9章 阿Q正传(4) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "灰白色的沉重的晚云中间时时发出闪光，接着一声钝响，是送灶的爆竹；", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "煮熟之后，横七竖八的插些筷子在这类东西上，可就称为“福礼”了，五更天陈列起来，并且点上香烛，恭请福神们来享用，拜的却只限于男人，拜完自然仍然是放爆竹。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "年年如此，家家如此，——只要买得起福礼和爆竹之类的——今年自然也如此。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我给那些因为在近旁而极响的爆竹声惊醒，看见豆一般大的黄色的灯火光，接着又听得毕毕剥剥的鞭炮，是四叔家正在“祝福”了；", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我在蒙胧中，又隐约听到远处的爆竹声联绵不断，似乎合成一天音响的浓云，夹着团团飞舞的雪花，拥抱了全市镇。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一到阴历的十二月二十三，爆竹就到处毕毕剥剥。", "work": "第66章 习惯与改革 杂文《二心集》 1930", "year": "1930", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "听说，一声爆竹，他也会吃惊。", "work": "第101章 论辩的魂灵 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "还怕爆竹，能听枪炮声么？", "work": "第101章 论辩的魂灵 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "檐下放起爆竹，是在将月亮从天狗嘴里救出；", "work": "第127章 家庭为中国之基本 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我想，火药只做爆竹，指南针只看坟山，恐怕那原因就在此。", "work": "第127章 家庭为中国之基本 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "楚国的郢城可是不比宋国：街道宽阔，房屋也整齐，大店铺里陈列着许多好东西，雪白的麻布，通红的辣椒，斑斓的鹿皮，肥大的莲子。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "公输般独自喝着酒，看见客人不大动刀匕，过意不去，只好劝他吃辣椒：", "work": "第44章 非攻(2) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "仍然自己不觉得有什么“不对”，一有闲空，就照例地吃侉饼、花生米、辣椒，看《天演论》。", "work": "第186章 琐记 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "或者自己活得无聊了，便空泛地希望一大转变，来作刺戟，正如饱于饮食的人，想吃些辣椒爽口。", "work": "第247章 现今的新文学的概观", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一面整顿了灶火，老栓便把一个碧绿的包，一个红红白白的破灯笼，一同塞在灶里；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一阵红黑的火焰过去时，店屋里散满了一种奇怪的香味。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她站起身，点上灯火，屋子越显得静。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他说不出的新鲜而且高兴，烛火像元夜似的闪闪的跳，他的思想也迸跳起来了：", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "可是永远记得那狼眼睛，又凶又怯，闪闪的像两颗鬼火，似乎远远的来穿透了他的皮肉。", "work": "第10章 阿Q正传(5) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我整天的靠着火，也须穿上棉袄了。", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但非常忧愁，忘却了吸烟，象牙嘴六尺多长湘妃竹烟管的白铜斗里的火光，渐渐发黑了。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "最先就绝了人声，接着是陆续的熄了灯火，独有月亮，却缓缓的出现在寒夜的空中。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他爽然的站着，慢慢的再定睛，然而白光却分明的又起来了，这回更广大，比硫黄火更白净，比朝雾更霏微，而且便在靠东墙的一张书桌下。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他偷看房里面，灯火如此辉煌，下巴骨如此嘲笑，异乎寻常的怕人，便再不敢向那边看。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "灯火结了大灯花照着空屋和坑洞，毕毕剥剥的炸了几声之后，便渐渐的缩小以至于无有，那是残油已经烧尽了。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那老旦嘴边插着两个点火的纸捻子，旁边有一个鬼卒，我费尽思量，才疑心他或者是目连目连：也称“大目犍连”，又译目犍连。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们换了四回手，渐望见依稀的赵庄，而且似乎听到歌吹了，还有几点火，料想便是戏台，但或者也许是渔火。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那火接近了，果然是渔火；", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "回望戏台在灯火光中，却又如初来未到时候一般，又缥缈得像一座仙山楼阁，满被红霞罩着了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "正旺相，柴火又现成，我们可以偷一点来煮吃。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我们中间几个年长的仍然慢慢的摇着船，几个到后舱去生火，年幼的和我都剥豆。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他们的儿子阿牛烧火。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "她在这一天可做的事是不过坐在灶下烧火。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "祥林嫂除烧火之外，没有别的事，却闲着了，坐着只看柳妈洗器皿。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我给那些因为在近旁而极响的爆竹声惊醒，看见豆一般大的黄色的灯火光，接着又听得毕毕剥剥的鞭炮，是四叔家正在“祝福”了；", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "倒塌的亭子边还有一株山茶树，从晴绿的密叶里显出十几朵红花来，赫赫的在雪中明得如火，愤怒而且傲慢，如蔑视游人的甘心于远行。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”他从衣袋里掏出一支烟卷来，点了火衔在嘴里，看着喷出的烟雾，沉思似的说，“无非做了些无聊的事情，等于什么也没有做。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他又掏出一支烟卷来，衔在嘴里，点了火。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "堂前有了灯光，就是号召晚餐的烽火，合家的人们便都齐集在中央的桌子周围。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "“他如果能懂事，早就点了灯笼火把，寻了那孝女来了。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "你看，啧，那火光不是绿莹莹的么？", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "“我放火。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "“我放火！", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但他似乎并不留心别的事，只闪烁着狂热的眼光，在地上，在空中，在人身上，迅速地搜查，仿佛想要寻火种。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "许多人们的耳朵里，心里，都有了一个可怕的声音：“放火！", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "“我放火！", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我放火！", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "灯火销沉下去了，煤油已经将涸，他便站起，从书架下摸出一个小小的洋铁壶来添煤油。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "灯火在微微地发抖。", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我在小小的灯火光中，闭目枯坐，如见雪花片片飘坠，来增补这一望无际的雪堆；", "work": "第32章 孤独者(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但终于走进自己的屋子里了，没有灯火；", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "庄木三的烟早已吸到底，火逼得斗底里的烟油吱吱地叫了，还吸着。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那作品，像太阳的光一样，从无量的光源中涌出来，不像石火，用铁和石敲出来，这才是真艺术。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "“妈的纣王，一败，就奔上鹿台去了，”说话的大约是回来的伤兵，“妈的，他堆好宝贝，自己坐在中央，就点起火来。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他就近拾了两块石头，支起石片来，放上松针面，聚些枯枝，在下面生了火。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他跨下床，借着月光走向门背后，摸到钻火家伙，点上松明，向水瓮里一照。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "’他的眼里忽然发出电火的光芒，将一个剑匣放在我膝上。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "眉间尺忽然全身都如烧着猛火，自己觉得每一枝毛发上都仿佛闪出火星来。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他不觉全身一冷，但立刻又灼热起来，像是猛火焚烧着。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这样地经过了煮熟一锅小米的时光，眉间尺早已焦躁得浑身发火，看的人却仍不见减，还是津津有味随的。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "前面却仅有两点磷火一般的那黑色人的眼光。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”两粒磷火下的声音说，“哪两件么？", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "笑声即刻散布在杉树林中，深处随着有一群磷火似的眼光闪动，倏忽临近，听到咻咻的饿狼的喘息。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "近来便是走索，缘竿，抛丸，倒立，吞刀，吐火等等奇妙的把戏，也都看得毫无意味。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "并不要许多工夫，一个煮牛的大金鼎便摆在殿外，注满水，下面堆了兽炭，点起火来。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那黑色人站在旁边，见炭火一红，便解下包袱，打开，两手捧出孩子的头来，高高举起。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "炭火也正旺，映着那黑色人变成红黑，如铁的烧到微红。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "烟消火灭；", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”墨子让耕柱子用水和着玉米粉，自己却取火石和艾绒打了火，点起枯枝来沸水，眼睛看火焰，慢慢的说道：“我们的老乡公输般，他总是倚恃着自己的一点小聪明，兴风作浪的。", "work": "第43章 非攻(1) 小说《故事新编》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "伊于是只好搀些白石，再不够，便凑上些红黄的和灰黑的，后来总算将就的填满了裂口，止要一点火，一熔化，事情便完成，然而伊也累得眼花耳响，支持不住了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这时昆仑山上的古森林的大火昆仑山上的古森林的大火：语见《山海经·大荒西经》：“有大山名曰昆仑之丘…", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "伊向西一瞟，决计从那里拿过一株带火的大树来点芦柴积，正要伸手，又觉得脚趾上有什么东西刺着了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "伊就去点上火，而且不止一地方。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "火势并不旺，那芦柴是没有干透的，但居然也烘烘的响，很久很久，终于伸出无数火焰的舌头来，一伸一缩的向上舔，又很久，便合成火焰的重台花重台花：是指复瓣花。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，又成了火焰的柱，赫赫的压倒了昆仑山上的红光。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大风忽地起来，火柱旋转着发吼，青的和杂色的石块都一色通红了，饴糖似的流布在裂缝中间，像一条不灭的闪电。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "风和火势卷得伊的头发都四散而且旋转，汗水如瀑布一般奔流，大光焰烘托了伊的身躯，使宇宙间现出最后的肉红色。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "火柱逐渐上升了，只留下一堆芦柴灰。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "有一日，天气很寒冷，却听到一点喧嚣，那是禁军终于杀到了，因为他们等候着望不见火光和烟尘的时候，所以到得迟。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "残膏的灯火照着残妆，粉有些褪了，眼圈显得微黄，眉毛的黛色也仿佛两边不一样。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但嘴唇依然红得如火；", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "羿并不勒住马，任它跑着，一面却也拈弓搭箭，只一发，只听得铮的一声，箭尖正触着箭尖，在空中发出几点火花，两枝箭便向上挤成一个“人”字，又翻身落在地上了。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他望见人家的灯火已在前面，一高兴便不再想下去了。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，须发开张飘动，像黑色火，这一瞬息，使人仿佛想见他当年射日的雄姿。", "work": "第48章 奔月(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "所以君子固然相对慨叹，连杀人放火嫖妓骗钱以及一切鬼混的人，也都乘作恶余暇，摇着头说道，“他们人心日下了。", "work": "第49章 我之节烈观(1) 杂文《坟》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "的时候，他这一边还没有失火…", "work": "第56章 说胡须 杂文《坟》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "文艺是国民精神所发的火光，同时也是引导国民精神的前途的灯火。", "work": "第57章 论睁了眼看 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "上帝已逃，魔鬼扬起了火鞭复仇；", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "当“扬起火鞭”焚烧“斡罗斯”将要开头的时候，就像拔都那时的结局一样，朝鲜人乱杀中国人“九·一八”事变发生前不久，由于日本帝国主义者的挑拨和指使，平壤和汉城等地曾出现过袭击华侨的事件。", "work": "第60章 “民族主义文学”的任务和运命 杂文《二心集》 1931", "year": "1931", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一九三二年“一·二八”日本侵略军进攻上海时，处于战区的暨南大学、劳动大学、同济大学等，校舍或毁于炮火，或被日军夺占，学生也都流散。", "work": "第78章 逃的辩护 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "所以要一把眼泪一把鼻涕，哭哭啼啼，而又刁声浪气的诉苦说：我不入火坑入火坑：汪精卫一九三三年四月十四日在上海答记者问时曾说：“现时置身南京政府中人，其中心焦灼，无异投身火坑一样。", "work": "第82章 大观园的人才 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我们抱着共赴国难的决心，涌身跳入火坑，同时…", "work": "第82章 大观园的人才 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，竭诚招邀同志们一齐跳入火坑。", "work": "第82章 大观园的人才 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”，谁入火坑。", "work": "第82章 大观园的人才 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "然而娼妓说她自己落在火坑里，还是想人家去救她出来；", "work": "第82章 大观园的人才 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "而老鸨婆哭火坑，却未必有人相信她，何况她已经申明：她是敞开了怀抱，准备把一切人都拖进火坑的。", "work": "第82章 大观园的人才 杂文《伪自由书》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一粒深黄色火，是南普陀寺的琉璃灯。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，加以较详的说明，则：一，是知道火能烧死人，水也能淹死人，但水的模样柔和，好像容易亲近，因而也容易上当；", "work": "第98章 水性 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我就默然，点起火来吸烟卷。", "work": "第102章 “碰壁”之后 杂文《华盖集》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "主要讲述了：骆宏勋被历城县知县贺世赖诬为强盗，在解往京城途中，又被四杰村恶霸朱氏兄弟将囚车夺去，欲加杀害，幸为几个绿林好汉将他救出，并放火烧了四杰村。", "work": "第109章 学界的三魂 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但这是“洞若观火”的，否则，就不给。", "work": "第112章 记“发薪” 杂文《华盖集续编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但我想，这些译稿，也许去年已被兵火烧掉了。", "work": "第117章 为了忘却的记念(1) 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "普洛美修斯偷火给人类，总算是犯了天条，贬入地狱。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但是，钻木取火的燧人氏却似乎没有犯窃盗罪，没有破坏神圣的私有财产——那时候，树木还是无主的公物。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "火神菩萨只管放火，不管点灯。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "凡是火着就有他的份。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "从古至今，没有听到过点灯出名的名人，虽然人类从燧人氏那里学会了点火已经有五六千年的时间。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "放火就不然。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "秦始皇放了一把火——烧了书没有烧人；", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "项羽入关又放了一把火——烧的是阿房宫不是民房（？", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "却放火烧百姓了；", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "中世纪正教的僧侣就会把异教徒当柴火烧，间或还灌上油。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一场大火，几十里路的延烧过去，稻禾，树木，房舍——尤其是草棚——一会儿都变成飞灰了。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "还不够，就有燃烧弹，硫磺弹，从飞机上面扔下来，像上海一二八的大火似的，够烧几天几晚。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "可是说起来，他又不承认：火神菩萨据说原是保佑小民的，至于火灾，却要怪小民自不小心，或是为非作歹，纵火抢掠。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "历代放火的名人总是这样说，却未必总有人信。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我们只看见点灯是平凡的，放火是雄壮的，所以点灯就被禁止，放火就受供养。", "work": "第122章 火 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "日暮，忽见一人著乌袴褶来，取火照之，面首无七孔，面莽傥然。", "work": "第123章 捣鬼心传 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一关于中国的火", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "希腊人所用的火，听说是在一直先前，普洛美修斯普洛美修斯：通译普罗米修斯，是希腊神话中的神。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但那可不是燧人氏，而是随意放火的莫名其妙的东西。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "自从燧人氏发见，或者发明了火以来，能够很有味的吃火锅，点起灯来，夜里也可以工作了，但是，真如先哲之所谓“有一利必有一弊”罢，同时也开始了火灾，故意点上火，烧掉那有巢氏所发明的巢的了不起的人物也出现了。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "其实，放火，是很可怕的，然而比起烧饭来，却也许更有趣。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "因为他们住着帐篷，不知道住房子，所以就一路的放火。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "其实，秦的末年就有着放火的名人项羽在，一烧阿房宫，便天下闻名，至今还会在戏台上出现，连在日本也很有名。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "而且如果放火比先前放得大，那么，那人就也更加受尊敬，从远处看去，恰如救世主一样，而那火光，便令人以为是光明。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "不错，中国也有过讴歌了元和清的人们，但那是感谢火神之类，并非连心也全被征服了的证据。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "火灾极少，偷儿不来，土匪也一定不来抢。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "勃然大怒，放一把火烧光，算是保存自己的清白，则是昏蛋。", "work": "第138章 拿来主义 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我愿以愤火照出他的战绩，免使一群陷沙鬼将他先前的光荣和死尸一同拖入烂泥的深渊。", "work": "第144章 忆刘半农君 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "自杀事件一样，完全烟消火灭。", "work": "第149章 论“人言可畏” 杂文《且介亭杂文二集》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "，芒硝火焰似的起来，又芒硝火焰似的消灭了，其间就是开除了一个学生冯省三。", "work": "第169章 即小见大  杂文《热风》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "以文艺如此幼稚的时候，而批评家还要发掘美点，想扇起文艺的火焰来，那好意实在很可感。", "work": "第170章 对于批评家的希望 杂文《热风》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "灯火的带子也即刻被我旋高了。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一个从上面撞进去了，他于是遇到火，而且我以为这火是真的。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这以前，我的心也曾充满过血腥的歌声：血和铁，火焰和毒，恢复和报仇。", "work": "第192章 希望 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "屋上的雪是早已就有消化了的，因为屋里居人的火的温热。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "别的，在晴天之下，旋风忽来，便蓬勃地奋飞，在日光中灿灿地生光，如包藏火焰的大雾，旋转而且升腾，弥漫太空，使太空旋转而且升腾地闪烁。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "灯火渐渐地缩小了，在预告石油的已经不多；", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我俯看脚下，有火焰在。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "这是死火。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "死的火焰，现在先得到了你了！", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我拾起死火，正要细看，那冷气已使我的指头焦灼；", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "冰谷四面，又登时满有红焰流动，如大火聚火聚：佛家语，猛火聚集的地方。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我低头一看，死火已经燃烧，烧穿了我的衣裳，流在冰地上了。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "你们是再也遇不着死火了！", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一切鬼魂们的叫唤无不低微，然有秩序，与火焰的怒吼，油的沸腾，钢叉的震颤相和鸣，造成醉心的大乐醉心的大乐：使人沉醉的音乐。", "work": "第199章 失掉的好地狱 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大火聚有时不过冒些青烟；", "work": "第199章 失掉的好地狱 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "“鬼魂们在冷油温火里醒来，从魔鬼的光辉中看见地狱小花，惨白可怜，被大蛊惑，倏忽间记起人世，默想至不知几多年，遂同时向着人间，发一声反狱的绝叫。", "work": "第199章 失掉的好地狱 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "而且，添薪加火，磨砺刀山，使地狱全体改观，一洗先前颓废的气象。", "work": "第199章 失掉的好地狱 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "火一样热；", "work": "第199章 失掉的好地狱 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "灯火也因惊惧而缩小了，东方已经发白。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "只看见眼前仿佛有火花一样，我于是坐了起来。", "work": "第203章 死后 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "在编校中夕阳居然西下，灯火给我接续的光。", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "你们很平静地生活在这里，这是后方，没有炮火。", "work": "第245章 在厦门中山中学的讲演", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "你们应该把从中山先生书里得来的道理，把从其他进步书里得来的知识，当作革命武器，向着一切旧习惯，一切旧思想，一切人吃人的旧制度，猛烈开火！", "work": "第245章 在厦门中山中学的讲演", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "你们在平静的后方，还有应该向它开火的无形的敌人。", "work": "第245章 在厦门中山中学的讲演", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "地火在地下运行，奔突；", "work": "第268章 《野草》题辞", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "但同是涉及风月的“月黑杀人夜，风高放火天”呢，这不明明是一联古诗么？", "work": "第273章 《准风月谈》前记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我的谈风月也终于谈出了乱子来，不过也并非为了主张“杀人放火”。", "work": "第273章 《准风月谈》前记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "“若要官，杀人放火受招安；", "work": "第281章 田军作《八月的乡村》序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "一个人如果还有友情，那么，收存亡友的遗文真如捏着一团火，常要觉得寝食不安，给它企图流布的。", "work": "第283章 白莽作《孩儿塔》序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "即使前面是深渊，荆棘，狭谷，火坑，都由我自己负责。", "work": "第289章 北京通信", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "阿q没有想得十分停当，已经发了鼾声，四两烛还只点去了小半寸，红焰焰的光照着他张开的嘴。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "否则，地狱的毒焰将围绕我，猛烈地烧尽我的悔恨和悲哀。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我将在孽风和毒焰中拥抱子君，乞她宽容，或者使她快意…", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "风和火势卷得伊的头发都四散而且旋转，汗水如瀑布一般奔流，大光焰烘托了伊的身躯，使宇宙间现出最后的肉红色。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”每一新制度，新学术，新名词，传入中国，便如落在黑色染缸，立刻乌黑一团，化为济私助焰之具。", "work": "第94章 偶感 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "边缘都参差如夏云头，镶着日光，发出水银色焰。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "当我幼小的时候，本就爱看快舰激起的浪花，洪炉喷出的烈焰。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "冰谷四面，又登时满有红焰流动，如大火聚火聚：佛家语，猛火聚集的地方。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "接着又是甲士，后面一大队骑着高头大马的文武官员，簇拥着一位王爷，紫糖色脸，络腮胡子，左捏黄斧头，右拿白牛尾，威风凛凛：这正是“恭行天罚”的周王发周王发：即周武王姬发，周文王之子。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他正在厨房里，紫色的圆脸，头戴一顶小毡帽，颈上套一个明晃晃的银项圈，这可见他的父亲十分爱他，怕他死去，所以在神佛面前许下愿心，用圈子将他套住了。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "先前的紫色的圆脸，已经变作灰黄，而且加上了很深的皱纹；", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "她又带了窗外的半枯的槐树的新叶来，使我看见，还有挂在铁似的老干上的一房一房的紫白的藤花。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "不必说碧绿的菜畦，光滑的石井栏，高大的皂荚树，紫红的桑椹；", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "倘只有一条像诸君一样的紫红的绒绳的围巾，那可是无论宽到二尺或三尺，也完全是不中用。", "work": "第238章 娜拉走后怎样", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "兵丁们给他穿上紫袍，戴上荆冠，庆贺他；", "work": "第191章 复仇（二）散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "戏弄完了，就给他脱了紫袍，仍穿他自己的衣服。", "work": "第191章 复仇（二）散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "女孩——约十岁，紫发，乌眼珠，白地黑方格长衫。", "work": "第196章 过客 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "伊自己也不知道怎样，总觉得左右不如意了，便焦躁的伸出手去，信手一拉，拔起一株从山上长到天边的紫藤，一房一房的刚开着大不可言的紫花，伊一挥，那藤便横搭在地面上，遍地散满了半紫半白的花瓣。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "久之，他抬起紫涨着的脸来了，还是气喘吁吁的，说：“到昨天，他们又打起架来了，从堂屋一直打到门口。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我也不知道她喜欢深色还是浅色，就买了一朵大红的，一朵粉红的，都带到这里来。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "粉红的天空中，曲曲折折的漂着许多条石绿色的浮云，星便在那后面忽明忽灭的眨眼。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "我记得有一种开过极细小的粉红花，现在还开着，但是更极细小了，她在冷的夜气中，瑟缩地做梦，梦见春的到来，梦见秋的到来，梦见瘦的诗人将眼泪擦在她最末的花瓣上，告诉她秋虽然来，冬虽然来，而此后接着还是春，蝴蝶乱飞，蜜蜂都唱起春词来了。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "他知道小粉红花的梦，秋后要有春；", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "猩红的栀子开花时，枣树又要做小粉红花的梦，青葱地弯成弧形了…", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "从先前的阿q看来，小d本来是不足齿数的，但他近来挨了饿，又瘦又乏已经不下于小d，所以便成了势均力敌的现象，四只手拔着两颗头，都弯了腰，在钱家粉墙上映出一个蓝色的虹形，至于半点钟之久了。", "work": "第7章 阿Q正传(2) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "庵周围也是水田，粉墙突出在新绿里，后面的低土墙里是菜园。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "——一望全是粉墙，", "work": "第210章 他 近代诗《集外集》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "你看我那时的一双手呵，真是粉嫩粉嫩…", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "“你现在也还是粉嫩粉嫩…", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "假使半夜之后，在薄暗中，远处隐约着一位这样的粉面朱唇，就是现在的我，也许会跑过去看看的，但自然，却未必就被诱惑得上吊。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "在许多人期待着恶人的没落的凝望中，他出来了，服饰比画上还简单，不拿铁索，也不带算盘，就是雪白的一条莽汉，粉面朱唇，眉黑如漆，蹙着，不知道是在笑还是在哭。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "大约又走了十多里，这才接近树林，然而满眼是胡蜂，粉蝶，蚂蚁，蚱蜢，那里有一点禽兽的踪迹。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "那白气到天半便变成白云，罩住了这处所，渐渐现出绯红颜色，映得一切都如桃花。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "桃花开在园西，李花开在园东。", "work": "第213章 桃花 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "桃花红，李花白。", "work": "第213章 桃花 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "（没说，桃花不及李花白。", "work": "第213章 桃花 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "桃花可是生了气，满面涨作“杨妃红”“杨妃红”：《开元天宝遗事·红汗》：“贵妃…", "work": "第213章 桃花 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "四时皆春，一年到头请你看桃花，你想够多么乏味？", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "即使那桃花有车轮般大，也只能在初上去的时候，暂时吃惊，决不会每天做一首“桃之夭夭”的。", "work": "第293章 厦门通信（二）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "桃红和青白色的斗大的杂花，在眼前还分明，到远处可就成为斑斓的烟霭了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "粉红的天空中，曲曲折折的漂着许多条石绿色的浮云，星便在那后面忽明忽灭的眨眼。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "red", "quote": "”伊想着，猛然间站立起来了，擎上那非常圆满而精力洋溢的臂膊，向天打一个欠伸，天空便突然失了色，化为神异的肉红，暂时再也辨不出伊所在的处所。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "他看见眼前浮出一朵扁圆的乌花，橙黄心，从左眼的左角漂到右，消失了；", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "咳嗽一止，万籁寂然，秋末的夕阳，照着两部白胡子，都在闪闪的发亮。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "在编校中夕阳居然西下，灯火给我接续的光。", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "广州的天气热得真早，夕阳从西窗射入，逼得人只能勉强穿一件单衣。", "work": "第269章 《朝花夕拾》小引", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "yellow", "quote": "回望戏台在灯火光中，却又如初来未到时候一般，又缥缈得像一座仙山楼阁，满被红霞罩着了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "”孔乙己立刻显出颓唐不安模样，脸上笼上了一层灰色，嘴里说些话；", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "到时是春初的下午，天气欲雨不雨，一切都罩在灰色中；", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "大家在关口目送着，去了两三丈远，还辨得出白发，黄袍，青牛，白口袋，接着就尘头逐步而起，罩着人和牛，一律变成灰色，再一会，已只有黄尘滚滚，什么也看不见了。", "work": "第45章 出关 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "这在我自己，是容易解答的：因为我新来而且灰色。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "黄河以北的几省，是黄色和灰色画的，江浙是淡墨和淡绿，厦门是淡红和灰色，广州是深绿和深红。", "work": "第84章 在钟楼上（夜记之二）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "那么，比起现在将眼眶染成淡灰色的时式打扮来，可以说是更彻底，更可爱。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "但这一段话，我是和不是东西之流开开玩笑的，要使他爬耳搔腮，热剌剌的觉得他的世界有些灰色。", "work": "第282章 徐懋庸作《打杂集》序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "至于叶遂宁是碰死在自己的希望碑上不必说了，戈理基呢，听人说，已有点灰色了。", "work": "第287章 文艺与革命（并冬芬来信）", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "这种东西，用处只有一种，就是可以借此看看社会的暗角落里，有着怎样灰色的人们，以为现在是攀附显现的时候了，也都吞吞吐吐的来开口。", "work": "第290章 答KS君", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "街上黑沉沉的一无所有，只有一条灰白的路，看得分明。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "但他似乎被太阳晒得头晕了，脸色越加变成灰白，从劳乏的红肿的两眼里，发出古怪的闪光。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "灰白色的沉重的晚云中间时时发出闪光，接着一声钝响，是送灶的爆竹；", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "胖孩子却看见那白背心正研究着这发亮的秃头，他也便跟着去研究，就只见满头光油油的，耳朵左近还有一片灰白色的头发，此外也不见得有怎样新奇。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "有时，仿佛看见那生路就像一条灰白的长蛇，自己蜿蜒地向我奔来，我等着，等着，看看临近，但忽然便消失在黑暗里了。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "然而子君的葬式却又在我的眼前，是独自负着虚空的重担，在灰白的长路上前行，而又即刻消失在周围的严威和冷眼里了。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "他看见他的母亲坐在灰白色的月影中，仿佛身体都在颤动；", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "她像是受了炮烙似的缩手，脸色同时变作灰黑，也不再去取烛台，只是失神的站着。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "到入棺，是连殳很不妥帖地躺着，脚边放一双黄皮鞋，腰边放一柄纸糊的指挥刀，骨瘦如柴的灰黑的脸旁，是一顶金边的军帽。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "远望前面，便依稀看见灰黑色的城墙和雉堞。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "伊于是只好搀些白石，再不够，便凑上些红黄的和灰黑的，后来总算将就的填满了裂口，止要一点火，一熔化，事情便完成，然而伊也累得眼花耳响，支持不住了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "我姑且举灰黑的手装作喝干一杯酒，我将在不知道时候的时候独自远行。", "work": "第188章 影的告别 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "北京的冬季，地上还有积雪，灰黑色的秃树枝丫叉于晴朗的天空中，而远处有一二风筝浮动，在我是一种惊异和悲哀。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "先前的紫色的圆脸，已经变作灰黄，而且加上了很深的皱纹；", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "灰白色的沉重的晚云中间时时发出闪光，接着一声钝响，是送灶的爆竹；", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "胖孩子却看见那白背心正研究着这发亮的秃头，他也便跟着去研究，就只见满头光油油的，耳朵左近还有一片灰白色的头发，此外也不见得有怎样新奇。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "她脸色陡然变成灰黄，死了似的；", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "暗中忽然仿佛看见一堆食物，这之后，便浮出一个子君的灰黄的脸来，睁了孩子气的眼睛，恳托似的看着我。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "他看见他的母亲坐在灰白色的月影中，仿佛身体都在颤动；", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "远望前面，便依稀看见灰黑色的城墙和雉堞。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "北京的冬季，地上还有积雪，灰黑色的秃树枝丫叉于晴朗的天空中，而远处有一二风筝浮动，在我是一种惊异和悲哀。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "树木也多起来了，不知名的落叶树上，已经吐着新芽，一望好像灰绿的轻烟，其间夹着松柏，在蒙胧中仍然显得很苍翠。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "伊于是弯腰去捧芦灰了，一捧一捧的填在地上的大水里，芦灰还未冷透，蒸得水澌澌的沸涌，灰水泼满了伊的周身。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "那么，比起现在将眼眶染成淡灰色的时式打扮来，可以说是更彻底，更可爱。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "这大苦痛，便是社会的可怜的椒盐，和战士孤儿等辈一同，给无聊的社会一些味道，使他们无聊地持续下去。", "work": "第277章 柔石作《二月》小引", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "潮湿的路极其分明，仰看太空，浓云已经散去，挂着一轮圆月，散出冷静的光辉。", "work": "第33章 孤独者(3) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "一天是阴沉的上午，太阳还不能从云里面挣扎出来；", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "面河的农家的烟突里，逐渐减少了炊烟，女人孩子们都在自己门口的土场上泼些水，放下小桌子和矮凳；", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "别家的炊烟早消歇了，碗筷也洗过了，而陈士成还不去做饭。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "天色愈阴暗了，下午竟下起雪来，雪花大的有梅花那么大，满天飞舞，夹着烟霭和忙碌的气色，将鲁镇乱成一团糟。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "我在这繁响的拥抱中，也懒散而且舒适，从白天以至初夜的疑虑，全给祝福的空气一扫而空了，只觉得天地圣众歆享了牲醴和香烟，都醉醺醺的在空中蹒跚，预备给鲁镇的人们以无限的幸福。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "旧历的年底毕竟最像年底，村镇上不必说，就在天空中也显出将到新年的气象来。", "work": "第22章 祝福(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "“唉唉，我真傻，”祥林嫂看了天空，叹息着，独语似的说。", "work": "第23章 祝福(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "上面是铅色的天，白皑皑的绝无精彩，而且微雪又飞舞起来了。", "work": "第24章 在酒楼上(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "gray", "quote": "天空的铅色来得更浓；", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他好容易曲曲折折的汇出手来，手里就有一个小小的长方包，葵绿色的，一径递给四太太。", "work": "第26章 肥皂(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "她刚接到手，就闻到一阵似橄榄非橄榄的说不清的香味，还看见葵绿色的纸包上有一个金光灿烂的印子和许多细簇簇的花纹。", "work": "第26章 肥皂(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "于是这葵绿色的纸包被打开了，里面还有一层很薄的纸，也是葵绿色，揭开薄纸，才露出那东西的本身来，光滑坚致，也是葵绿色，上面还有细簇簇的花纹，而薄纸原来却是米色的，似橄榄非橄榄的说不清的香味也来得更浓了。", "work": "第26章 肥皂(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”她捧孩子似的将那葵绿色的东西送到鼻子下面去，嗅着说。", "work": "第26章 肥皂(1) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他一进门，迎头就看见中央的方桌中间放着那肥皂的葵绿色的小小的长方包，包中央的金印子在灯光下明晃晃的发闪，周围还有细小的花纹。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "接着一朵明绿花，墨绿色的心；", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "粉红的天空中，曲曲折折的漂着许多条石绿色的浮云，星便在那后面忽明忽灭的眨眼。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "看他的画像，是红面孔，红胡须，不过祭祀的时候，却须避去一切红色的东西，而代之以绿色。", "work": "第134章 关于中国的两三件事 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "《山海经》也另买了一部石印的，每卷都有图赞，绿色的画，字是红的，比那木刻的精致得多了。", "work": "第177章 阿长与《山海经》 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "一面整顿了灶火，老栓便把一个碧绿的包，一个红红白白的破灯笼，一同塞在灶里；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "这时候，我的脑里忽然闪出一幅神异的图画来：深蓝的天空中挂着一轮金黄的圆月，下面是海边的沙地，都种着一望无际的碧绿的西瓜，其间有一个十一二岁的少年，项带银圈，手捏一柄钢叉，向一匹猹猹：鲁迅在一九二九年五月四日致舒新城的信中说：“‘猹’字是我据乡下人所说的声音，生造出来的，读如‘查’。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "我在朦胧中，眼前展开一片海边碧绿的沙地来，上面深蓝的天空中挂着一轮金黄的圆月。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "于是架起两支橹，一支两人，一里一换，有说笑的，有嚷的，夹着潺潺的船头激水的声音，在左右都是碧绿的豆麦田地的河流中，飞一般径向赵庄前进了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他只得绕出树林，看那后面却又是碧绿的高粱田，远处散点着几间小小的土屋。", "work": "第47章 奔月(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "不必说碧绿的菜畦，光滑的石井栏，高大的皂荚树，紫红的桑椹；", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "但是，草木在旱干的沙漠中间，拼命伸长他的根，吸取深地中的水泉，来造成碧绿的林莽，自然是为了自己的“生”的，然而使疲劳枯渴的旅人，一见就怡然觉得遇到了暂时息肩之所，这是如何的可以感激，而且可以悲哀的事？", "work": "第208章 一觉 散文诗《野草》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "我向来没有这样忍耐的等待过什么事物，而况这身边的胖绅士的吁吁的喘气，这台上的冬冬喤喤的敲打，红红绿绿的晃荡，加之以十二点，忽而使我省悟到在这里不适于生存了。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "这时船走得更快，不多时，在台上显出人物来，红红绿绿的动，近台的河里一望乌黑的是看戏的人家的船篷。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "我想你红绿帖红绿帖：旧时男女订婚时两家交换的帖子。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "又将两份红绿帖子互换了地方，推给两面，嘴里说道：", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "两方面各将红绿帖子收起，大家的腰骨都似乎直得多，原先收紧着的脸相也宽懈下来，全客厅顿然见得一团和气了。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他们用两个长短不同的竹筒，染成红绿，连作一排，筒内藏一个弹簧，旁边有一个把手，摇起来就格格的响。", "work": "第95章 玩具 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "鬼卒和鬼王是红红绿绿的衣裳，赤着脚；", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他不但活泼而诙谐，单是那浑身雪白这一点，在红红绿绿中就有“鹤立鸡群”之概。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "我向来没有这样忍耐的等待过什么事物，而况这身边的胖绅士的吁吁的喘气，这台上的冬冬喤喤的敲打，红红绿绿的晃荡，加之以十二点，忽而使我省悟到在这里不适于生存了。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "这时船走得更快，不多时，在台上显出人物来，红红绿绿的动，近台的河里一望乌黑的是看戏的人家的船篷。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "鬼卒和鬼王是红红绿绿的衣裳，赤着脚；", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "我向来没有这样忍耐的等待过什么事物，而况这身边的胖绅士的吁吁的喘气，这台上的冬冬喤喤的敲打，红红绿绿的晃荡，加之以十二点，忽而使我省悟到在这里不适于生存了。", "work": "第18章 社戏(1) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "这时船走得更快，不多时，在台上显出人物来，红红绿绿的动，近台的河里一望乌黑的是看戏的人家的船篷。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "鬼卒和鬼王是红红绿绿的衣裳，赤着脚；", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他跳下卧床之后，四五步就走到书桌面前，坐下去，抽出一张绿格纸，毫不迟疑，但又自暴自弃似的写下一行题目道：《幸福的家庭》。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”他也说不下去了，停了一会，忽而奋然的抓起笔来，就在写着一行“幸福的家庭”的绿格纸上起算草，起了好久，这才仰起头来说道：“五吊八！", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”他想着，随即粗暴的抓起那写着一行题目和一堆算草的绿格纸来，揉了几揉，又展开来给她拭去了眼泪和鼻涕。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "村外多是水田，满眼是新秧的嫩绿，夹着几个圆形的活动的黑点，便是耕田的农夫。", "work": "第7章 阿Q正传(2) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "地上都嫩绿了，便是不很换叶的松柏也显得格外的娇嫩。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "你看，啧，那火光不是绿莹莹的么？", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "从此完全静寂了，暮色下来，绿莹莹的长明灯更其分明地照出神殿，神龛，而且照到院子，照到木栅里的昏暗。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "终于，腰腿的酸痛逼得伊站立起来，倚在一座较为光滑的高山上，仰面一看，满天是鱼鳞样的白云，下面则是黑压压的浓绿。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他也并非全树通红，最多的是浅绛，有几片则在绯红地上，还带着几团浓绿。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "庵周围也是水田，粉墙突出在新绿里，后面的低土墙里是菜园。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "沛君便十分安心似的沉静地走到自己的桌前，看着呈文，一面伸手去揭开了绿锈斑斓的墨盒盖。", "work": "第37章 弟兄 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "接着一朵明绿花，墨绿色的心；", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "接着一朵明绿花，墨绿色的心；", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "树木也多起来了，不知名的落叶树上，已经吐着新芽，一望好像灰绿的轻烟，其间夹着松柏，在蒙胧中仍然显得很苍翠。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "叶子变成暗绿，熟了。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "大概是谁都知道，孩子并没有死，喷出来的是装在刀柄里的苏木汁苏木汁：苏木是常绿小乔木，心材称“苏方”。", "work": "第83章 怎么写（夜记之一）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "黄河以北的几省，是黄色和灰色画的，江浙是淡墨和淡绿，厦门是淡红和灰色，广州是深绿和深红。", "work": "第84章 在钟楼上（夜记之二）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "黄河以北的几省，是黄色和灰色画的，江浙是淡墨和淡绿，厦门是淡红和灰色，广州是深绿和深红。", "work": "第84章 在钟楼上（夜记之二）杂文《三闲集》1927", "year": "1927", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "但如果他出身旧家，先前曾有玩弄翰墨的人，则只要不很破落，未将觉得没用的东西卖给旧货担，就也许还能在尘封的废物之中，寻出一个小小的镜屏，玲珑剔透的石块，竹根刻成的人像，古玉雕出的动物，锈得发绿的铜铸的三脚癞虾蟆：这就是所谓“小摆设”。", "work": "第132章 小品文的危机 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "雪下面还有冷绿的杂草。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "否则，纵有成千成百的天才，也因为没有泥土，不能发达，要像一碟子绿豆芽。", "work": "第239章 未有天才之前", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "看看绿叶，编编旧稿，总算也在做一点事。", "work": "第269章 《朝花夕拾》小引", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "一片独有一点蛀孔，镶着乌黑的花边，在红、黄和绿的斑驳中，明眸似的向人凝视。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "后洒处生草，其花甚媚，色如妇面，其叶正绿反红，秋开，名曰断肠花，即今秋海棠也。", "work": "第218章 别诸弟三首·庚子二月 七绝", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "何况在风沙扑面，狼虎成群的时候，谁还有这许多闲工夫，来赏玩琥珀扇坠，翡翠戒指呢。", "work": "第132章 小品文的危机 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "所以遇到很熟的友人，他便要劝诱他就在院子里种白菜；", "work": "第17章 鸭的喜剧 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "四铭尽量的睁大了细眼睛瞪着看得她要哭，这才收回眼光，伸筷自去夹那早先看中了的一个菜心去。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "可是菜心已经不见了，他左右一瞥，就发见学程刚刚夹着塞进他张得很大的嘴里去，他于是只好无聊的吃了一筷黄菜叶。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "只是盐和干辣椒，面粉，半株白菜，却聚集在一处了，旁边还有几十枚铜元。", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "就在他背后的书架的旁边，已经出现了一座白菜堆，下层三株，中层两株，顶上一株，向他叠成一个很大的a字。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "有一间堆积房，白菜之类都到那边去。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "主人的书房另一间，靠壁满排着书架，那旁边自然决没有什么白菜堆；", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "——这可以放心，她必不至于捧着白菜的。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "接着一座六株的白菜堆，屹然的向他叠成一个很大的a字。", "work": "第38章 幸福的家庭 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "这保姆是乡下人，在和他讲故事：黄帝打蚩尤，大禹捉无支祁，还有乡下人荒年吃薇菜。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他又记得了自己问过薇菜的样子，而且山上正见过这东西。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "还是用那烙过松针面的石片，来烤薇菜。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "两人就笑嘻嘻的来尝烤薇菜；", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他们从此天天采薇菜。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "然而近地的薇菜，却渐渐的采完，虽然留着根，一时也很难生长，每天非走远路不可了。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "而且新住处也逐渐的难找了起来，因为既要薇菜多，又要溪水近，这样的便当之处，在首阳山上实在也不可多得的。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "有一天，他们俩正在吃烤薇菜，不容易找，所以这午餐已在下午了。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "‘上那西山呀采它的薇菜，", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "那两个傻瓜发脾气，因此不吃薇菜了，也是事实，不过并没有死，倒招来了很大的运气。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "见武王伐纣，以为不义，遂隐于首阳之山，不食周粟，以微（薇）菜为粮。", "work": "第40章 采薇(2) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "看见鱼翅，并不就抛在路上以显其“平民化”，只要有养料，也和朋友们像萝卜白菜一样的吃掉，只不用它来宴大宾；", "work": "第138章 拿来主义 杂文《且介亭杂文》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "不必说碧绿的菜畦，光滑的石井栏，高大的皂荚树，紫红的桑椹；", "work": "第182章 从百草园到三味书屋散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "北京的白菜运往浙江，便用红头绳系住菜根，倒挂在水果店头，尊为“胶菜”；", "work": "第183章 藤野先生 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "她一面哭，一面想：想那时候，自己纺着棉纱，宝儿坐在身边吃茴香豆，瞪着一双小黑眼睛想了一刻，便说：“妈！", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "倘肯多花一文，便可以买一碟盐煮笋，或者茴香豆，做下酒物了，如果出到十几文，那就能买一样荤菜，但这些顾客，多是短衣帮，大抵没有这样阔绰。", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”他不回答，对柜里说，“温两碗酒，要一碟茴香豆。", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "茴香豆的茴字，怎样写的？", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”我暗想我和掌柜的等级还很远呢，而且我们掌柜也从不将茴香豆上账；", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "他便给他们吃茴香豆，一人一颗。", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "孩子吃完豆，仍然不散，眼睛都望着碟子。", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”直起身又看一看豆，自己摇头说，“不多不多！", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "立刻就要吃饭了，还吃炒豆子，吃穷了一家子！", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "伊的曾孙女儿六斤捏着一把豆，正从对面跑来，见这情形，便直奔河边，藏在乌桕树后，伸出双丫角的小头，大声说：“这老不死的！", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "九斤老太自从庆祝了五十大寿以后，便渐渐的变了不平家，常说伊年青的时候，天气没有现在这般热，豆子也没有现在这般硬；", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "于是架起两支橹，一支两人，一里一换，有说笑的，有嚷的，夹着潺潺的船头激水的声音，在左右都是碧绿的豆麦田地的河流中，飞一般径向赵庄前进了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "两岸的豆麦和河底的水草所发散出来的清香，夹杂在水气中扑面的吹来；", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "那声音大概是横笛，宛转，悠扬，使我的心也沉静，然而又自失起来，觉得要和它弥散在含着豆麦蕴藻之香的夜气里。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "这回想出来的是桂生，说是罗汉豆罗汉豆：即学名蚕豆，又称胡豆、倭豆、佛豆。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "岸上的田里，乌油油的都是结实的罗汉豆。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”一声答应，大家便散开在阿发家的豆田里，各摘了一大捧，抛入船舱中。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "我们中间几个年长的仍然慢慢的摇着船，几个到后舱去生火，年幼的和我都剥豆。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "不久豆熟了，便任凭航船浮在水面上，都围起来用手撮着吃。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "吃完豆，又开船，一面洗器具，豆荚豆壳全抛在河水里，什么痕迹也没有了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "“双喜，你们这班小鬼，昨天偷了我的豆了罢？", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”我抬头看时，是六一公公棹着小船，卖了豆回来了，船肚里还有剩下的一堆豆。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "“豆可中吃呢？", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "我的豆种是粒粒挑选过的，乡下人不识好歹，还说我的豆比不上别人的呢。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "待到母亲叫我回去吃晚饭的时候，桌上便有一大碗煮熟了的罗汉豆，就是六一公公送给母亲和我吃的。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "”但我吃了豆，却并没有昨夜的豆那么好。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "真的，一直到现在，我实在再没有吃到那夜似的好豆，——也不再看到那夜似的好戏了。", "work": "第19章 社戏(2) 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "否则，纵有成千成百的天才，也因为没有泥土，不能发达，要像一碟子绿豆芽。", "work": "第239章 未有天才之前", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "树木也多起来了，不知名的落叶树上，已经吐着新芽，一望好像灰绿的轻烟，其间夹着松柏，在蒙胧中仍然显得很苍翠。", "work": "第39章 采薇(1) 小说《故事新编》1935", "year": "1935", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "green", "quote": "头发蓬松，正如青烟一阵。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他也还如平常一样，黄的方脸和蓝布破大衫，只在浓眉底下的大而且长的眼睛中，略带些异样的光闪，看人就许多工夫不眨眼，并且总含着悲愤疑惧的神情。", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "在电杆旁，和他对面，正向着马路，其时也站定了两个人：一个是淡黄制服的挂刀的面黄肌瘦的巡警，手里牵着绳头，绳的那头就拴在别一个穿蓝布大衫上罩白背心的男人的臂膊上。", "work": "第29章 示众 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "爱姑怕事情有变故，连忙去看庄木三，见他已经在茶几上打开一个蓝布包裹，取出洋钱来。", "work": "第36章 离婚 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "过了十多天，或者一个月罢，我还记得，是她告假回家以后的四五天，她穿着新的蓝布衫回来了，一见面，就将一包书递给我，高兴地说道：“哥儿，有画儿的‘三哼经’，我给你买来了！", "work": "第177章 阿长与《山海经》 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "知道了这消息之后，椭圆的脸，细细的眼睛和胡子，蓝布袍，黑马褂，就时时出现在我的眼前，其间还隐约看见绞首台。", "work": "第279章 《守常全集》题记", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "从先前的阿q看来，小d本来是不足齿数的，但他近来挨了饿，又瘦又乏已经不下于小d，所以便成了势均力敌的现象，四只手拔着两颗头，都弯了腰，在钱家粉墙上映出一个蓝色的虹形，至于半点钟之久了。", "work": "第7章 阿Q正传(2) 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "伊透过乌桕叶，看见又矮又胖的赵七爷正从独木桥上走来，而且穿着宝蓝色竹布的长衫。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "声，仰头便能看见一个淡墨色的蟹风筝或嫩蓝色的蜈蚣风筝。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "”他说，一面打开暗蓝色布的包裹来。", "work": "第203章 死后 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "这时候，我的脑里忽然闪出一幅神异的图画来：深蓝的天空中挂着一轮金黄的圆月，下面是海边的沙地，都种着一望无际的碧绿的西瓜，其间有一个十一二岁的少年，项带银圈，手捏一柄钢叉，向一匹猹猹：鲁迅在一九二九年五月四日致舒新城的信中说：“‘猹’字是我据乡下人所说的声音，生造出来的，读如‘查’。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "我在朦胧中，眼前展开一片海边碧绿的沙地来，上面深蓝的天空中挂着一轮金黄的圆月。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "你看，三头六臂的蓝脸，三只眼睛，长帽，半个的头，牛头和猪牙齿，都应该吹熄…", "work": "第28章 长明灯 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "往往伸着颈子等候多时，却只见十几个人抬着一个金脸或蓝脸红脸的神像匆匆地跑过去。", "work": "第179章 五猖会 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "蓝脸，上面又画些鱼鳞，也许是龙鳞或别的什么鳞罢，我不大清楚。", "work": "第181章 无常 散文《朝花夕拾》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "秋天的后半夜，月亮下去了，太阳还没有出，只剩下一片乌蓝的天；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "蓝皮阿五便放下酒碗，在他脊梁上用死劲的打了一掌，含含糊糊嚷道：“你…", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "”似乎是蓝皮阿五的声音。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "她抬头看时，正是蓝皮阿五，睡眼朦胧的跟着她走。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "这时聚集了几堆人：门内是王九妈蓝皮阿五之类，门外是咸亨的掌柜和红鼻子老拱之类。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "蓝皮阿五也伸出手来，很愿意自告奋勇；", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "这一日里，蓝皮阿五简直整天没有到；", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "蓝皮阿五便伸手揪住了老拱的肩头，两个人七歪八斜的笑着挤着走去。", "work": "第5章 明天 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "女人们见面时一定说，邹七嫂在阿q那里买了一条蓝绸裙，旧固然是旧的，但只化了九角钱。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "但第二日，邹七嫂便将那蓝裙去染了皂，又将阿q可疑之点传扬出去了，可是确没有提起秀才要驱逐他这一节。", "work": "第8章 阿Q正传(3) 小说 《呐喊》 1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "伊透过乌桕叶，看见又矮又胖的赵七爷正从独木桥上走来，而且穿着宝蓝色竹布的长衫。", "work": "第13章 风波 小说《呐喊》1920", "year": "1920", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "我便轻如行云，漂浮空际，上有蔚蓝的天，下是深山大海，广厦高楼，战场，摩托车，洋场，公馆，晴明的闹市，黑暗的夜…", "work": "第35章 伤逝(2) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "戏子扮好一个鬼王，蓝面鳞纹，手执钢叉，还得有十几名鬼卒，则普通的孩子都可以应募。", "work": "第158章 女吊 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "”他说，一面打开暗蓝色布的包裹来。", "work": "第203章 死后 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "那时，我抬头一看，碧蓝的天空有飞机在翱翔，演武场的南面有耸入云际的无线电台，北面有厦门大学的一整排巍峨的花岗石洋楼，构成一幅美丽悦人的图画。", "work": "第244章 在厦门大学送别会上的讲演", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "两个人都悚然的回过头，只见那乌鸦张开两翅，一挫身，直向着远处的天空，箭也似的飞去了。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "这时候，我的脑里忽然闪出一幅神异的图画来：深蓝的天空中挂着一轮金黄的圆月，下面是海边的沙地，都种着一望无际的碧绿的西瓜，其间有一个十一二岁的少年，项带银圈，手捏一柄钢叉，向一匹猹猹：鲁迅在一九二九年五月四日致舒新城的信中说：“‘猹’字是我据乡下人所说的声音，生造出来的，读如‘查’。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他们不知道一些事，闰土在海边时，他们都和我一样只看见院子里高墙上的四角的天空。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "我在朦胧中，眼前展开一片海边碧绿的沙地来，上面深蓝的天空中挂着一轮金黄的圆月。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "现在总算脱出这牢笼了，我从此要在新的开阔的天空中翱翔，趁我还未忘却了我的翅子的扇动。", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "这上面的夜的天空，奇怪而高，我生平没有见过这样奇怪而高的天空。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "但是，有几枝还低亚着，护定他从打枣的竿梢所得的皮伤，而最直最长的几枝，却已默默地铁似的直刺着奇怪而高的天空，使天空闪闪地鬼眼；", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "直刺着天空中圆满的月亮，使月亮窘得发白。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "鬼眼的天空越加非常之蓝，不安了，仿佛想离去人间，避开枣树，只将月亮剩下。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "而一无所有的干子，却仍然默默地铁似的直刺着奇怪而高的天空，一意要制他的死命，不管他各式各样地着许多蛊惑的眼睛。", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "北京的冬季，地上还有积雪，灰黑色的秃树枝丫叉于晴朗的天空中，而远处有一二风筝浮动，在我是一种惊异和悲哀。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "四面都还是严冬的肃杀，而久经诀别的故乡的久经逝去的春天，却就在这天空中荡漾了。", "work": "第194章 风筝 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "”她说着，同时抬起眼睛，无可告诉地一看破旧屋顶以上的天空。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "她于是抬起眼睛向着天空，并无词的言语也沉默尽绝，惟有颤动，辐射若太阳光，使空中的波涛立刻回旋，如遭飓风，汹涌奔腾于无边的荒野。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "瞪眼望天空，他更无话可说。", "work": "第214章 他们的花园 近代诗《集外集》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "那时，我抬头一看，碧蓝的天空有飞机在翱翔，演武场的南面有耸入云际的无线电台，北面有厦门大学的一整排巍峨的花岗石洋楼，构成一幅美丽悦人的图画。", "work": "第244章 在厦门大学送别会上的讲演", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "但是你们若走到市区水仙宫一带去看，就会看到那污浊惊人的街道，你们若走到镇南关附近一带去看，就会看到蒿目伤心的荒冢，和我们这里演武场天空所看到的正成相反的对照。", "work": "第244章 在厦门大学送别会上的讲演", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "可知“选集”不能代表全部著作，一小块美丽的天空，不能代表整个地方的整齐清洁。", "work": "第244章 在厦门大学送别会上的讲演", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "这《八月的乡村》，即是很好的一部，虽然有些近乎短篇的连续，结构和描写人物的手段，也不能比法捷耶夫的《毁灭》，然而严肃，紧张，作者的心血和失去的天空，土地，受难的人民，以至失去的茂草，高粱，蝈蝈，蚊子，搅成一团，鲜红的在读者眼前展开，显示着中国的一份和全部，现在和未来，死路与活路。", "work": "第281章 田军作《八月的乡村》序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "华老栓忽然坐起身，擦着火柴，点上遍身油腻的灯盏，茶馆的两间屋子里，便弥满了青白的光。", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "华大妈忙看她儿子和别人的坟，却只有不怕冷的几点青白小花，零星开着；", "work": "第4章 药 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "青白脸色，皱纹间时常夹些伤痕；", "work": "第11章 孔乙己 小说《呐喊》1919", "year": "1919", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "莲花白竟赊来了，他喝了两杯，青白色的脸上泛了红，吃完饭，又颇有些高兴了，他点上一支大号哈德门香烟，从桌上抓起一本《尝试集》《尝试集》：系中国现代文学史上第一部白话诗集，是胡适里程碑式的著作，一九二○年三月上海亚东图书馆出版。", "work": "第15章 端午节 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "但也还仿佛记得她脸色变成青白，后来又渐渐转作绯红，——没有见过，也没有再见的绯红；", "work": "第34章 伤逝(1) 小说《彷徨》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "桃红和青白色的斗大的杂花，在眼前还分明，到远处可就成为斑斓的烟霭了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "公园里面，外国孩子聚沙成为圆堆，横插上两条短树干，这明明是在创造铁甲炮车了，而中国孩子是青白的，瘦瘦的脸，躲在大人的背后，羞怯的，惊异的看着，身上穿着一件斯文之极的长衫。", "work": "第95章 玩具 杂文《花边文学》1934", "year": "1934", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "一切冰冷，一切青白。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "上下四旁无不冰冷，青白。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "而一切青白冰上，却有红影无数，纠结如珊瑚网。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "冰谷四面，登时完全青白。", "work": "第197章 死火 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "青白的两颊泛出轻红，如铅上涂了胭脂水。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "当眉间尺肿着眼眶，头也不回的跨出门外，穿着青衣，背着青剑，迈开大步，径奔城中的时候，东方还没有露出阳光。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "腰间还依稀看见佩着和他背上一样的青剑。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他用青剑一挥，狼头便坠在地面的青苔上。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他已经掣起地上的青衣，包了眉间尺的头，和青剑都背在背脊上，回转身，在暗中向王城扬长地走去。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "爱青剑兮一个仇人自屠。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "一夫爱青剑兮呜呼不孤。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "一发怒，便按着青剑，总想寻点小错处，杀掉几个人。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他从从容容地伸开那捏着看不见的青剑的臂膊，如一段枯枝；", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "臂膊忽然一弯，青剑便蓦地从他后面劈下，剑到头落，坠入鼎中，怦的一声，雪白的水花向着空中同时四射。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "当初，他还只是冷笑，随后眼光便凶狠起来，一到说破他们的隐情，那就满脸都变成青色了。", "work": "第3章 狂人日记(2) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "”慢慢地滴下去，那剑嘶嘶地吼着，慢慢转成青色了。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "暗中的声音刚刚停止，眉间尺便举手向肩头抽取青色的剑，顺手从后项窝向前一削，头颅坠在地面的青苔上，一面将剑交给黑色人。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他恭敬地跪着俯伏下去时，果然看见背上有一个圆圆的小包袱，青色布，上面还画上一些暗红色的花纹。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "刚在惊疑，黑色人已经掣出了背着的青色的剑，只一挥，闪电般从后项窝直劈下去，扑通一声，王的头就落在鼎里了。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "“第二天当我们第一眼看到青岛青青的山角时，我们的心才又从冻结里蠕活过来。", "work": "第152章 三月的租界 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "你穿了青衣，背上这剑，衣剑一色，谁也看不分明的。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "当眉间尺肿着眼眶，头也不回的跨出门外，穿着青衣，背着青剑，迈开大步，径奔城中的时候，东方还没有露出阳光。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "第一口撕尽了眉间尺的青衣，第二口便身体全都不见了，血痕也顷刻舔尽，只微微听得咀嚼骨头的声音。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他已经掣起地上的青衣，包了眉间尺的头，和青剑都背在背脊上，回转身，在暗中向王城扬长地走去。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "穿一身青衣，背着一个圆圆的青包裹；", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "那青面獠牙的一伙人，便都哄笑起来。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "你看那女人“咬你几口”的话，和一伙青面獠牙人的笑，和前天佃户的话，明明是暗号。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "有的是仍旧青面獠牙，抿着嘴笑。", "work": "第3章 狂人日记(2) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "不过较之写些“青面獠牙”“口鼻流血”的笨伯，自然聪明得远。", "work": "第123章 捣鬼心传 杂文《南腔北调集》1933", "year": "1933", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "水中的青天的底子，一切事物统在上面交错，织成一篇，永是生动，永是展开，我看不见这一篇的结束。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "青天上面，有无数美的人和美的事，我一一看见，一一知道。", "work": "第195章 好的故事 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "不但全闽攻下，长江以南的大半土地，也都拨云雾而见青天了。", "work": "第245章 在厦门中山中学的讲演", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "夏夜，蚊子多了，便摇着蒲扇坐在槐树下，从密叶缝里看那一点一点的青天，晚出的槐蚕又每每冰冷的落在头颈上。", "work": "第264章 《呐喊》自序", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "逃掉了五色旗下的“铁窗斧钺风味”，而在青天白日之下又有“缧绁缧绁：古时系罪人的黑色绳索。", "work": "第286章 通信", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "幸我来也兮青其光！", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "青其光兮永不相忘。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "嗟来归来，嗟来陪来兮青其光！", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "猩红的栀子开花时，枣树又要做小粉红花的梦，青葱地弯成弧形了…", "work": "第187章 秋夜 散文诗《野草》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "我曾绕树徘徊，细看叶片的颜色，当他青葱的时候是从没有这么注意的。", "work": "第206章 腊叶 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "，是我先前没有见过的：就是一段树，只要浸在水中，枝叶便青葱得可爱。", "work": "第269章 《朝花夕拾》小引", "year": "待补年份", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "莲花白竟赊来了，他喝了两杯，青白色的脸上泛了红，吃完饭，又颇有些高兴了，他点上一支大号哈德门香烟，从桌上抓起一本《尝试集》《尝试集》：系中国现代文学史上第一部白话诗集，是胡适里程碑式的著作，一九二○年三月上海亚东图书馆出版。", "work": "第15章 端午节 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "桃红和青白色的斗大的杂花，在眼前还分明，到远处可就成为斑斓的烟霭了。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "”，听说是抱了一回铁柱之后受孕的，是一块纯青透明的铁。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "这样地七日七夜，就看不见了剑，仔细看时，却还在炉底里，纯青的，透明的，正像两条冰。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "眉间尺伏在掘开的洞穴旁边，伸手下去，谨慎小心地撮开烂树，待到指尖一冷，有如触着冰雪的时候，那纯青透明的剑也出现了。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "当初本想用和天一色的纯青石的，然而地上没有这么多，大山又舍不得用，有时到热闹处所去寻些零碎，看见的又冷笑，痛骂，或者抢回去，甚而至于还咬伊的手。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "窗外的星月和屋里的松明随乎都骤然失了光辉，惟有青光充塞宇内。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "那剑便溶在这青光中，看去好像一无所有。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "暗中的声音刚刚停止，眉间尺便举手向肩头抽取青色的剑，顺手从后项窝向前一削，头颅坠在地面的青苔上，一面将剑交给黑色人。", "work": "第41章 铸剑(1) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "他用青剑一挥，狼头便坠在地面的青苔上。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "头发蓬松，正如青烟一阵。", "work": "第42章 铸剑(2) 小说《故事新编》1926", "year": "1926", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "大火聚有时不过冒些青烟；", "work": "第199章 失掉的好地狱 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "那时候大约是盛夏，青蝇密集在凉棚索子上，铁黑色的细腰蜂就在桑树间或墙角的蛛网左近往来飞行，有时衔一支小青虫去了，有时拉一个蜘蛛。", "work": "第51章 春末闲谈 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "事情可更坏了：嗡的一声，就有一个青蝇停在我的颧骨上，走了几步，又一飞，开口便舐我的鼻尖。", "work": "第203章 死后 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "眼色也同赵贵翁一样，脸色也都铁青。", "work": "第2章 狂人日记(1) 小说《呐喊》1918", "year": "1918", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "我们的船向前走，两岸的青山在黄昏中，都装成了深黛颜色，连着退向船后梢去。", "work": "第14章 故乡 小说《呐喊》1921", "year": "1921", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "独有眼睛非常大，睫毛也很长，眼白又青得如夜的晴天，而且是北方的无风的晴天，这里的就没有那么明净了。", "work": "第25章 在酒楼上(2) 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "不多久，那惟一的盆景万年青的阔叶又已消失在昏暗中，破絮一般的白云间闪出星点，黑夜就从此开头。", "work": "第27章 肥皂(2） 小说《彷徨》1924", "year": "1924", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "伊接过来看时，是一条很光滑的青竹片，上面还有两行黑色的细点，比槲树叶上的黑斑小得多。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "空中青碧到如一片海，略有些浮云，仿佛有谁将粉笔洗在笔洗里似的摇曳。", "work": "第16章 白光 小说《呐喊》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "伊待到天上一色青碧的时候，才伸手去一摸，指面上却觉得还很有些参差。", "work": "第46章 补天 小说《故事新编》1922", "year": "1922", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "它将小青虫封在窠里，自己在外面日日夜夜敲打着，祝道“像我像我”，经过若干日，——我记不清了，大约七七四十九日罢，——那青虫也就成了细腰蜂了，所以《诗经》里说：“螟蛉有子，果蠃负之。", "work": "第51章 春末闲谈 杂文《坟》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "有一天，乡下做社戏了，他和戏子相识，便上台替他们去敲锣，精光的头皮，簇新的海青海青：江浙一带方言，指一种广袖的长袍。", "work": "第157章 我的第一个师父 杂文《且介亭杂文末编》1936", "year": "1936", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "白中隐青的单瓣梅花，深黄的磬口的蜡梅花磬口的蜡梅花：据清代陈淏子撰《花镜》卷三载：“圆瓣深黄，形似梅花，虽盛开如半含者，名磬口，最为世珍。", "work": "第193章 雪 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}, {"bucket": "blue", "quote": "青白的两颊泛出轻红，如铅上涂了胭脂水。", "work": "第201章 颓败线的颤动 散文诗《野草》1925", "year": "1925", "source": "S01 颜色意象统计与情感分析 最终参考版"}]};
